export interface MCQQuestion { id: number; text: string; image?: string; table?: string;
  options: { label: string; text: string }[]; correct: string; }
export interface MCQPaper { id: string; year: number; session: string; paperCode: string; questionData: MCQQuestion[]; }

const paper_01: MCQQuestion[] = [{"id":1,"text":"In country Z there has been a decrease in the birth rate. In the short run, which variable will be affected?","options":[{"label":"A","text":"inflation"},{"label":"B","text":"population"},{"label":"C","text":"supply"},{"label":"D","text":"unemployment"}],"correct":""},{"id":2,"text":"The diagram shows the choices for an individual between leisure and earnings. The person decides to take a job that gives more leisure time. What is the opportunity cost to the individual of moving from position Y to position X?","options":[{"label":"A","text":"\\$20"},{"label":"B","text":"\\$80"},{"label":"C","text":"4 hours of leisure per day"},{"label":"D","text":"12 hours of leisure per day"}],"correct":"","image":"/images/econ-mcq/0_394_703_1007_521_0.jpg"},{"id":3,"text":"A student defined opportunity cost as 'the alternative given up when a course of action is followed'. Why is this definition inadequate?","options":[{"label":"A","text":"The 'next best' alternative is not stressed."},{"label":"B","text":"The type of economic system is not identified."},{"label":"C","text":"There is no mention of money values."},{"label":"D","text":"There is no reference to finite resources and unlimited wants."}],"correct":""},{"id":4,"text":"The market for a good was in equilibrium. A change occurred which resulted in a new equilibrium with a higher price for the good and a lower quantity traded. Which change would have caused this?","options":[{"label":"A","text":"The demand curve moved to the left."},{"label":"B","text":"The demand curve moved to the right."},{"label":"C","text":"The supply curve moved to the left."},{"label":"D","text":"The supply curve moved to the right."}],"correct":""},{"id":5,"text":"What will result in a movement along the demand curve for a product?","options":[{"label":"A","text":"a change in tastes"},{"label":"B","text":"an increase in income"},{"label":"C","text":"a rise in the price of the product"},{"label":"D","text":"a successful advertising campaign for the product"}],"correct":""},{"id":6,"text":"In a year when there were big increases in demand for new cars, many used cars also came onto the market. The diagrams show the demand for and the supply of new and used cars. The original equilibrium position was at \\( \\mathrm{E} \\) in each case. What will be the new equilibrium position in each market?","options":[{"label":"A","text":"X | X"},{"label":"B","text":"X | Y"},{"label":"C","text":"Y | X"},{"label":"D","text":"Y | Y"}],"correct":"","image":"/images/econ-mcq/2_302_400_1194_494_0.jpg"},{"id":7,"text":"A government places an indirect tax on a good which has price-elastic demand. What is the result?","options":[{"label":"A","text":"decrease | decrease"},{"label":"B","text":"decrease | increase"},{"label":"C","text":"increase | decrease"},{"label":"D","text":"increase | increase"}],"correct":""},{"id":8,"text":"The diagram shows the demand for and the supply of bread.","options":[{"label":"A","text":"maximum price \\( {P}_{1} \\) is fixed by the government."},{"label":"B","text":"What is likely to be the immediate result of this?"},{"label":"C","text":"a shortage of bread"},{"label":"D","text":"a surplus of bread"}],"correct":"","image":"/images/econ-mcq/3_611_561_578_443_0.jpg"},{"id":9,"text":"What is a function of commercial banks?","options":[{"label":"A","text":"accept deposits and savings"},{"label":"B","text":"lender of last resort to government"},{"label":"C","text":"manage the national debt"},{"label":"D","text":"operate monetary policy"}],"correct":""},{"id":10,"text":"The table shows spending in the leisure sector of a country in 1995, 1999 and 2005. What can be concluded from the table?","options":[{"label":"A","text":"Leisure spending, in billions of dollars, increased more between 1995 and 1999 than between 1999 and 2005."},{"label":"B","text":"Leisure spending is growing in line with income growth."},{"label":"C","text":"Eulsure spending increased by an average of \\$10 billion a year between 1995 and 2005."},{"label":"D","text":"Leisure spending is taking an increasing share of total consumption."}],"correct":"","table":"<table><tr><td>year</td><td>1995</td><td>1999</td><td>2005</td></tr><tr><td>leisure spending (\\$ billion)</td><td>118</td><td>154</td><td>198</td></tr><tr><td>as a % of total consumption</td><td>27.0</td><td>27.5</td><td>28.0</td></tr></table>"},{"id":11,"text":"What would be likely to happen within a country if its government granted more work permits to doctors coming from other countries?","options":[{"label":"A","text":"increased demand for doctors"},{"label":"B","text":"increased productivity of doctors"},{"label":"C","text":"increased salaries for doctors"},{"label":"D","text":"increased supply of doctors"}],"correct":""},{"id":12,"text":"What is not a benefit of trade union membership for a worker?","options":[{"label":"A","text":"achieving higher wages for workers"},{"label":"B","text":"negotiating a higher rate of interest on a bank loan for workers"},{"label":"C","text":"providing support to workers when being made unemployed"},{"label":"D","text":"an improvement in health and safety standards at work"}],"correct":""},{"id":13,"text":"What will happen to a firm that expands to take advantage of economies of scale?","options":[{"label":"A","text":"Average costs of production will decrease."},{"label":"B","text":"Average costs of production will increase."},{"label":"C","text":"Profits will decrease."},{"label":"D","text":"The price of the firm's products will increase."}],"correct":""},{"id":14,"text":"The table shows total fixed and total variable costs at different levels of output for a firm. What happens as output rises?","options":[{"label":"A","text":"Average fixed cost falls."},{"label":"B","text":"Average fixed cost rises."},{"label":"C","text":"Average variable cost remains constant."},{"label":"D","text":"Average variable cost rises."}],"correct":"","table":"<table><tr><td>output</td><td>total fixed cost \\$</td><td>total variable cost \\$</td></tr><tr><td>100</td><td>1000</td><td>1000</td></tr><tr><td>200</td><td>1000</td><td>1500</td></tr><tr><td>300</td><td>1000</td><td>2000</td></tr><tr><td>400</td><td>1000</td><td>2500</td></tr></table>"},{"id":15,"text":"Which characteristics are found in a monopoly?","options":[{"label":"A","text":"freedom of entry to the market and a single seller"},{"label":"B","text":"freedom of entry to the market and many sellers"},{"label":"C","text":"many buyers and a single seller"},{"label":"D","text":"many buyers and many sellers"}],"correct":""},{"id":16,"text":"What is deflation?","options":[{"label":"A","text":"a decrease in the claimant count"},{"label":"B","text":"a decrease in the Consumer Prices Index"},{"label":"C","text":"a decrease in the Human Development Index"},{"label":"D","text":"a decrease in the real Gross Domestic Product"}],"correct":""},{"id":17,"text":"What is the likely outcome of an expansionary monetary policy?","options":[{"label":"A","text":"Borrowing by consumers falls as the money supply increases."},{"label":"B","text":"Firms expand to meet higher consumer demand."},{"label":"C","text":"Prices fall as total supply exceeds total demand."},{"label":"D","text":"Wages rise due to a lower rate of inflation."}],"correct":""},{"id":18,"text":"In the past, governments have adopted policies to try to end a recession in their country and increase economic growth. Which combination of policies is most likely to achieve this?","options":[{"label":"A","text":"lower taxes and decrease government spending"},{"label":"B","text":"lower taxes and increase government spending"},{"label":"C","text":"raise taxes and decrease government spending"},{"label":"D","text":"raise taxes and increase government spending"}],"correct":""},{"id":19,"text":"The table shows taxes as a percentage of Gross Domestic Product (GDP) for four countries. From this information, which country had the highest percentage of direct taxation as a percentage of GDP?","options":[{"label":"A","text":"12 | 14 | 2 | 5"},{"label":"B","text":"14 | 15 | 2 | 14"},{"label":"C","text":"17 | 13 | 5 | 10"},{"label":"D","text":"18 | 10 | 1 | 10"}],"correct":""},{"id":20,"text":"As a country develops economically, what is most likely to happen?","options":[{"label":"A","text":"There will be an increase in productivity."},{"label":"B","text":"There will be an increase in the birth rate."},{"label":"C","text":"There will be an increase in the death rate."},{"label":"D","text":"There will be reduced occupational mobility."}],"correct":""},{"id":21,"text":"Which government policy would be most likely to reduce structural unemployment?","options":[{"label":"A","text":"a decrease in the rate of interest"},{"label":"B","text":"a decrease in the tax on goods and services"},{"label":"C","text":"an increase in spending on education and training"},{"label":"D","text":"an increase in tariffs on imported goods and services"}],"correct":""},{"id":22,"text":"A government has a target of keeping inflation between 2% and 3%. The diagram shows the rate of inflation over a four-year period. What can be deduced from the diagram?","options":[{"label":"A","text":"The government target was missed in two years."},{"label":"B","text":"The price level fell in two years."},{"label":"C","text":"The price level was at its highest in the first year."},{"label":"D","text":"The real value of money fell in three years."}],"correct":"","image":"/images/econ-mcq/8_512_326_780_429_0.jpg"},{"id":23,"text":"What is most likely to be found in a high-income economy?","options":[{"label":"A","text":"access to safe water | infant mortality rate"},{"label":"B","text":"birth rate | adult literacy rate"},{"label":"C","text":"gross domestic product per head | access to safe water"},{"label":"D","text":"infant mortality rate | death rate"}],"correct":""},{"id":24,"text":"The table shows figures for the real GDP of a country in a particular year.","options":[{"label":"A","text":"quarter is three months."},{"label":"B","text":"At the end of which quarter had the economy experienced a recession?"},{"label":"C","text":"quarter 3"},{"label":"D","text":"quarter 4"}],"correct":"","table":"<table><tr><td>quarter 1 (\\$bn)</td><td>quarter 2 (\\$bn)</td><td>quarter 3 (\\$bn)</td><td>quarter 4 (\\$bn)</td></tr><tr><td>100</td><td>101</td><td>99</td><td>98</td></tr></table>"},{"id":25,"text":"What is a quota in international trade?","options":[{"label":"A","text":"a government grant to encourage production"},{"label":"B","text":"a limit on the quantity of imports"},{"label":"C","text":"a tax on imports"},{"label":"D","text":") an administrative and technical barrier"}],"correct":""},{"id":26,"text":"What is an advantage of a floating exchange rate for an economy?","options":[{"label":"A","text":"It can correct a current account deficit or surplus."},{"label":"B","text":"It creates certainty for firms importing goods."},{"label":"C","text":"It increases government control of the economy."},{"label":"D","text":"It stops money flows into and out of the economy."}],"correct":""},{"id":27,"text":"The table shows information from a country's current account of its balance of payments. What is the country's current account balance?","options":[{"label":"A","text":"+\\$1 billion B -\\$4 billion C -\\$7 billion D -\\$15 billion"},{"label":"B","text":"Permission to reproduce items where third-party owned material protected by copyright is included has been sought and cleared where possible. Every reasonable effort has been made by the publisher (UCLES) to trace copyright holders, but if any items requiring clearance have unwittingly been included, the publisher will be pleased to make amends at the earliest possible opportunity."},{"label":"C","text":"To avoid the issue of disclosure of answer-related information to candidates, all copyright acknowledgements are reproduced online in the Cambridge Assessment International Education Copyright Acknowledgements Booklet. This is produced for each series of examinations and is freely available to download at www.cambridgeinternational.org after the live examination series."},{"label":"D","text":"Local Examinations Syndicate (UCLES), which is a department of the University of Cambridge."}],"correct":"","table":"<table><tr><td></td><td>\\$ billion</td></tr><tr><td>exports of goods</td><td>20</td></tr><tr><td>imports of goods</td><td>24</td></tr><tr><td>net services</td><td>\\( + 5 \\)</td></tr><tr><td>net primary income</td><td>-8</td></tr><tr><td>net secondary income</td><td>-8</td></tr></table>"}];

const paper_02: MCQQuestion[] = [{"id":1,"text":"What causes economic agents to make choices?","options":[{"label":"A","text":"limited needs and wants"},{"label":"B","text":"the existence of finite resources"},{"label":"C","text":"the existence of free goods"},{"label":"D","text":"the market mechanism"}],"correct":""},{"id":2,"text":"A government announces that it will spend an extra \\$10bn on healthcare, financed by reducing expenditure on defence. What is the economic concept represented by this decision?","options":[{"label":"A","text":"expansionary monetary policy"},{"label":"B","text":"increased spending on a public good"},{"label":"C","text":"opportunity cost"},{"label":"D","text":"the operation of the market mechanism"}],"correct":""},{"id":3,"text":"What would not cause a shift in the supply curve?","options":[{"label":"A","text":"changes in costs of production"},{"label":"B","text":"changes in direct taxes"},{"label":"C","text":"changes in indirect taxes"},{"label":"D","text":"changes in a subsidy from the government"}],"correct":""},{"id":4,"text":"For health reasons, consumers decide that they want to eat more vegetables and less meat. What price signals would the market system send to reallocate resources so that consumers get what they want?","options":[{"label":"A","text":"decrease | decrease"},{"label":"B","text":"decrease | increase"},{"label":"C","text":"increase | decrease"},{"label":"D","text":"increase | increase"}],"correct":""},{"id":5,"text":"What is a likely benefit of a country moving from a mixed economy to a market economy?","options":[{"label":"A","text":"less inequality"},{"label":"B","text":"more nationalisation"},{"label":"C","text":"more public goods"},{"label":"D","text":"reduced costs of production"}],"correct":""},{"id":6,"text":"What is an external cost of smoking cigarettes?","options":[{"label":"A","text":"the cost of the cigarette packaging"},{"label":"B","text":"the cost to non-smokers' health"},{"label":"C","text":"the cost to smokers"},{"label":"D","text":"the tax on cigarettes"}],"correct":""},{"id":7,"text":"The table shows information about four financial institutions. Which institution is most likely to be a commercial bank?","options":[{"label":"A","text":"no | no"},{"label":"B","text":"no | yes"},{"label":"C","text":"yes | no"},{"label":"D","text":"yes | yes"}],"correct":""},{"id":8,"text":"What shows a forwards vertical merger?","options":[{"label":"A","text":"A smartphone producer buys a computer chip producer."},{"label":"B","text":"A steel producer buys a car producer."},{"label":"C","text":"A tractor producer buys a wheat producer."},{"label":"D","text":"An oven producer buys a washing machine producer."}],"correct":""},{"id":9,"text":"Which service is most likely to be supplied by a small business?","options":[{"label":"A","text":"banking"},{"label":"B","text":"dental treatment"},{"label":"C","text":"energy distribution"},{"label":"D","text":"rail travel"}],"correct":""},{"id":10,"text":"At a price of \\$5, the demand for a firm's product is 1000 units per week. When its price rises to \\$10, the demand for its product falls to 600 units per week. What are the changes in the firm's average revenue (AR) and total revenue (TR) per week when the price of its product rises?","options":[{"label":"A","text":"\\( + 5 \\) | +1000"},{"label":"B","text":"\\( + 5 \\) | +6000"},{"label":"C","text":"\\( + {10} \\) | +1000"},{"label":"D","text":"+10 | +6000"}],"correct":""},{"id":11,"text":"A monopoly firm can often earn greater profits than a firm in a competitive market. Which characteristic of monopoly is most likely to cause this?","options":[{"label":"A","text":"It can restrict the entry of new firms."},{"label":"B","text":"It is a price-taker."},{"label":"C","text":"It is protected by the government."},{"label":"D","text":"Its total costs are usually low."}],"correct":""},{"id":12,"text":"An economy is experiencing a period of deflation with lower output and rising unemployment. Which policy measure would the government be most likely to use to correct this?","options":[{"label":"A","text":"improve education and training"},{"label":"B","text":"increase interest rates"},{"label":"C","text":"reduce income tax"},{"label":"D","text":"reduce unemployment benefits"}],"correct":""},{"id":13,"text":"What is likely to increase with economic growth?","options":[{"label":"A","text":"cyclical unemployment"},{"label":"B","text":"income per head"},{"label":"C","text":"the budget deficit"},{"label":"D","text":"the stock of natural resources"}],"correct":""},{"id":14,"text":"An economy has a high rate of inflation. Which monetary policy measure is required to reduce inflation?","options":[{"label":"A","text":"a depreciation of its currency against the US dollar"},{"label":"B","text":"an increase in the money supply"},{"label":"C","text":"an increase in the rate of interest"},{"label":"D","text":"an increase in the basic rate of income tax"}],"correct":""},{"id":15,"text":"In a mixed economy, a government provides some goods that markets cannot. What is the name of these goods?","options":[{"label":"A","text":"free goods"},{"label":"B","text":"economic goods"},{"label":"C","text":"merit goods"},{"label":"D","text":"public goods"}],"correct":""},{"id":16,"text":"Which of these people would be classed as unemployed?","options":[{"label":"A","text":"a student who does not work"},{"label":"B","text":"a person who does not have a job and is actively looking for one"},{"label":"C","text":"a retired person who does not work"},{"label":"D","text":"an adult who does not have a job and stays at home to provide childcare"}],"correct":""},{"id":17,"text":"The table shows the weights attached to four items in the Consumer Prices Index of a country in year 1 and in year 2. Which conclusion can be drawn?","options":[{"label":"A","text":"food prices were higher in year 2 than in year 1"},{"label":"B","text":"people spent less on transport in year 2 than in year 1"},{"label":"C","text":"people spent more on food in year 2 than in year 1"},{"label":"D","text":"a greater proportion of income was spent on clothing in year 2 than in year 1"}],"correct":"","table":"<table><tr><td>item</td><td>year 1</td><td>year 2</td></tr><tr><td>food</td><td>33</td><td>33.5</td></tr><tr><td>transport</td><td>18</td><td>17.5</td></tr><tr><td>rent</td><td>11</td><td>10.5</td></tr><tr><td>clothing</td><td>9</td><td>10</td></tr></table>"},{"id":18,"text":"The table shows the percentage (%) shares of income going to different household income groups in a country in two years. What can be concluded about the change over the period?","options":[{"label":"A","text":"The distribution of income has become more unequal."},{"label":"B","text":"The number of households in the highest 20% has increased."},{"label":"C","text":"The proportion of households in absolute poverty has increased."},{"label":"D","text":"The proportion of households in relative poverty has fallen."}],"correct":"","table":"<table><tr><td>household income group</td><td>year 1 % share of income</td><td>year 2 % share of income</td></tr><tr><td>highest 20%</td><td>50</td><td>53</td></tr><tr><td>next highest 20%</td><td>20</td><td>22</td></tr><tr><td>next highest 20%</td><td>15</td><td>18</td></tr><tr><td>next highest 20%</td><td>10</td><td>5</td></tr><tr><td>lowest 20%</td><td>5</td><td>2</td></tr></table>"},{"id":19,"text":"An economy has a high rate of population growth. What is most likely to have caused this?","options":[{"label":"A","text":"The average years of schooling is relatively high."},{"label":"B","text":"The birth rate is lower than the death rate."},{"label":"C","text":"The retirement age has increased."},{"label":"D","text":"There are more immigrants than emigrants."}],"correct":""},{"id":20,"text":"What is the most likely cause of an increase in poverty in developing economies?","options":[{"label":"A","text":"an increase in poor nutrition and ill-health"},{"label":"B","text":"an increase in education provision"},{"label":"C","text":"an increase in international tourism"},{"label":"D","text":"an increase in trade union bargaining power"}],"correct":""},{"id":21,"text":"Two countries wish to use their scarce resources to specialise in production and trade with each other. Under which conditions is this most likely to happen?","options":[{"label":"A","text":"different | difficult"},{"label":"B","text":"different | easy"},{"label":"C","text":"similar | difficult"},{"label":"D","text":"similar | easy"}],"correct":""},{"id":22,"text":"What is a likely effect of imposing a tariff?","options":[{"label":"A","text":"It encourages home industries to be more efficient."},{"label":"B","text":"It increases the demand for home-produced goods."},{"label":"C","text":"It reduces the price of home-produced goods."},{"label":"D","text":"It reduces the price of imports."}],"correct":""},{"id":23,"text":"What is included in the primary income component on the current account of the balance of payments?","options":[{"label":"A","text":"dividends and interest from investment in other countries"},{"label":"B","text":"expenditure on accommodation by international tourists visiting a country"},{"label":"C","text":"expenditure on imported raw materials"},{"label":"D","text":"social security payments paid to residents living abroad"}],"correct":""}];

const paper_03: MCQQuestion[] = [{"id":1,"text":"What is classed as the factor of production land?","options":[{"label":"A","text":"an airport"},{"label":"B","text":"a car park"},{"label":"C","text":"a doctor's office"},{"label":"D","text":"a forest"}],"correct":""},{"id":2,"text":"An economics graduate chooses to work in a bank rather than teach economics which was the next best alternative. Which cost is incurred as a result of this decision?","options":[{"label":"A","text":"external cost"},{"label":"B","text":"internal cost"},{"label":"C","text":"opportunity cost"},{"label":"D","text":"private cost"}],"correct":""},{"id":3,"text":"The diagram shows an initial production possibility curve of \\( {\\mathrm{{PPC}}}_{1} \\) . What is likely to have caused the movement of the production possibility curve \\( {\\mathrm{{PPC}}}_{1} \\) to \\( {\\mathrm{{PPC}}}_{2} \\) ?","options":[{"label":"A","text":"a decline in non-renewable resources"},{"label":"B","text":"a decline in the opportunity cost of consumer goods"},{"label":"C","text":"an increase in investment"},{"label":"D","text":"an increase in unemployment"}],"correct":"","image":"/images/econ-mcq/21_613_1081_595_471_0.jpg"},{"id":4,"text":"What is an example of microeconomics?","options":[{"label":"A","text":"a fall in the cost of growing wheat"},{"label":"B","text":"a fall in the unemployment rate"},{"label":"C","text":"- an increase in the rate of inflation"},{"label":"D","text":"an increase in government spending"}],"correct":""},{"id":5,"text":"There are three key questions to be decided in determining resource allocation within an economy. What does not relate to one of the choices in the three key questions?","options":[{"label":"A","text":"whether all income groups receive the output"},{"label":"B","text":"whether consumer or industrial goods are produced"},{"label":"C","text":"whether economic goods or free goods are supplied"},{"label":"D","text":"whether labour or capital is used in production"}],"correct":""},{"id":6,"text":"The price elasticity of demand for smartphones is believed to be -2.0. A manufacturer decides to cut prices by 10%. What will be the effect of this change in price?","options":[{"label":"A","text":"demand will fall by 20%"},{"label":"B","text":"demand will rise by 5%"},{"label":"C","text":"quantity supplied will remain unchanged"},{"label":"D","text":"revenue will increase"}],"correct":""},{"id":7,"text":"What is a characteristic of a market economic system?","options":[{"label":"A","text":"consumers decide whether production is labour-intensive or capital-intensive"},{"label":"B","text":"factors of production are government-owned"},{"label":"C","text":"high levels of government intervention"},{"label":"D","text":"land and capital are privately owned"}],"correct":""},{"id":8,"text":"A government intends to build a new road through a forest. What will be an external cost of this?","options":[{"label":"A","text":"the cost of building the road"},{"label":"B","text":"the loss suffered by those who would have used the forest"},{"label":"C","text":"the cost of maintaining the road"},{"label":"D","text":"the new jobs created from the construction of the road"}],"correct":""},{"id":9,"text":"Which function does a central bank provide for the general public?","options":[{"label":"A","text":"accepting deposits"},{"label":"B","text":"issuing banknotes"},{"label":"C","text":"making loans"},{"label":"D","text":"providing overdrafts"}],"correct":""},{"id":10,"text":"In some countries, there has been a significant reduction in the number of trade union members. Who are the members of trade unions?","options":[{"label":"A","text":"employers"},{"label":"B","text":"exporters"},{"label":"C","text":"importers"},{"label":"D","text":"workers"}],"correct":""},{"id":11,"text":"What would be most likely to encourage a firm to grow internally?","options":[{"label":"A","text":"when diseconomies of scale occur at low levels of output"},{"label":"B","text":"when economies of scale occur at high levels of output"},{"label":"C","text":"when new firms enter the market and increase competition"},{"label":"D","text":"when the firm only supplies the local market"}],"correct":""},{"id":12,"text":"The table shows the average revenue of a firm at various levels of output. What happens to total revenue as output rises?","options":[{"label":"A","text":"Total revenue falls and then rises."},{"label":"B","text":"Total revenue falls continuously."},{"label":"C","text":"Total revenue rises and then falls."},{"label":"D","text":"Total revenue rises continuously."}],"correct":"","table":"<table><tr><td>output</td><td>average revenue <br> (\\$)</td></tr><tr><td>1</td><td>10</td></tr><tr><td>2</td><td>8</td></tr><tr><td>3</td><td>6</td></tr><tr><td>4</td><td>4</td></tr></table>"},{"id":13,"text":"What is the definition of a government budget?","options":[{"label":"A","text":"a forecast of government spending and revenue for the following financial year"},{"label":"B","text":"an account of government taxation revenues for the current financial year"},{"label":"C","text":"an estimate of government capital spending for the current financial year"},{"label":"D","text":"an explanation of government spending for the following financial year"}],"correct":""},{"id":14,"text":"A government decides to increase defence expenditure and reduce direct taxes. Which type of policy is this?","options":[{"label":"A","text":"exchange rate policy"},{"label":"B","text":"fiscal policy"},{"label":"C","text":"monetary policy"},{"label":"D","text":"trade protection policy"}],"correct":""},{"id":15,"text":"Governments use monetary policy such as increasing the rate of interest. What is a result of increasing the rate of interest?","options":[{"label":"A","text":"It creates disincentives for wage earners."},{"label":"B","text":"It discourages investment by entrepreneurs."},{"label":"C","text":"It reduces the disposable income of consumers."},{"label":"D","text":"It reduces government transfer payments."}],"correct":""},{"id":16,"text":"The table shows the distribution of the working population in millions (m) in various sectors of an economy over two years. What can be concluded from the information?","options":[{"label":"A","text":"Less output was produced in the economy in year 2 than year 1."},{"label":"B","text":"Fewer people were employed in the secondary sector in year 1 than year 2."},{"label":"C","text":"More people were employed in the primary sector in year 2 than year 1."},{"label":"D","text":"More people were employed in the tertiary sector in year 2 than year 1."}],"correct":"","table":"<table><tr><td>economic sector</td><td>year 1 employment (m)</td><td>year 2 employment (m)</td></tr><tr><td>education</td><td>4</td><td>3</td></tr><tr><td>engineering</td><td>6</td><td>8</td></tr><tr><td>farming</td><td>2</td><td>1</td></tr><tr><td>finance</td><td>8</td><td>6</td></tr><tr><td>healthcare</td><td>4</td><td>5</td></tr><tr><td>motor vehicle production</td><td>5</td><td>5</td></tr><tr><td>oil extraction</td><td>2</td><td>2</td></tr></table>"},{"id":17,"text":"Which government intervention would increase the geographic mobility of labour?","options":[{"label":"A","text":"controlling firms locating in areas of low employment"},{"label":"B","text":"giving grants to firms moving into areas of high unemployment"},{"label":"C","text":"providing relocation expenses for workers"},{"label":"D","text":"subsidising declining industries"}],"correct":""},{"id":18,"text":"Which action by employers is most likely to reduce long-term economic growth?","options":[{"label":"A","text":"allowing workers time off to attend retraining courses"},{"label":"B","text":"encouraging workers to work flexibly in different roles"},{"label":"C","text":"granting workers regular short breaks during the working day"},{"label":"D","text":"replacing skilled workers with semi-skilled workers"}],"correct":""},{"id":19,"text":"The table shows the weights attached to various categories of goods in a Consumer Prices Index (CPI) in two years. What can be concluded from the table when comparing year 1 and year 2?","options":[{"label":"A","text":"Real income spent by the average consumer on motoring increased."},{"label":"B","text":"The cost of producing food has fallen."},{"label":"C","text":"The CPI has not changed over the two years."},{"label":"D","text":"The proportion of income spent on clothing has increased."}],"correct":"","table":"<table><tr><td>CPI category</td><td>year 1</td><td>year 2</td></tr><tr><td>clothing</td><td>100</td><td>200</td></tr><tr><td>food</td><td>400</td><td>300</td></tr><tr><td>energy</td><td>100</td><td>100</td></tr><tr><td>household goods</td><td>200</td><td>100</td></tr><tr><td>motoring</td><td>200</td><td>300</td></tr><tr><td>total</td><td>1000</td><td>1000</td></tr></table>"},{"id":20,"text":"The table shows the Human Development Index (HDI) values for two countries. What might explain the difference in the HDI values?","options":[{"label":"A","text":"Country X has double the inflation rate of country Y."},{"label":"B","text":"Country X has half the population of country Y."},{"label":"C","text":"Country X spends more of its real GDP on foreign aid than country Y."},{"label":"D","text":"Country X spends more of its real GDP on schooling than country Y."}],"correct":"","table":"<table><tr><td>country</td><td>HDI value</td></tr><tr><td>X</td><td>0.90</td></tr><tr><td>Y</td><td>0.45</td></tr></table>"},{"id":21,"text":"Wealthy countries have people who live in relative poverty. What is the most likely cause of this?","options":[{"label":"A","text":"generous state pensions"},{"label":"B","text":"low national minimum wage"},{"label":"C","text":"progressive taxation"},{"label":"D","text":"subsidised healthcare"}],"correct":""},{"id":22,"text":"The diagram shows population data for a country for 1950, 2005 and 2050. What can be concluded from the diagram?","options":[{"label":"A","text":"Men outnumber women in each year."},{"label":"B","text":"People are living longer over the period."},{"label":"C","text":"The population has grown continuously."},{"label":"D","text":"The workforce has grown continuously."}],"correct":"","image":"/images/econ-mcq/29_202_693_1398_735_0.jpg"},{"id":23,"text":"A country has large reserves of oil. It decides to produce a wide range of goods rather than specialise in oil production. What is not an acceptable reason in support of this decision?","options":[{"label":"A","text":"Oil is a non-renewable resource that could be exhausted quickly."},{"label":"B","text":"Producing a wide range of goods increases the benefits from free trade."},{"label":"C","text":"Relying on other countries for vital goods and services makes a country vulnerable."},{"label":"D","text":"The price of oil is volatile, making export revenue unstable."}],"correct":""},{"id":24,"text":"The US puts a 25% tariff on Chinese steel to protect jobs in the US steel industry. Under which condition would this policy be most effective?","options":[{"label":"A","text":"The price elasticity of demand for Chinese steel is -2.5."},{"label":"B","text":"The price elasticity of demand for Chinese steel is -0.5."},{"label":"C","text":"The price elasticity of supply for Chinese steel is 2.5."},{"label":"D","text":"The price elasticity of supply for Chinese steel is zero."}],"correct":""},{"id":25,"text":"What might a central bank do to stop a fall in the value of its country's currency?","options":[{"label":"A","text":"raise interest rates"},{"label":"B","text":"reduce taxes on imports"},{"label":"C","text":"remove controls on currency outflows"},{"label":"D","text":"sell their currency on the foreign exchange market"}],"correct":""},{"id":26,"text":"A government wishes to reduce the surplus on the current account of its balance of payments. Which policy is likely to achieve this?","options":[{"label":"A","text":"cutting government spending"},{"label":"B","text":"devaluing its currency"},{"label":"C","text":"increasing existing import quotas"},{"label":"D","text":"increasing import duties"}],"correct":""}];

const paper_04: MCQQuestion[] = [{"id":1,"text":"Which statement about the factors of production is correct?","options":[{"label":"A","text":"Capital is a financial resource and includes savings in banks."},{"label":"B","text":"Enterprise is limited in supply and includes office workers."},{"label":"C","text":"Labour is a human resource and includes pensioners and children."},{"label":"D","text":"Land is a natural resource and includes trees and fish."}],"correct":""},{"id":2,"text":"A builder spends one hour travelling to and from work. He works 40 hours per week for \\$200. He is given a choice to work 50 hours a week for an extra \\$75. What would be the opportunity cost to the builder of working the extra hours?","options":[{"label":"A","text":"the ability to increase his purchasing power"},{"label":"B","text":"the additional time travelling to and from work"},{"label":"C","text":"the increased hourly earnings of \\$7.50"},{"label":"D","text":"the ten hours of leisure time"}],"correct":""},{"id":3,"text":"What is included in microeconomics?","options":[{"label":"A","text":"the calculation of national income and expenditure"},{"label":"B","text":"the effects of a change in exchange rates on the trade balance of an economy"},{"label":"C","text":"the effects of an increase in the price of a good or service"},{"label":"D","text":"the factors leading to demand-pull inflation"}],"correct":""},{"id":4,"text":"What is an economist's definition of a market?","options":[{"label":"A","text":"a collection of informal retail outlets run by small firms"},{"label":"B","text":"a place where traders gather regularly for short periods"},{"label":"C","text":"a system that enables individuals and firms to buy and sell goods"},{"label":"D","text":"the existence of consumer demand for a good"}],"correct":""},{"id":5,"text":"What is an example of an external benefit from an individual cycling, rather than driving, to work?","options":[{"label":"A","text":"higher cost of building cycle lanes"},{"label":"B","text":"improved physical fitness to the individual from cycling"},{"label":"C","text":"lower cost of cycling compared with driving to work"},{"label":"D","text":"reduced congestion for other road users"}],"correct":""},{"id":6,"text":"It is expected that consumers will use less paper money. What is the most likely reason for this?","options":[{"label":"A","text":"Inflation reduces the value of paper money."},{"label":"B","text":"More ways of making payments will be available."},{"label":"C","text":"Other forms of money are more durable."},{"label":"D","text":"Paper money will have less intrinsic value."}],"correct":""},{"id":7,"text":"In low-income countries, fewer girls than boys become skilled design engineers. What might explain this situation?","options":[{"label":"A","text":"Girls are only interested in low-wage jobs."},{"label":"B","text":"Girls do not favour heavy manual work."},{"label":"C","text":"Girls have fewer opportunities to complete higher education."},{"label":"D","text":"It costs more for girls to be trained as design engineers."}],"correct":""},{"id":8,"text":"A company mining cobalt, invests in machinery to replace some workers. Eventually diseconomies of scale occur. What could cause this situation?","options":[{"label":"A","text":"As more cobalt is mined average costs increase."},{"label":"B","text":"Fewer workers are needed to produce the required output."},{"label":"C","text":"Output per hour increases as more machinery is used."},{"label":"D","text":"Overhead costs are spread as output increases."}],"correct":""},{"id":9,"text":"Why are many hairdressers able to operate as small businesses?","options":[{"label":"A","text":"high level of competition"},{"label":"B","text":"high scope for economies of scale"},{"label":"C","text":"long period of training required"},{"label":"D","text":"low start-up and running costs"}],"correct":""},{"id":10,"text":"Dimitry owns a firm that produces and sells bottles of lemonade. He only sells one size of bottle. How would Dimitry calculate the total revenue of the firm?","options":[{"label":"A","text":"multiply the quantity sold by the cost per bottle"},{"label":"B","text":"multiply the quantity sold by the price per bottle"},{"label":"C","text":"multiply the quantity sold by the profit per bottle"},{"label":"D","text":"multiply the quantity sold by the tax per bottle"}],"correct":""},{"id":11,"text":"Which market is likely to be the most competitive?","options":[{"label":"A","text":"high | few"},{"label":"B","text":"high | many"},{"label":"C","text":"low | few"},{"label":"D","text":"low | many"}],"correct":""},{"id":12,"text":"An economy has a high rate of inflation. In response to this, its government increases income tax. What is the most likely reason for this increase?","options":[{"label":"A","text":"to discourage the consumption of harmful goods"},{"label":"B","text":"to raise money for government spending"},{"label":"C","text":"to redistribute income"},{"label":"D","text":"to reduce total demand"}],"correct":""},{"id":13,"text":"Interest rates are sometimes raised to control inflation. Why might this policy be effective?","options":[{"label":"A","text":"Consumers may save more."},{"label":"B","text":"Government spending may increase."},{"label":"C","text":"Investment may be encouraged."},{"label":"D","text":"The exchange rate may fall."}],"correct":""},{"id":14,"text":"A government's revenue grew 8% to \\$3.25 trillion. Its expenditure was reduced to \\$3.69 trillion. What can be concluded from this?","options":[{"label":"A","text":"deficit | increase deficit"},{"label":"B","text":"deficit | reduce deficit"},{"label":"C","text":"surplus | increase surplus"},{"label":"D","text":"surplus | reduce surplus"}],"correct":""},{"id":15,"text":"A country's inflation rate, measured by the Consumer Prices Index (CPI), was 3% in year 1. Three years later it was 0.8%. What can be concluded from this information?","options":[{"label":"A","text":"Prices are falling."},{"label":"B","text":"The rate of price increases is falling."},{"label":"C","text":"The real rate of interest is negative."},{"label":"D","text":"There is increased purchasing power for those on fixed incomes."}],"correct":""},{"id":16,"text":"What will deflation most likely lead to?","options":[{"label":"A","text":"a fall in the real value of debts"},{"label":"B","text":"an increase in the exchange rate"},{"label":"C","text":"an increase in the rate of interest"},{"label":"D","text":"an increase in the real purchasing power of money"}],"correct":""},{"id":17,"text":"Economic growth can be defined as","options":[{"label":"A","text":"a reduction in a country's rate of inflation."},{"label":"B","text":"an increase in a country's exports."},{"label":"C","text":"an increase in a country's population."},{"label":"D","text":"an increase in a country's productive capacity."}],"correct":""},{"id":18,"text":"The table compares the distribution of employment in selected industries in two years. How did the distribution of employment change between year 1 and year 2?","options":[{"label":"A","text":"fell | rose"},{"label":"B","text":"fell | unchanged"},{"label":"C","text":"rose | fell"},{"label":"D","text":"rose | unchanged"}],"correct":"","table":"<table><tr><td rowspan=\"2\">industry</td><td colspan=\"2\">employment in millions</td></tr><tr><td>year 1</td><td>year 2</td></tr><tr><td>agriculture</td><td>4</td><td>3</td></tr><tr><td>mining</td><td>2</td><td>2</td></tr><tr><td>manufacturing</td><td>6</td><td>6</td></tr><tr><td>retailing</td><td>4</td><td>4</td></tr><tr><td>transport</td><td>4</td><td>5</td></tr><tr><td>total</td><td>20</td><td>20</td></tr></table>"},{"id":19,"text":"In a year, two changes occurred in a company. Company directors' salaries increased by 15%. Office workers' wages increased by 5%. The rate of inflation was 3.4%. What happened to real income?","options":[{"label":"A","text":"fell | fell"},{"label":"B","text":"fell | rose"},{"label":"C","text":"rose | fell"},{"label":"D","text":"rose | rose"}],"correct":""},{"id":20,"text":"The richest 60% of the population of a high-income economy received an increase in income. The income of the rest of the population did not change. What happened to absolute and relative poverty?","options":[{"label":"A","text":"increased | increased"},{"label":"B","text":"increased | remained constant"},{"label":"C","text":"remained constant | increased"},{"label":"D","text":"remained constant | remained constant"}],"correct":""},{"id":21,"text":"Gross Domestic Product (GDP) is a better measure of comparative living standards when it is adjusted for the effects of","options":[{"label":"A","text":"exports and inflation."},{"label":"B","text":"imports and exports."},{"label":"C","text":"population change and exports."},{"label":"D","text":"population change and inflation."}],"correct":""},{"id":22,"text":"What is a disadvantage of increasing international specialisation?","options":[{"label":"A","text":"Consumers pay higher prices for goods and services reducing their welfare."},{"label":"B","text":"Domestic firms may be uncompetitive leading to structural unemployment."},{"label":"C","text":"Domestic firms may experience rising costs as they pay more for imports."},{"label":"D","text":"Resources may be used less efficiently as domestic firms face less competition."}],"correct":""},{"id":23,"text":"Which method of protection always reduces the supply of an imported good to zero?","options":[{"label":"A","text":"embargo"},{"label":"B","text":"quota"},{"label":"C","text":"subsidy"},{"label":"D","text":"tariff"}],"correct":""},{"id":24,"text":"A country has a deficit on its current account of its balance of payments. What could increase the size of its deficit?","options":[{"label":"A","text":"increased exports of its services"},{"label":"B","text":"increased international competitiveness of its goods"},{"label":"C","text":"increased numbers of visitors from abroad"},{"label":"D","text":"increased spending on its military bases abroad"}],"correct":""}];

const paper_05: MCQQuestion[] = [{"id":1,"text":"What is an advantage of competitive markets?","options":[{"label":"A","text":"Competition causes inequalities of wealth."},{"label":"B","text":"Competition encourages the efficient use of resources."},{"label":"C","text":"The economic problem of scarcity is eliminated."},{"label":"D","text":"The right quantity of merit goods is guaranteed."}],"correct":""},{"id":2,"text":"A multinational company (MNC) wishes to invest in a low-income country to expand its palm oil production. What is most likely to make this investment possible?","options":[{"label":"A","text":"high cost of clearing forests to increase land for plantations"},{"label":"B","text":"increased demand for palm oil"},{"label":"C","text":"shortages of labour in the rural economy"},{"label":"D","text":"the removal of subsidies for palm oil production"}],"correct":""},{"id":3,"text":"A farmer sells land used for crops to a firm that will use the land for wind turbines to produce electric power. What is the opportunity cost of this decision by the farmer?","options":[{"label":"A","text":"the cost of installing wind turbines"},{"label":"B","text":"the loss of revenue from crops that grow on the land"},{"label":"C","text":"the profit made from selling the land"},{"label":"D","text":"the reduced cost of producing renewable energy"}],"correct":""},{"id":4,"text":"What is not included in microeconomics?","options":[{"label":"A","text":"economies of scale"},{"label":"B","text":"forms of competition"},{"label":"C","text":"individual demand"},{"label":"D","text":"the inflation rate"}],"correct":""},{"id":5,"text":"What determines a consumer's demand for a product?","options":[{"label":"A","text":"✓ | ✓ | ✓"},{"label":"B","text":"✓ | ✓ | ✘"},{"label":"C","text":"✘ | ✓ | ✓"},{"label":"D","text":"✓ | ✘ | ✓"}],"correct":""},{"id":6,"text":"Which problem will be reduced by a government subsidy to a firm?","options":[{"label":"A","text":"absence of a public good"},{"label":"B","text":"abuse of monopoly power"},{"label":"C","text":"overconsumption of a demerit good"},{"label":"D","text":"underconsumption of a merit good"}],"correct":""},{"id":7,"text":"What might cause consumers in a high-income economy to both save more and spend more?","options":[{"label":"A","text":"an increase in the rate of interest"},{"label":"B","text":"an increase in wealth"},{"label":"C","text":"expectation that prices will fall in the future"},{"label":"D","text":"inflation rising at a faster rate than wages"}],"correct":""},{"id":8,"text":"What would be a disadvantage of specialisation for a worker?","options":[{"label":"A","text":"a low price of the product that they make"},{"label":"B","text":"boredom due to repetition of the same task"},{"label":"C","text":"higher quality of the good"},{"label":"D","text":"the opportunity to undertake training"}],"correct":""},{"id":9,"text":"Which cost of production falls continuously as output increases?","options":[{"label":"A","text":"average fixed cost"},{"label":"B","text":"average total cost"},{"label":"C","text":"average variable cost"},{"label":"D","text":"O total variable cost"}],"correct":""},{"id":10,"text":"A Swedish furniture maker bought a Romanian firm that owned 83000 hectares of trees. Which type of merger is this most likely to be?","options":[{"label":"A","text":"diversification"},{"label":"B","text":"horizontal"},{"label":"C","text":"vertical backward"},{"label":"D","text":"vertical forward"}],"correct":""},{"id":11,"text":"What is calculated when price is multiplied by the quantity demanded of a product?","options":[{"label":"A","text":"average revenue"},{"label":"B","text":"profit"},{"label":"C","text":"total cost"},{"label":"D","text":"total revenue"}],"correct":""},{"id":12,"text":"A private sector firm is the only supplier of rail services between two cities. What will stop the firm charging very high ticket prices?","options":[{"label":"A","text":"barriers to entry into rail services"},{"label":"B","text":"competition from public road transport"},{"label":"C","text":"government policy encouraging monopoly power"},{"label":"D","text":"high costs of maintaining rail tracks"}],"correct":""},{"id":13,"text":"What is a fiscal policy measure?","options":[{"label":"A","text":"direct tax"},{"label":"B","text":"exchange rates"},{"label":"C","text":"interest rates"},{"label":"D","text":"regulation"}],"correct":""},{"id":14,"text":"A government uses expansionary monetary policy. What does the government decrease?","options":[{"label":"A","text":"bank lending"},{"label":"B","text":"interest rates"},{"label":"C","text":"the budget deficit"},{"label":"D","text":"the money supply"}],"correct":""},{"id":15,"text":"A country is experiencing unemployment. It has a progressive income tax policy and benefits for the poor. The government aims to increase employment and reduce income inequality. Which fiscal policy measures are most likely to achieve these aims?","options":[{"label":"A","text":"decrease the highest tax rate | decrease"},{"label":"B","text":"increase the highest tax rate | decrease"},{"label":"C","text":"decrease the lowest tax rate | increase"},{"label":"D","text":"increase the lowest tax rate | increase"}],"correct":""},{"id":16,"text":"The table shows changes in the Consumer Prices Index (CPI) from the base year, 1, and for the next three years. Which statement is correct?","options":[{"label":"A","text":"Consumer prices were highest in year 3."},{"label":"B","text":"The rate of inflation was 2.1% in year 4."},{"label":"C","text":"The rate of inflation was highest in year 2."},{"label":"D","text":"The rate of inflation was lowest in year 1."}],"correct":"","table":"<table><tr><td>year</td><td>1</td><td>2</td><td>3</td><td>4</td></tr><tr><td>CPI</td><td>100</td><td>101.1</td><td>101.8</td><td>102.1</td></tr></table>"},{"id":17,"text":"What is likely to happen when a country is experiencing deflation?","options":[{"label":"A","text":"Consumers delay spending."},{"label":"B","text":"Governments raise interest rates."},{"label":"C","text":"The level of imports increases."},{"label":"D","text":"The real value of money falls."}],"correct":""},{"id":18,"text":"Economic growth can be defined as","options":[{"label":"A","text":"a reduction in a country's rate of inflation."},{"label":"B","text":"an increase in a country's exports."},{"label":"C","text":"an increase in a country's population."},{"label":"D","text":"an increase in a country's productive capacity."}],"correct":""},{"id":19,"text":"The table compares the distribution of employment in selected industries in two years. How did the distribution of employment change between year 1 and year 2?","options":[{"label":"A","text":"fell | rose"},{"label":"B","text":"fell | unchanged"},{"label":"C","text":"rose | fell"},{"label":"D","text":"rose | unchanged"}],"correct":"","table":"<table><tr><td rowspan=\"2\">industry</td><td colspan=\"2\">employment in millions</td></tr><tr><td>year 1</td><td>year 2</td></tr><tr><td>agriculture</td><td>4</td><td>3</td></tr><tr><td>mining</td><td>2</td><td>2</td></tr><tr><td>manufacturing</td><td>6</td><td>6</td></tr><tr><td>retailing</td><td>4</td><td>4</td></tr><tr><td>transport</td><td>4</td><td>5</td></tr><tr><td>total</td><td>20</td><td>20</td></tr></table>"},{"id":20,"text":"In a year, two changes occurred in a company. Company directors' salaries increased by 15%. Office workers' wages increased by 5%. The rate of inflation was 3.4%. What happened to real income?","options":[{"label":"A","text":"fell | fell"},{"label":"B","text":"fell | rose"},{"label":"C","text":"rose | fell"},{"label":"D","text":"rose | rose"}],"correct":""},{"id":21,"text":"The richest 60% of the population of a high-income economy received an increase in income. The income of the rest of the population did not change. What happened to absolute and relative poverty?","options":[{"label":"A","text":"increased | increased"},{"label":"B","text":"increased | remained constant"},{"label":"C","text":"remained constant | increased"},{"label":"D","text":"remained constant | remained constant"}],"correct":""},{"id":22,"text":"Gross Domestic Product (GDP) is a better measure of comparative living standards when it is adjusted for the effects of","options":[{"label":"A","text":"exports and inflation."},{"label":"B","text":"imports and exports."},{"label":"C","text":"population change and exports."},{"label":"D","text":"population change and inflation."}],"correct":""},{"id":23,"text":"What is the most likely benefit for a low-income economy if it removes tariffs on imported goods and services?","options":[{"label":"A","text":"more choice for domestic consumers"},{"label":"B","text":"more employment in declining industries"},{"label":"C","text":"more exports by domestic firms"},{"label":"D","text":"more tax revenue from imports"}],"correct":""},{"id":24,"text":"Economies have become increasingly linked through globalisation. What would discourage this?","options":[{"label":"A","text":"creation of a single world market"},{"label":"B","text":"direct foreign investment by multinational companies"},{"label":"C","text":"expansion of trade in financial services"},{"label":"D","text":"protectionist policies by trading groups"}],"correct":""},{"id":25,"text":"What may result from a balance of payments trade surplus?","options":[{"label":"A","text":"The exchange rate appreciates and causes export prices to fall."},{"label":"B","text":"The exchange rate appreciates and causes export prices to rise."},{"label":"C","text":"The exchange rate depreciates and causes export prices to fall."},{"label":"D","text":"The exchange rate depreciates and causes export prices to rise."}],"correct":""},{"id":26,"text":"A country has a deficit on its current account of its balance of payments. What could increase the size of its deficit?","options":[{"label":"A","text":"increased exports of its services"},{"label":"B","text":"increased international competitiveness of its goods"},{"label":"C","text":"increased numbers of visitors from abroad"},{"label":"D","text":"increased spending on its military bases abroad"}],"correct":""}];

const paper_06: MCQQuestion[] = [{"id":1,"text":"Increasing output of one good reduces production of another good. Which economic concept does this change represent?","options":[{"label":"A","text":"average cost"},{"label":"B","text":"diseconomies of scale"},{"label":"C","text":"economies of scale"},{"label":"D","text":"opportunity cost"}],"correct":""},{"id":2,"text":"What condition in an economy would encourage immigration of labour?","options":[{"label":"A","text":"high cost of housing"},{"label":"B","text":"preference for domestic over foreign qualifications"},{"label":"C","text":"reduced quotas for foreign workers"},{"label":"D","text":"shortage of skilled workers"}],"correct":""},{"id":3,"text":"Who is a microeconomic decision maker?","options":[{"label":"A","text":"the director of an international trade organisation"},{"label":"B","text":"the entrepreneur of a firm"},{"label":"C","text":"the finance minister of a government"},{"label":"D","text":"the governor of a central bank"}],"correct":""},{"id":4,"text":"What is an essential feature of a market economy?","options":[{"label":"A","text":"Central planners determine what, how and for whom to produce."},{"label":"B","text":"It aims for equality in the distribution of goods and services."},{"label":"C","text":"The market price reflects both the private and external costs of production."},{"label":"D","text":"The price mechanism sends signals to consumers and producers to allocate resources."}],"correct":""},{"id":5,"text":"What is a definition of market failure?","options":[{"label":"A","text":"market forces of demand and supply do not allocate resources efficiently"},{"label":"B","text":"not all consumers can afford to buy the goods they would like"},{"label":"C","text":"private benefits of consumption are greater than external benefits"},{"label":"D","text":"public goods are only provided by a government"}],"correct":""},{"id":6,"text":"Average incomes rose by 5% but savings did not rise. What might explain this?","options":[{"label":"A","text":"Consumer confidence in the economy fell."},{"label":"B","text":"Incomes rose more slowly than the rate of inflation."},{"label":"C","text":"Interest rates for savings rose."},{"label":"D","text":"The rate of income tax was reduced."}],"correct":""},{"id":7,"text":"Which firm is in the tertiary sector?","options":[{"label":"A","text":"bread bakery"},{"label":"B","text":"fruit grower"},{"label":"C","text":"meal delivery"},{"label":"D","text":"road builder"}],"correct":""},{"id":8,"text":"What is a benefit to a worker of being a member of a trade union?","options":[{"label":"A","text":"access to advice"},{"label":"B","text":"guaranteed employment"},{"label":"C","text":"opportunity to work extra hours"},{"label":"D","text":"payment of subscriptions"}],"correct":""},{"id":9,"text":"How would advertising a good result in a retail firm increasing its market share?","options":[{"label":"A","text":"It will improve the personal service in its shops."},{"label":"B","text":"It will increase the firm's costs."},{"label":"C","text":"It will reduce demand for competitors' products."},{"label":"D","text":"It will result in diversification in the firm."}],"correct":""},{"id":10,"text":"What describes the total revenue of a firm?","options":[{"label":"A","text":"fixed costs plus variable costs"},{"label":"B","text":"income from sales minus total costs"},{"label":"C","text":"quantity of goods sold multiplied by unit price"},{"label":"D","text":"variable costs divided by output"}],"correct":""},{"id":11,"text":"What is fiscal policy?","options":[{"label":"A","text":"government decisions on money supply and interest rates taken to influence total demand"},{"label":"B","text":"government decisions on spending and taxation designed to influence total demand"},{"label":"C","text":"government measures designed to influence total supply in the economy"},{"label":"D","text":"government regulation of the foreign exchange rate to influence imports"}],"correct":""},{"id":12,"text":"What is the money supply?","options":[{"label":"A","text":"the total quantity of foreign currency available within the economy"},{"label":"B","text":"the total quantity of money available within the economy"},{"label":"C","text":"the total quantity of money issued by the central bank"},{"label":"D","text":"the total quantity of money within commercial banks"}],"correct":""},{"id":13,"text":"The table shows the Consumer Prices Index (CPI) of a country for five years. Which statement about the country is correct?","options":[{"label":"A","text":"It faced deflation in year 2."},{"label":"B","text":"It faced deflation in year 3."},{"label":"C","text":"It faced inflation in year 4."},{"label":"D","text":"It faced inflation in year 5."}],"correct":"","table":"<table><tr><td>year</td><td>CPI</td></tr><tr><td>1</td><td>100</td></tr><tr><td>2</td><td>120</td></tr><tr><td>3</td><td>135</td></tr><tr><td>4</td><td>140</td></tr><tr><td>5</td><td>138</td></tr></table>"},{"id":14,"text":"What may cause deflation?","options":[{"label":"A","text":"advances in technology and increases in labour productivity"},{"label":"B","text":"government using a policy of very low interest rates"},{"label":"C","text":"increases in the costs of production that reduce firms' profits"},{"label":"D","text":"increases in the rate of inflation as measured by the CPI"}],"correct":""},{"id":15,"text":"Economic growth can be defined as","options":[{"label":"A","text":"a reduction in a country's rate of inflation."},{"label":"B","text":"an increase in a country's exports."},{"label":"C","text":"an increase in a country's population."},{"label":"D","text":"an increase in a country's productive capacity."}],"correct":""},{"id":16,"text":"The table compares the distribution of employment in selected industries in two years. How did the distribution of employment change between year 1 and year 2?","options":[{"label":"A","text":"fell | rose"},{"label":"B","text":"fell | unchanged"},{"label":"C","text":"rose | fell"},{"label":"D","text":"rose | unchanged"}],"correct":"","table":"<table><tr><td rowspan=\"2\">industry</td><td colspan=\"2\">employment in millions</td></tr><tr><td>year 1</td><td>year 2</td></tr><tr><td>agriculture</td><td>4</td><td>3</td></tr><tr><td>mining</td><td>2</td><td>2</td></tr><tr><td>manufacturing</td><td>6</td><td>6</td></tr><tr><td>retailing</td><td>4</td><td>4</td></tr><tr><td>transport</td><td>4</td><td>5</td></tr><tr><td>total</td><td>20</td><td>20</td></tr></table>"},{"id":17,"text":"In a year, two changes occurred in a company. Company directors' salaries increased by 15%. Office workers' wages increased by 5%. The rate of inflation was 3.4%. What happened to real income?","options":[{"label":"A","text":"fell | fell"},{"label":"B","text":"fell | rose"},{"label":"C","text":"rose | fell"},{"label":"D","text":"rose | rose"}],"correct":""},{"id":18,"text":"The richest 60% of the population of a high-income economy received an increase in income. The income of the rest of the population did not change. What happened to absolute and relative poverty?","options":[{"label":"A","text":"increased | increased"},{"label":"B","text":"increased | remained constant"},{"label":"C","text":"remained constant | increased"},{"label":"D","text":"remained constant | remained constant"}],"correct":""},{"id":19,"text":"Gross Domestic Product (GDP) is a better measure of comparative living standards when it is adjusted for the effects of","options":[{"label":"A","text":"exports and inflation."},{"label":"B","text":"imports and exports."},{"label":"C","text":"population change and exports."},{"label":"D","text":"population change and inflation."}],"correct":""},{"id":20,"text":"What is a benefit of a multinational company (MNC) to the host country?","options":[{"label":"A","text":"A MNC may improve the reputation of its home country as a high-quality producer."},{"label":"B","text":"Exports by a MNC may result in an improved trade balance for the host country."},{"label":"C","text":"Production by a MNC may lead to higher levels of pollution in the host country."},{"label":"D","text":"Profits made by a MNC are sent back to its home country."}],"correct":""},{"id":21,"text":"Globalisation is the process by which domestic firms become involved in international markets. What encourages globalisation?","options":[{"label":"A","text":"controls on foreign exchange"},{"label":"B","text":"immigration restrictions"},{"label":"C","text":"increasing tariffs"},{"label":"D","text":"widespread use of the internet"}],"correct":""},{"id":22,"text":"What does a foreign exchange rate between Malaysia and the US measure?","options":[{"label":"A","text":"the cost of the Malaysian currency in the US currency"},{"label":"B","text":"the difference in the cost of living between Malaysia and the US"},{"label":"C","text":"the difference in the standard of living between Malaysia and the US"},{"label":"D","text":"GDP of Malaysia divided by the GDP of the US"}],"correct":""},{"id":23,"text":"A country has a deficit on its current account of its balance of payments. What could increase the size of its deficit?","options":[{"label":"A","text":"increased exports of its services"},{"label":"B","text":"increased international competitiveness of its goods"},{"label":"C","text":"increased numbers of visitors from abroad"},{"label":"D","text":"increased spending on its military bases abroad"}],"correct":""}];

const paper_07: MCQQuestion[] = [{"id":1,"text":"A government uses different supply-side policy measures to improve economic performance. Which policy measure would not satisfy one of the government's macroeconomic aims?","options":[{"label":"A","text":"changing the tax system which leads to more tax evasion"},{"label":"B","text":"encouraging foreign investment which improves the balance of payments"},{"label":"C","text":"privatising state industries which increases economic growth"},{"label":"D","text":"retraining redundant workers which lowers unemployment"}],"correct":""},{"id":2,"text":"What could cause an increase in demand for a factor of production?","options":[{"label":"A","text":"decrease in the efficiency of the factor of production"},{"label":"B","text":"decrease in the price of an alternative factor of production"},{"label":"C","text":"increase in the demand for the good or service produced"},{"label":"D","text":"increase in the price of the factor of production"}],"correct":""},{"id":3,"text":"Which components, in addition to Gross Domestic Product (GDP) per head, are included in the Human Development Index (HDI)?","options":[{"label":"A","text":"average earnings and inequalities of incomes"},{"label":"B","text":"balance of trade and balance of payments"},{"label":"C","text":"life expectancy at birth and expected years of schooling"},{"label":"D","text":"size of population and age structure of population"}],"correct":""},{"id":4,"text":"The US government introduces tariffs on steel imported from China. This increases the price of imported Chinese steel. Whose income would be likely to increase as a direct result?","options":[{"label":"A","text":"yes | yes"},{"label":"B","text":"yes | no"},{"label":"C","text":"no | yes"},{"label":"D","text":"no | no"}],"correct":""},{"id":5,"text":"A government retrains unemployed industrial workers to increase employment opportunities. The policy may have adverse effects on other government macroeconomic aims. What illustrates this situation?","options":[{"label":"A","text":"Better skilled workers may increase productivity and improve economic growth."},{"label":"B","text":"Increased wage-earning capacity may lead to demand-pull inflation."},{"label":"C","text":"More employed workers may reduce government expenditure on benefit payments."},{"label":"D","text":"Near full employment may result in a more stable balance of payments."}],"correct":""},{"id":6,"text":"The diagram shows the demand and supply for apples. To what extent is the market for apples in disequilibrium at a price of \\$2.50 per kilo?","options":[{"label":"A","text":"Demand exceeds supply by 200000 tonnes."},{"label":"B","text":"Demand exceeds supply by 400000 tonnes."},{"label":"C","text":"Supply exceeds demand by 200000 tonnes."},{"label":"D","text":"Supply exceeds demand by 400000 tonnes."}],"correct":"","image":"/images/econ-mcq/65_608_695_581_522_0.jpg"},{"id":7,"text":"The table shows the world output of iron ore and the average yearly price for four years. What can be concluded about the relationship between world output of iron ore and the average yearly price over the four years?","options":[{"label":"A","text":"highest | highest"},{"label":"B","text":"highest | lowest"},{"label":"C","text":"lowest | highest"},{"label":"D","text":"lowest | lowest"}],"correct":"","table":"<table><tr><td>year</td><td>world output of iron ore (billion tonnes)</td><td>average yearly price (\\$ per tonne)</td></tr><tr><td>year 1</td><td>2.86</td><td>128</td></tr><tr><td>year 2</td><td>2.98</td><td>135</td></tr><tr><td>year 3</td><td>2.22</td><td>97</td></tr><tr><td>year 4</td><td>2.28</td><td>95</td></tr></table>"},{"id":8,"text":"A firm has a high price elasticity of supply for its product. What does this indicate?","options":[{"label":"A","text":"It can increase revenue by reducing the price."},{"label":"B","text":"It can quickly respond to changes in price."},{"label":"C","text":"It keeps very low volumes of product in stock."},{"label":"D","text":"It produces a good that has close substitutes."}],"correct":""},{"id":9,"text":"A manufacturer of medical supplies benefits from improved road links to its main markets. What benefit definitely occurs as a result?","options":[{"label":"A","text":"increased average revenue"},{"label":"B","text":"increased external economies of scale"},{"label":"C","text":"increased internal economies of scale"},{"label":"D","text":"increased market share"}],"correct":""},{"id":10,"text":"Which row shows an essential characteristic of competitive markets and monopoly markets?","options":[{"label":"A","text":"many buyers | single seller"},{"label":"B","text":"many sellers | single buyer"},{"label":"C","text":"single buyer | many buyers"},{"label":"D","text":"single seller | many sellers"}],"correct":""},{"id":11,"text":"A student has nothing to do on a Friday evening. She withdraws \\$5 from the \\$100 she has in a savings account and buys a present to take to a party, to which admission is free. What does this involve?","options":[{"label":"A","text":"an opportunity cost equal to \\$95"},{"label":"B","text":"an opportunity cost equal to other goods she could have bought for \\$5"},{"label":"C","text":"no opportunity cost, as entrance to the party is free"},{"label":"D","text":"no opportunity cost, as she had no better way of using the time"}],"correct":""},{"id":12,"text":"The development of artificial intelligence in machines raises the productivity of capital. What will be the effect of this?","options":[{"label":"A","text":"The costs of production will increase."},{"label":"B","text":"The demand for capital will increase."},{"label":"C","text":"The price of capital will fall."},{"label":"D","text":"The supply of capital will decrease."}],"correct":""},{"id":13,"text":"Which combination is necessary for the construction of a consumer prices index?","options":[{"label":"A","text":"yes | yes | yes"},{"label":"B","text":"yes | no | yes"},{"label":"C","text":"yes | no | no"},{"label":"D","text":"no | yes | yes"}],"correct":""},{"id":14,"text":"A government removed the quota on goods imported into the country. What is the most likely result of this?","options":[{"label":"A","text":"a decrease in demand for domestic production"},{"label":"B","text":"a decrease in domestic unemployment"},{"label":"C","text":"a decrease in exports"},{"label":"D","text":"a decrease in the balance of trade deficit"}],"correct":""},{"id":15,"text":"What is an advantage of a country having a market economic system with a large private sector?","options":[{"label":"A","text":"Firms can become unprofitable if they do not produce what consumers want."},{"label":"B","text":"Market forces often fail to ensure maximum benefits for society."},{"label":"C","text":"Some goods may not be provided at all or not in sufficient quantity."},{"label":"D","text":"There is an unequal distribution of income which can increase over time."}],"correct":""},{"id":16,"text":"What is an example of a fiscal policy measure?","options":[{"label":"A","text":"increasing the exchange rate"},{"label":"B","text":"reducing the power of trade unions"},{"label":"C","text":"reducing the rate of corporation tax"},{"label":"D","text":"setting a lower interest rate"}],"correct":""},{"id":17,"text":"Why would an increase in the interest rate potentially lead to lower inflation?","options":[{"label":"A","text":"Consumers will be more willing to save when interest rates are high."},{"label":"B","text":"Consumers will be more willing to spend when interest rates are high."},{"label":"C","text":"Producers will be more willing to borrow from banks when interest rates are high."},{"label":"D","text":"Producers will be more willing to invest when interest rates are high."}],"correct":""},{"id":18,"text":"Which government action will not add directly to the quantity or quality of human resources?","options":[{"label":"A","text":"improvement in health facilities"},{"label":"B","text":"investment in education and training"},{"label":"C","text":"provision of better food and nutrition"},{"label":"D","text":"reclamation of land from the sea"}],"correct":""},{"id":19,"text":"What is a likely cause of economic growth?","options":[{"label":"A","text":"decreased employment"},{"label":"B","text":"decreased investment"},{"label":"C","text":"decreased productivity"},{"label":"D","text":"decreased taxation"}],"correct":""},{"id":20,"text":"The table shows how three people, X, Y and Z, spend their income. What is the likely order of income, from lowest income to highest income, for these three people?","options":[{"label":"A","text":"\\( Y \\rightarrow  X \\rightarrow  Z \\)"},{"label":"B","text":"\\( Y \\rightarrow  Z \\rightarrow  X \\)"},{"label":"C","text":"\\( Z \\rightarrow  X \\rightarrow  Y \\)"},{"label":"D","text":"\\( Z \\rightarrow  Y \\rightarrow  X \\)"}],"correct":"","table":"<table><tr><td></td><td>person X</td><td>person Y</td><td>person Z</td></tr><tr><td>food, clothing and housing</td><td>30%</td><td>25%</td><td>50%</td></tr><tr><td>entertainment and leisure</td><td>35%</td><td>35%</td><td>25%</td></tr><tr><td>luxury goods</td><td>35%</td><td>40%</td><td>25%</td></tr></table>"},{"id":21,"text":"Why would standards of living fall when there is a recession?","options":[{"label":"A","text":"The government would increase taxes to combat the recession."},{"label":"B","text":"The purchasing power of households would fall."},{"label":"C","text":"The value of the domestic currency would increase."},{"label":"D","text":"There would be a rise in the level of immigration."}],"correct":""},{"id":22,"text":"What is the purpose of an economy's production possibility curve (PPC)?","options":[{"label":"A","text":"It answers the question of what to produce in an economy."},{"label":"B","text":"It enables microeconomic decisions to be taken by firms."},{"label":"C","text":"It measures the supply of goods and services available in an economy."},{"label":"D","text":"It shows the productive capacity in an economy at a point in time."}],"correct":""},{"id":23,"text":"The governments of low-income countries often allow foreign multinational companies (MNCs) to mine minerals in their country. Which conflict between benefit and cost might this cause the low-income countries?","options":[{"label":"A","text":"improved balance of trade | training by the MNCs"},{"label":"B","text":"higher employment | loss of a finite resource"},{"label":"C","text":"increased profits for the MNCs | efficient production"},{"label":"D","text":"more sustainable development | economic growth"}],"correct":""},{"id":24,"text":"The table shows some economic indicators. Which increase in the first indicator is most likely to lead to an increase in the second indicator?","options":[{"label":"A","text":"budget surplus | consumer saving"},{"label":"B","text":"consumer spending | unemployment"},{"label":"C","text":"inflation | trade surplus"},{"label":"D","text":"productivity | living standards"}],"correct":""},{"id":25,"text":"What is the definition of foreign exchange rate?","options":[{"label":"A","text":"the difference between emigration and immigration"},{"label":"B","text":"the difference between the values of imports and exports"},{"label":"C","text":"the price of one currency in terms of another"},{"label":"D","text":"the price of one good in terms of another"}],"correct":""},{"id":26,"text":"Which activity is correctly linked to the organisation that provides it?","options":[{"label":"A","text":"central bank | regulate the rate of inflation"},{"label":"B","text":"central bank | set direct tax rates"},{"label":"C","text":"commercial bank | manage the government's financial accounts"},{"label":"D","text":"commercial bank | safeguard the country's foreign reserves"}],"correct":""},{"id":27,"text":"Which topic is not included in microeconomics?","options":[{"label":"A","text":"consumer demand"},{"label":"B","text":"economies of scale"},{"label":"C","text":"forms of competition"},{"label":"D","text":"inflation"}],"correct":""}];

const paper_08: MCQQuestion[] = [{"id":1,"text":"What is an example of a free good?","options":[{"label":"A","text":"defence"},{"label":"B","text":"education"},{"label":"C","text":"health services"},{"label":"D","text":"sunshine"}],"correct":""},{"id":2,"text":"A student has nothing to do on a Friday evening. She withdraws \\$5 from the \\$100 she has in a savings account and buys a present to take to a party, to which admission is free. What does this involve?","options":[{"label":"A","text":"an opportunity cost equal to \\$95"},{"label":"B","text":"an opportunity cost equal to other goods she could have bought for \\$5"},{"label":"C","text":"no opportunity cost, as entrance to the party is free"},{"label":"D","text":"no opportunity cost, as she had no better way of using the time"}],"correct":""},{"id":3,"text":"The diagram shows two production possibility curves for a country. What might cause a shift from point K to point L in the country's production?","options":[{"label":"A","text":"a change in what consumers want to buy"},{"label":"B","text":"a recession"},{"label":"C","text":"more investment"},{"label":"D","text":"the use of previously unemployed resources"}],"correct":"","image":"/images/econ-mcq/73_663_1038_470_440_0.jpg"},{"id":4,"text":"In recent years, a government has started to make more use of the free market system. However, they are doing it very slowly to avoid the disadvantages that a free market system might bring. What is a possible disadvantage of the free market system?","options":[{"label":"A","text":"decreased incentive to work"},{"label":"B","text":"decreased levels of pollution"},{"label":"C","text":"increased efficiency"},{"label":"D","text":"increased inequality of income"}],"correct":""},{"id":5,"text":"What will cause the demand curve for a good to shift to the right?","options":[{"label":"A","text":"a decrease in the disposable income of consumers"},{"label":"B","text":"a decrease in the price of a complement good"},{"label":"C","text":"a decrease in the price of a substitute good"},{"label":"D","text":"a decrease in the price of the good"}],"correct":""},{"id":6,"text":"The table shows the demand and supply schedules for rice. The current price is \\$2.00 per kilo. What will happen if the price is reduced to \\$1.00 per kilo?","options":[{"label":"A","text":"The demand schedule will shift to the left."},{"label":"B","text":"The market will move from shortage to surplus."},{"label":"C","text":"The market will move from surplus to shortage."},{"label":"D","text":"The supply schedule will shift to the right."}],"correct":"","table":"<table><tr><td>price per kilo \\$</td><td>quantity demanded (million tonnes)</td><td>quantity supplied (million tonnes)</td></tr><tr><td>2.50</td><td>5</td><td>30</td></tr><tr><td>2.00</td><td>10</td><td>25</td></tr><tr><td>1.50</td><td>20</td><td>20</td></tr><tr><td>1.00</td><td>30</td><td>15</td></tr><tr><td>0.50</td><td>40</td><td>10</td></tr></table>"},{"id":7,"text":"What could cause profits to be high in a monopoly market?","options":[{"label":"A","text":"barriers to entry"},{"label":"B","text":"diseconomies of scale"},{"label":"C","text":"elastic demand for the product"},{"label":"D","text":"high number of substitutes for the product"}],"correct":""},{"id":8,"text":"Which firm is most likely to be classified as a small firm in the tertiary sector?","options":[{"label":"A","text":"a farm"},{"label":"B","text":"a hairdresser"},{"label":"C","text":"a steelworks"},{"label":"D","text":"a supermarket"}],"correct":""},{"id":9,"text":"Germany is considered a capital-intensive economy while Indonesia is considered a labour-intensive economy. What does this mean about the economies of Germany and Indonesia?","options":[{"label":"A","text":"Capital is relatively cheaper than labour in Germany while labour is relatively cheaper than capital in Indonesia."},{"label":"B","text":"Germany has many primary sector workers while Indonesia has many tertiary sector workers."},{"label":"C","text":"Indonesia has a higher growth in its population size than Germany."},{"label":"D","text":"Relatively more low-cost labour is available in Germany while capital is more efficient than labour in Indonesia."}],"correct":""},{"id":10,"text":"A bank continues to operate loss-making branches. Which objective is the bank trying to achieve?","options":[{"label":"A","text":"growth"},{"label":"B","text":"efficiency"},{"label":"C","text":"profit maximisation"},{"label":"D","text":"social welfare"}],"correct":""},{"id":11,"text":"The table shows how three people, X, Y and Z, spend their income. What is the likely order of income, from lowest income to highest income, for these three people?","options":[{"label":"A","text":"\\( Y \\rightarrow  X \\rightarrow  Z \\)"},{"label":"B","text":"\\( Y \\rightarrow  Z \\rightarrow  X \\)"},{"label":"C","text":"\\( Z \\rightarrow  X \\rightarrow  Y \\)"},{"label":"D","text":"\\( Z \\rightarrow  Y \\rightarrow  X \\)"}],"correct":"","table":"<table><tr><td></td><td>person X</td><td>person Y</td><td>person Z</td></tr><tr><td>food, clothing and housing</td><td>30%</td><td>25%</td><td>50%</td></tr><tr><td>entertainment and leisure</td><td>35%</td><td>35%</td><td>25%</td></tr><tr><td>luxury goods</td><td>35%</td><td>40%</td><td>25%</td></tr></table>"},{"id":12,"text":"Which activity is correctly linked to the organisation that provides it?","options":[{"label":"A","text":"central bank | regulate the rate of inflation"},{"label":"B","text":"central bank | set direct tax rates"},{"label":"C","text":"commercial bank | manage the government's financial accounts"},{"label":"D","text":"commercial bank | safeguard the country's foreign reserves"}],"correct":""},{"id":13,"text":"The chart shows a government's spending in a year. What was the total government spending on public goods?","options":[{"label":"A","text":"\\$2390 million"},{"label":"B","text":"\\$5050 million"},{"label":"C","text":"\\$7440 million"},{"label":"D","text":"\\$33940 million"}],"correct":"","image":"/images/econ-mcq/77_330_662_1138_595_0.jpg"},{"id":14,"text":"A government wishes to pursue an expansionary monetary policy. What should it do?","options":[{"label":"A","text":"discourage bank lending"},{"label":"B","text":"give subsidies to firms"},{"label":"C","text":"lower income tax thresholds"},{"label":"D","text":"lower interest rates"}],"correct":""},{"id":15,"text":"A government introduces a series of economic measures. What is a supply-side policy measure?","options":[{"label":"A","text":"building more affordable homes to improve labour mobility"},{"label":"B","text":"controlling consumer spending to reduce inflation"},{"label":"C","text":"lowering interest rates to encourage purchase of expensive goods"},{"label":"D","text":"raising pensions to help retired people pay their fuel bills"}],"correct":""},{"id":16,"text":"What is identified as economic growth?","options":[{"label":"A","text":"a fall in labour productivity"},{"label":"B","text":"an increase in the productive capacity of the economy"},{"label":"C","text":"an increase in the Consumer Prices Index (CPI)"},{"label":"D","text":"the economy enters a period of recession"}],"correct":""},{"id":17,"text":"The retail trade in a country has unemployed workers in one region and job vacancies in another region. What could explain this?","options":[{"label":"A","text":"Costs of employing workers are lower when there is unemployment."},{"label":"B","text":"It is more expensive to live in the area where the retail jobs are available."},{"label":"C","text":"Retailing demands the same skills everywhere."},{"label":"D","text":"The geographical mobility of labour has increased."}],"correct":""},{"id":18,"text":"A country wishes to reduce the level of inflation. Which combination of policy measures will be most successful?","options":[{"label":"A","text":"decrease exchange rates | increase interest rates"},{"label":"B","text":"decrease interest rates | increase exchange rates"},{"label":"C","text":"increase government spending | decrease interest rates"},{"label":"D","text":"increase interest rates | decrease government spending"}],"correct":""},{"id":19,"text":"A government wants to reduce both its budget deficit and the amount of poverty in its country. Which fiscal policy measure is most likely to achieve both of these aims?","options":[{"label":"A","text":"decreasing the rate of progressive income tax"},{"label":"B","text":"decreasing government spending on welfare benefits"},{"label":"C","text":"increasing the rate of progressive income tax"},{"label":"D","text":"increasing government spending on welfare benefits"}],"correct":""},{"id":20,"text":"Which components, in addition to Gross Domestic Product (GDP) per head, are included in the Human Development Index (HDI)?","options":[{"label":"A","text":"average earnings and inequalities of incomes"},{"label":"B","text":"balance of trade and balance of payments"},{"label":"C","text":"life expectancy at birth and expected years of schooling"},{"label":"D","text":"size of population and age structure of population"}],"correct":""},{"id":21,"text":"What is likely to cause an immediate decrease in the size of the labour force?","options":[{"label":"A","text":"a fall in the average size of families"},{"label":"B","text":"a fall in the birth rate"},{"label":"C","text":"a reduction in the age of retirement"},{"label":"D","text":"an increase in net immigration"}],"correct":""},{"id":22,"text":"The table shows some economic indicators. Which increase in the first indicator is most likely to lead to an increase in the second indicator?","options":[{"label":"A","text":"budget surplus | consumer saving"},{"label":"B","text":"consumer spending | unemployment"},{"label":"C","text":"inflation | trade surplus"},{"label":"D","text":"productivity | living standards"}],"correct":""},{"id":23,"text":"The price of a currency in a fixed exchange rate system is reduced. What is this called?","options":[{"label":"A","text":"appreciation"},{"label":"B","text":"depreciation"},{"label":"C","text":"devaluation"},{"label":"D","text":"revaluation"}],"correct":""},{"id":24,"text":"A government removed the quota on goods imported into the country. What is the most likely result of this?","options":[{"label":"A","text":"a decrease in demand for domestic production"},{"label":"B","text":"a decrease in domestic unemployment"},{"label":"C","text":"a decrease in exports"},{"label":"D","text":"a decrease in the balance of trade deficit"}],"correct":""},{"id":25,"text":"What is most likely to result from a reduction in the value of a country's currency if there are no other changes in the economy?","options":[{"label":"A","text":"A trade in goods surplus will fall."},{"label":"B","text":"Export prices will rise."},{"label":"C","text":"Import prices will rise."},{"label":"D","text":"The inflation rate will fall."}],"correct":""},{"id":26,"text":"The governments of low-income countries often allow foreign multinational companies (MNCs) to mine minerals in their country. Which conflict between benefit and cost might this cause the low-income countries?","options":[{"label":"A","text":"improved balance of trade | training by the MNCs"},{"label":"B","text":"higher employment | loss of a finite resource"},{"label":"C","text":"increased profits for the MNCs | efficient production"},{"label":"D","text":"more sustainable development | economic growth"}],"correct":""}];

const paper_09: MCQQuestion[] = [{"id":1,"text":"Which factor has the correct factor reward identified?","options":[{"label":"A","text":"capital | profit"},{"label":"B","text":"enterprise | wages"},{"label":"C","text":"labour | interest"},{"label":"D","text":"land | rent"}],"correct":""},{"id":2,"text":"A student has nothing to do on a Friday evening. She withdraws \\$5 from the \\$100 she has in a savings account and buys a present to take to a party, to which admission is free. What does this involve?","options":[{"label":"A","text":"an opportunity cost equal to \\$95"},{"label":"B","text":"an opportunity cost equal to other goods she could have bought for \\$5"},{"label":"C","text":"no opportunity cost, as entrance to the party is free"},{"label":"D","text":") no opportunity cost, as she had no better way of using the time"}],"correct":""},{"id":3,"text":"What would cause a shift in a country's production possibility curve?","options":[{"label":"A","text":"a fall in unemployment"},{"label":"B","text":"a recovery from a recession"},{"label":"C","text":"a rise in prices"},{"label":"D","text":"the destruction of factories in a war"}],"correct":""},{"id":4,"text":"Which topic is studied in macroeconomics?","options":[{"label":"A","text":"cost-push inflation"},{"label":"B","text":"market price determination"},{"label":"C","text":"public goods"},{"label":"D","text":"the output of a firm"}],"correct":""},{"id":5,"text":"China is moving towards a more mixed economic system and reducing the role of the public sector. Which economic policy measure might best achieve this?","options":[{"label":"A","text":"creating excess capacity in state-owned enterprises"},{"label":"B","text":"encouraging competition among private sector firms"},{"label":"C","text":"protecting infant industries"},{"label":"D","text":"subsidising transport infrastructure"}],"correct":""},{"id":6,"text":"The diagram shows the supply and demand for a product. Suppliers have decided to produce 10000 units and charge a price of \\$6. What is the result of this decision in the short run?","options":[{"label":"A","text":"A stable equilibrium price will be achieved."},{"label":"B","text":"Suppliers will be left with unsold stock."},{"label":"C","text":"The equilibrium market price will increase."},{"label":"D","text":"There will be excess demand at the price of \\$6."}],"correct":"","image":"/images/econ-mcq/83_561_232_676_587_0.jpg"},{"id":7,"text":"Which statement about price elasticity of demand (PED) is correct?","options":[{"label":"A","text":"PED measures the percentage change in quantity demanded divided by the percentage change in price."},{"label":"B","text":"PED measures the change in price divided by the change in the quantity demanded."},{"label":"C","text":"PED means a change in price will cause an equal change in the quantity demanded."},{"label":"D","text":"PED means a change in demand will result in a greater percentage change in price."}],"correct":""},{"id":8,"text":"A manufacturer of tinned beans mechanises its assembly line. This increases output by 30% and reduces labour by 20%. How and why will this affect supply curve S?","options":[{"label":"A","text":"S will move to the left due to an increase in average costs."},{"label":"B","text":"S will move to the left due to an increase in the price of tinned beans."},{"label":"C","text":"S will move to the right due to an increase in consumer demand."},{"label":"D","text":"S will move to the right due to an increase in productivity."}],"correct":"","image":"/images/econ-mcq/84_623_338_548_434_0.jpg"},{"id":9,"text":"A cinema has 500 seats. It raised its admission price from \\$2 to \\$5 and daily revenue increased from \\$800 to \\$1500. What can be concluded from this information?","options":[{"label":"A","text":"Price elasticity of demand for cinema seats was elastic."},{"label":"B","text":"Price elasticity of supply of cinema seats was elastic."},{"label":"C","text":"The cinema operated below full capacity."},{"label":"D","text":"The cinema's profits rose by \\$700."}],"correct":""},{"id":10,"text":"What is an outcome of a competitive market?","options":[{"label":"A","text":"high prices and low quality"},{"label":"B","text":"low prices and large choice"},{"label":"C","text":"high profits and low quality"},{"label":"D","text":"low profits and little choice"}],"correct":""},{"id":11,"text":"What might prevent an individual choosing a particular occupation?","options":[{"label":"A","text":"little opportunity for career progression"},{"label":"B","text":"low cost of travelling to work"},{"label":"C","text":"no risk to personal health"},{"label":"D","text":"wage rate above national minimum wage"}],"correct":""},{"id":12,"text":"What might encourage a consumer to spend less and save more?","options":[{"label":"A","text":"the expectation that prices will fall"},{"label":"B","text":"the expectation that prices will rise"},{"label":"C","text":"the expectation that unemployment will fall"},{"label":"D","text":"the expectation that real GDP will rise"}],"correct":""},{"id":13,"text":"The table shows how three people, X, Y and Z, spend their income. What is the likely order of income, from lowest income to highest income, for these three people?","options":[{"label":"A","text":"\\( Y \\rightarrow  X \\rightarrow  Z \\)"},{"label":"B","text":"\\( Y \\rightarrow  Z \\rightarrow  X \\)"},{"label":"C","text":"\\( Z \\rightarrow  X \\rightarrow  Y \\)"},{"label":"D","text":"\\( Z \\rightarrow  Y \\rightarrow  X \\)"}],"correct":"","table":"<table><tr><td></td><td>person X</td><td>person Y</td><td>person Z</td></tr><tr><td>food, clothing and housing</td><td>30%</td><td>25%</td><td>50%</td></tr><tr><td>entertainment and leisure</td><td>35%</td><td>35%</td><td>25%</td></tr><tr><td>luxury goods</td><td>35%</td><td>40%</td><td>25%</td></tr></table>"},{"id":14,"text":"Which activity is correctly linked to the organisation that provides it?","options":[{"label":"A","text":"central bank | regulate the rate of inflation"},{"label":"B","text":"central bank | set direct tax rates"},{"label":"C","text":"commercial bank | manage the government's financial accounts"},{"label":"D","text":"commercial bank | safeguard the country's foreign reserves"}],"correct":""},{"id":15,"text":"What is not usually a macroeconomic aim?","options":[{"label":"A","text":"balance of payments stability"},{"label":"B","text":"high government borrowing"},{"label":"C","text":"lowering cyclical unemployment"},{"label":"D","text":"reducing absolute poverty"}],"correct":""},{"id":16,"text":"A government decides to increase the indirect tax on petrol. Petrol has an inelastic price elasticity of demand. What are likely to be the consequences?","options":[{"label":"A","text":"decreases | decreases"},{"label":"B","text":"decreases | increases"},{"label":"C","text":"increases | decreases"},{"label":"D","text":"increases | increases"}],"correct":""},{"id":17,"text":"In a country, there is an increase in the rate of interest to prevent inflation. Which type of macroeconomic policy is this?","options":[{"label":"A","text":"fiscal policy"},{"label":"B","text":"monetary policy"},{"label":"C","text":"supply-side policy"},{"label":"D","text":"trade policy"}],"correct":""},{"id":18,"text":"A government significantly increases its spending on education and training over several years. What will be the likely effect of this policy measure on the rate of inflation in both the short run and the long run?","options":[{"label":"A","text":"decreases | decreases"},{"label":"B","text":"decreases | increases"},{"label":"C","text":"increases | decreases"},{"label":"D","text":"increases | increases"}],"correct":""},{"id":19,"text":"What may cause a recession?","options":[{"label":"A","text":"an increase in consumer spending"},{"label":"B","text":"an increase in government spending"},{"label":"C","text":"an increase in imports"},{"label":"D","text":"an increase in investment"}],"correct":""},{"id":20,"text":"Why might the macroeconomic aim of full employment conflict with the aim of stable prices?","options":[{"label":"A","text":"Full employment leads to higher cost of imports."},{"label":"B","text":"Full employment leads to increased income inequality."},{"label":"C","text":"Full employment leads to increases in wages."},{"label":"D","text":"Full employment leads to lower exports."}],"correct":""},{"id":21,"text":"In a country, inflation is 10% and nominal interest rates are 7%. Which group is most likely to benefit from this situation?","options":[{"label":"A","text":"borrowers"},{"label":"B","text":"employers"},{"label":"C","text":"lenders"},{"label":"D","text":"savers"}],"correct":""},{"id":22,"text":"Which action is not performed by a government as part of its international role?","options":[{"label":"A","text":"building offshore wind farms"},{"label":"B","text":"imposing tariffs on imports"},{"label":"C","text":"issuing visas to foreign tourists"},{"label":"D","text":"providing humanitarian aid to refugees"}],"correct":""},{"id":23,"text":"Which components, in addition to Gross Domestic Product (GDP) per head, are included in the Human Development Index (HDI)?","options":[{"label":"A","text":"average earnings and inequalities of incomes"},{"label":"B","text":"balance of trade and balance of payments"},{"label":"C","text":"life expectancy at birth and expected years of schooling"},{"label":"D","text":"size of population and age structure of population"}],"correct":""},{"id":24,"text":"What is likely to cause an immediate decrease in the size of the labour force?","options":[{"label":"A","text":"a fall in the average size of families"},{"label":"B","text":"a fall in the birth rate"},{"label":"C","text":"a reduction in the age of retirement"},{"label":"D","text":"an increase in net immigration"}],"correct":""},{"id":25,"text":"The table shows some economic indicators. Which increase in the first indicator is most likely to lead to an increase in the second indicator?","options":[{"label":"A","text":"budget surplus | consumer saving"},{"label":"B","text":"consumer spending | unemployment"},{"label":"C","text":"inflation | trade surplus"},{"label":"D","text":"productivity | living standards"}],"correct":""},{"id":26,"text":"When are countries most likely to specialise and trade with each other?","options":[{"label":"A","text":"when the cost of transport between them is high"},{"label":"B","text":"when there are large differences in their resource allocations"},{"label":"C","text":"when they have access to the same technology"},{"label":"D","text":"when they have high tariffs and other protective measures"}],"correct":""},{"id":27,"text":"A government removed the quota on goods imported into the country. What is the most likely result of this?","options":[{"label":"A","text":"a decrease in demand for domestic production"},{"label":"B","text":"a decrease in domestic unemployment"},{"label":"C","text":"a decrease in exports"},{"label":"D","text":"a decrease in the balance of trade deficit"}],"correct":""},{"id":28,"text":"A country has a surplus on the current account of its balance of payments. What would be most likely to cause the country to move into deficit?","options":[{"label":"A","text":"devaluation of its fixed exchange rate"},{"label":"B","text":"government subsidies to its exporters"},{"label":"C","text":"improved technology in other countries"},{"label":"D","text":"productivity increases in its export industries"}],"correct":""},{"id":29,"text":"The governments of low-income countries often allow foreign multinational companies (MNCs) to mine minerals in their country. Which conflict between benefit and cost might this cause the low-income countries?","options":[{"label":"A","text":"improved balance of trade | training by the MNCs"},{"label":"B","text":"higher employment | loss of a finite resource"},{"label":"C","text":"increased profits for the MNCs | efficient production"},{"label":"D","text":"more sustainable development | economic growth"}],"correct":""}];

const paper_10: MCQQuestion[] = [{"id":1,"text":"What is the cause of scarcity in an economy?","options":[{"label":"A","text":"high employment levels"},{"label":"B","text":"high investment levels"},{"label":"C","text":"unlimited resources"},{"label":"D","text":"unlimited wants"}],"correct":""},{"id":2,"text":"What does a point on a production possibility curve for an economy represent?","options":[{"label":"A","text":"economic growth is falling"},{"label":"B","text":"inefficient use of resources available"},{"label":"C","text":"maximum output possible with current technology"},{"label":"D","text":"total demand for goods and services"}],"correct":""},{"id":3,"text":"What is most likely to increase enterprise as a factor of production in an economy?","options":[{"label":"A","text":"a decrease in government spending on education"},{"label":"B","text":"a decrease in regulation on firms"},{"label":"C","text":"an increase in emigration"},{"label":"D","text":"an increase in taxation on firms"}],"correct":""},{"id":4,"text":"Which economic activity would be classified as macroeconomics?","options":[{"label":"A","text":"households spend less on holidays abroad"},{"label":"B","text":"income tax is increased by the government"},{"label":"C","text":"wages rise for construction workers"},{"label":"D","text":"world coffee price rises due to poor weather"}],"correct":""},{"id":5,"text":"The diagram shows the effect of a decrease in price on the demand for a product. What does the arrow on the diagram illustrate?","options":[{"label":"A","text":"contraction in demand"},{"label":"B","text":"decrease in demand"},{"label":"C","text":"extension in demand"},{"label":"D","text":"increase in demand"}],"correct":"","image":"/images/econ-mcq/92_665_252_470_452_0.jpg"},{"id":6,"text":"What is the correct formula to calculate price elasticity of supply?","options":[{"label":"A","text":"the percentage change in price divided by the change in quantity supplied"},{"label":"B","text":"the percentage change in price divided by the percentage change in quantity supplied"},{"label":"C","text":"the percentage change in quantity supplied divided by the change in price"},{"label":"D","text":"the percentage change in quantity supplied divided by the percentage change in price"}],"correct":""},{"id":7,"text":"What is the most likely cause of a product having a price elasticity of demand greater than one?","options":[{"label":"A","text":"The product has a close substitute."},{"label":"B","text":"The product is a habit-forming good."},{"label":"C","text":"The product is a necessity."},{"label":"D","text":"The product requires only a small proportion of consumer income."}],"correct":""},{"id":8,"text":"For some illnesses, wearing a face mask has a benefit as it could prevent people from getting infected. Not all people are willing to wear face masks. Based on the statement above, why would there be an inefficient allocation of face masks in the free market?","options":[{"label":"A","text":"Consumers in the free market only consider private costs and benefits."},{"label":"B","text":"Face masks are non-rival and non-excludable."},{"label":"C","text":"There is abuse of monopoly power by the producer of face masks."},{"label":"D","text":"There is perfect information in the free market."}],"correct":""},{"id":9,"text":"What would bring about a movement upwards along the supply curve for rice?","options":[{"label":"A","text":"a decrease in the productivity of farmworkers"},{"label":"B","text":"a decrease in the profitability of rice production"},{"label":"C","text":"an increase in consumers' incomes"},{"label":"D","text":"an increase in farmworkers' wages"}],"correct":""},{"id":10,"text":"A government decides to reduce air pollution in city centres by giving financial assistance to bus companies, reducing their costs of production and prices for passengers. Which type of policy measure is this?","options":[{"label":"A","text":"a maximum price"},{"label":"B","text":"a minimum price"},{"label":"C","text":"a subsidy"},{"label":"D","text":"regulation"}],"correct":""},{"id":11,"text":"What would be least likely to act as a store of value during a period of rapid inflation?","options":[{"label":"A","text":"cash"},{"label":"B","text":"gold"},{"label":"C","text":"property"},{"label":"D","text":"shares"}],"correct":""},{"id":12,"text":"A country's central bank raised the rate of interest from 1% to 4% per year. How would this change have affected the amount saved and the cost of borrowing by individuals?","options":[{"label":"A","text":"decreased | decreased"},{"label":"B","text":"decreased | increased"},{"label":"C","text":"increased | decreased"},{"label":"D","text":"increased | increased"}],"correct":""},{"id":13,"text":"Which factor would not increase the bargaining strength of a trade union to raise wages?","options":[{"label":"A","text":"a rapidly growing economy"},{"label":"B","text":"high union membership in the industry"},{"label":"C","text":"legislation limiting strike action"},{"label":"D","text":"workers are in short supply"}],"correct":""},{"id":14,"text":"Which conditions are most likely to attract small firms to enter a market?","options":[{"label":"A","text":"local | high"},{"label":"B","text":"local | low"},{"label":"C","text":"national | high"},{"label":"D","text":"national | low"}],"correct":""},{"id":15,"text":"The table shows the units of factors of production that a firm needs to employ for two different levels of output. What is the firm experiencing?","options":[{"label":"A","text":"constant returns to scale"},{"label":"B","text":"diseconomies of scale"},{"label":"C","text":"external diseconomies of scale"},{"label":"D","text":"external economies of scale"}],"correct":"","table":"<table><tr><td>land</td><td>labour</td><td>capital</td><td>output</td></tr><tr><td>5</td><td>2</td><td>4</td><td>100</td></tr><tr><td>10</td><td>4</td><td>8</td><td>150</td></tr></table>"},{"id":16,"text":"What is an example of a government macroeconomic aim?","options":[{"label":"A","text":"a minimum of 10 years of schooling"},{"label":"B","text":"a sales tax of 10% on consumer goods"},{"label":"C","text":"a target rate of \\( 2\\% \\) inflation"},{"label":"D","text":"increasing pay for nurses"}],"correct":""},{"id":17,"text":"Government policy measures can affect economic activity in a country. Which pair of monetary policy measures would be likely to increase employment?","options":[{"label":"A","text":"depreciate foreign exchange rates and increase education spending"},{"label":"B","text":"increase money supply and reduce interest rates"},{"label":"C","text":"provide subsidies and grants and lower sales tax"},{"label":"D","text":"reduce income tax and improve infrastructure"}],"correct":""},{"id":18,"text":"What would be most likely to encourage saving?","options":[{"label":"A","text":"a rise in the exchange rate"},{"label":"B","text":"a rise in the goods and services tax rate"},{"label":"C","text":"a rise in the income tax rate"},{"label":"D","text":"a rise in the interest rate"}],"correct":""},{"id":19,"text":"The government of a country operating at full employment increases its spending on education and training. How does this affect the likelihood of achieving low inflation in the short run and the long run?","options":[{"label":"A","text":"less likely | less likely"},{"label":"B","text":"less likely | more likely"},{"label":"C","text":"more likely | less likely"},{"label":"D","text":"more likely | more likely"}],"correct":""},{"id":20,"text":"A government has introduced a tax on a necessity. Producers have passed on a large proportion of this tax to consumers in the form of higher prices. Which row is correct?","options":[{"label":"A","text":"direct | price elastic"},{"label":"B","text":"direct | price inelastic"},{"label":"C","text":"indirect | price elastic"},{"label":"D","text":"indirect | price inelastic"}],"correct":""},{"id":21,"text":"What is most likely to lead to an increase in structural unemployment in a country?","options":[{"label":"A","text":"The country is experiencing a period of negative economic growth."},{"label":"B","text":"The country is experiencing a period of positive economic growth."},{"label":"C","text":"The country is moving from producing primary sector goods to secondary sector goods."},{"label":"D","text":"The country is moving towards more flexible labour markets."}],"correct":""},{"id":22,"text":"Which citizens are most likely to benefit in a period of rapid inflation?","options":[{"label":"A","text":"citizens who are receiving fixed state benefits"},{"label":"B","text":"citizens who earn fixed incomes"},{"label":"C","text":"citizens who have lent money at a fixed rate of interest"},{"label":"D","text":"citizens who have borrowed money at a fixed rate of interest"}],"correct":""},{"id":23,"text":"Which statement is correct about the Human Development Index (HDI) and real GDP?","options":[{"label":"A","text":"HDI includes exports and imports while real GDP does not."},{"label":"B","text":"HDI includes life expectancy and years of schooling while real GDP does not."},{"label":"C","text":"HDI includes the level of output while real GDP does not."},{"label":"D","text":"HDI includes the level of unemployment in the population while real GDP does not."}],"correct":""},{"id":24,"text":"Other things being equal, what will cause a population both to increase and to age?","options":[{"label":"A","text":"a fall in the birth rate"},{"label":"B","text":"a fall in the death rate"},{"label":"C","text":"a rise in both the birth rate and the death rate"},{"label":"D","text":"a rise in the death rate and a fall in the birth rate"}],"correct":""},{"id":25,"text":"Which change would be unlikely to be found in a country as it develops?","options":[{"label":"A","text":"an increase in average incomes and a decrease in unemployment"},{"label":"B","text":"an increase in manufacturing production and an increase in shipping services"},{"label":"C","text":"an increase in subsistence farming and a decrease in financial services"},{"label":"D","text":"an increase in tourism and an increase in the export of agricultural products"}],"correct":""},{"id":26,"text":"It is cheaper for developed economies to buy some cereals from developing economies than to produce them domestically. What might reduce international trade in cereals?","options":[{"label":"A","text":"Cereals become less popular with the population of developing economies."},{"label":"B","text":"Developed economies place an embargo on cereal imports to prevent disease."},{"label":"C","text":"Governments tax cereal production in developed economies."},{"label":"D","text":"Producers of cereals in developing economies are subsidised."}],"correct":""},{"id":27,"text":"A country imposes a quota on imported cars. What is the most likely outcome of this action?","options":[{"label":"A","text":"a decrease in the domestic output of cars"},{"label":"B","text":"a decrease in the domestic price of cars"},{"label":"C","text":"an increase in the tax revenue from car imports"},{"label":"D","text":"an increase in the total revenue of domestic car producers"}],"correct":""},{"id":28,"text":"Which policy measure is most likely to reduce the current account deficit of the balance of payments of an economy?","options":[{"label":"A","text":"decrease the level of subsidies to domestic producers"},{"label":"B","text":"increase infrastructure spending to increase domestic productivity"},{"label":"C","text":"increase interest rates"},{"label":"D","text":"remove import tariffs"}],"correct":""}];

const paper_11: MCQQuestion[] = [{"id":1,"text":"What is part of the economic definition of scarcity?","options":[{"label":"A","text":"high levels of taxation"},{"label":"B","text":"low levels of investment"},{"label":"C","text":"unequal distribution of income"},{"label":"D","text":"unlimited consumer wants"}],"correct":""},{"id":2,"text":"A country’s production possibility curve (PPC) moves from \\( {\\mathrm{{PPC}}}_{1} \\) to \\( {\\mathrm{{PPC}}}_{2} \\) . What could cause this movement in the PPC?","options":[{"label":"A","text":"false | false | true"},{"label":"B","text":"false | true | false"},{"label":"C","text":"true | false | true"},{"label":"D","text":"true | true | false"}],"correct":"","image":"/images/econ-mcq/100_573_630_648_502_0.jpg"},{"id":3,"text":"A government spends \\( \\$ {100}\\mathrm{\\;m} \\) on subsidising wind farm construction instead of spending it on an increase in healthcare. Which economic concept does this spending decision illustrate?","options":[{"label":"A","text":"external cost"},{"label":"B","text":"free goods"},{"label":"C","text":"market disequilibrium"},{"label":"D","text":"opportunity cost"}],"correct":""},{"id":4,"text":"What is an example of a macroeconomic indicator?","options":[{"label":"A","text":"agricultural prices"},{"label":"B","text":"average earnings in the secondary sector"},{"label":"C","text":"real Gross Domestic Product (real GDP)"},{"label":"D","text":"total costs of German pharmaceutical firms"}],"correct":""},{"id":5,"text":"Good X is demanded in two areas, Y and Z. The table shows the amount of X demanded in these areas at different prices. What can be concluded from the table?","options":[{"label":"A","text":"Consumers in area Y are more willing and able than consumers in area Z to buy good X."},{"label":"B","text":"Consumers in area Y are richer than consumers in area Z."},{"label":"C","text":"Consumers in area Y want the good more than consumers in area Z."},{"label":"D","text":"There are more consumers living in area Y than in area Z."}],"correct":"","table":"<table><tr><td rowspan=\"2\">price of good X (US\\$)</td><td colspan=\"2\">quantity demanded per month</td></tr><tr><td>area Y</td><td>area Z</td></tr><tr><td>5</td><td>1000</td><td>200</td></tr><tr><td>10</td><td>800</td><td>150</td></tr><tr><td>15</td><td>600</td><td>100</td></tr><tr><td>20</td><td>400</td><td>50</td></tr><tr><td>25</td><td>200</td><td>0</td></tr></table>"},{"id":6,"text":"Which price elasticity of demand (PED) would cause an increase in total revenue if the price of the good increased?","options":[{"label":"A","text":"perfectly elastic"},{"label":"B","text":"relatively elastic"},{"label":"C","text":"relatively inelastic"},{"label":"D","text":"unitary elastic"}],"correct":""},{"id":7,"text":"The diagram shows the supply curve for coffee. The price of coffee increases from \\( {\\mathrm{P}}_{1} \\) to \\( {\\mathrm{P}}_{2} \\) . How would this benefit firms in the coffee industry?","options":[{"label":"A","text":"A higher price gives firms the ability to increase profits."},{"label":"B","text":"A higher price gives firms the incentive to reduce total fixed costs."},{"label":"C","text":"A higher price will encourage consumers to buy more coffee increasing total revenue."},{"label":"D","text":"A higher price will encourage less firms to enter the market to supply coffee."}],"correct":"","image":"/images/econ-mcq/102_639_251_524_448_0.jpg"},{"id":8,"text":"What might be an external benefit of an increase in the number of university graduates in an economy?","options":[{"label":"A","text":"an increase in revenue for the universities from fee-paying students"},{"label":"B","text":"an increase in tax revenue from a more productive labour force"},{"label":"C","text":"an increase in graduate employment as a percentage of the working population"},{"label":"D","text":"an increase in wages for graduates"}],"correct":""},{"id":9,"text":"The price of a good increases. What could cause this?","options":[{"label":"A","text":"The cost of raw materials falls."},{"label":"B","text":"The incomes of consumers rise."},{"label":"C","text":"The price of a complement rises."},{"label":"D","text":"The price of a substitute falls."}],"correct":""},{"id":10,"text":"Imposing a maximum price for a good is an example of which type of government policy?","options":[{"label":"A","text":"fiscal"},{"label":"B","text":"monetary"},{"label":"C","text":"regulation"},{"label":"D","text":"supply-side"}],"correct":""},{"id":11,"text":"Savers suffer as inflation rises to 4.4%. Which function of money is most involved in this statement?","options":[{"label":"A","text":"means of deferred payments"},{"label":"B","text":"medium of exchange"},{"label":"C","text":"store of value"},{"label":"D","text":"unit of account"}],"correct":""},{"id":12,"text":"One of the functions of money is to act as a measure of value. What does this mean?","options":[{"label":"A","text":"Money allows people to borrow and lend."},{"label":"B","text":"Money allows people to save their surplus income."},{"label":"C","text":"Money is used to buy goods and services."},{"label":"D","text":"Money is used to compare the worth of different goods and services."}],"correct":""},{"id":13,"text":"Which trade union activity will be beneficial for firms?","options":[{"label":"A","text":"balloting for industrial action to prevent redundancies"},{"label":"B","text":"campaigning to raise wages of trade union members"},{"label":"C","text":"instructing workers to strike over a safety dispute"},{"label":"D","text":"providing training which raises productivity of workers"}],"correct":""},{"id":14,"text":"What is not a variable cost of production?","options":[{"label":"A","text":"cost of fuel"},{"label":"B","text":"cost of raw materials"},{"label":"C","text":"extra pay for working additional hours"},{"label":"D","text":"rent of offices"}],"correct":""},{"id":15,"text":"What is a definition of a firm's revenue?","options":[{"label":"A","text":"money received from sales"},{"label":"B","text":"sales volume"},{"label":"C","text":"surplus over costs"},{"label":"D","text":"tax payments"}],"correct":""},{"id":16,"text":"What could cause internal diseconomies of scale for a firm?","options":[{"label":"A","text":"a fall in demand for the products produced by the firm"},{"label":"B","text":"a merger with another firm that results in slower decision-making"},{"label":"C","text":"spending more on research and development to create new products"},{"label":"D","text":"the lack of skilled labour in the geographical area where the firm is based"}],"correct":""},{"id":17,"text":"A government decides to leave direct taxes unchanged but to increase indirect taxes. What is this policy intended to achieve?","options":[{"label":"A","text":"to increase the value of the exchange rate"},{"label":"B","text":"to redistribute income from higher to lower income groups"},{"label":"C","text":"to reduce a budget deficit"},{"label":"D","text":"to reduce the rate of inflation"}],"correct":""},{"id":18,"text":"What is the most likely reason to increase government subsidies?","options":[{"label":"A","text":"to decrease consumption of a merit good"},{"label":"B","text":"to increase consumption of a merit good"},{"label":"C","text":"to decrease consumption of a demerit good"},{"label":"D","text":"to increase consumption of a demerit good"}],"correct":""},{"id":19,"text":"Which people are most likely to gain at a time of inflation?","options":[{"label":"A","text":"companies who sell abroad"},{"label":"B","text":"foreign tourists visiting the country"},{"label":"C","text":"those living on their savings"},{"label":"D","text":"those who are repaying borrowed money"}],"correct":""},{"id":20,"text":"The government of country Z announces an increase in spending on work-place training. What is the effect of this supply-side policy likely to be?","options":[{"label":"A","text":"a decrease in country Z's employment rate"},{"label":"B","text":"a decrease in country Z's exchange rate"},{"label":"C","text":"an increase in country Z's economic growth rate"},{"label":"D","text":"an increase in country Z's interest rate"}],"correct":""},{"id":21,"text":"The table shows real GDP in US\\$ billion for a country over a three-year period. What does the GDP data indicate for the country between year 1 and year 3?","options":[{"label":"A","text":"a reduction in the rate of inflation"},{"label":"B","text":"an increase in the rate of economic growth"},{"label":"C","text":"the existence of economic growth"},{"label":"D","text":"the existence of economic growth per capita"}],"correct":"","table":"<table><tr><td>year</td><td>real GDP US\\$ billion</td></tr><tr><td>1</td><td>205</td></tr><tr><td>2</td><td>215</td></tr><tr><td>3</td><td>219</td></tr></table>"},{"id":22,"text":"What is a likely consequence of a falling level of unemployment?","options":[{"label":"A","text":"downward pressure on wage rates"},{"label":"B","text":"increase in welfare benefit payments"},{"label":"C","text":"rise in absolute poverty"},{"label":"D","text":"rise in income tax revenue"}],"correct":""},{"id":23,"text":"The diagrams show Italy's unemployment rate and GDP per head. When do Italy's unemployment rate and GDP per head rise at the same time?","options":[{"label":"A","text":"2000-2001"},{"label":"B","text":"2007-2008"},{"label":"C","text":"2009-2010"},{"label":"D","text":"2014-2015"}],"correct":"","image":"/images/econ-mcq/106_277_251_1251_489_0.jpg"},{"id":24,"text":"During a recession, many people in a city become unemployed and their incomes fall. Some people can no longer pay the rent on their houses or buy the food they need. What is the effect of the recession in the city?","options":[{"label":"A","text":"increases | increases"},{"label":"B","text":"increases | unchanged"},{"label":"C","text":"unchanged | increases"},{"label":"D","text":"unchanged | unchanged"}],"correct":""},{"id":25,"text":"The Peruvian government set itself the target of reducing the number of its population in poverty. What change does not indicate that the Peruvian government had made progress towards this target?","options":[{"label":"A","text":"a rise in employment"},{"label":"B","text":"a rise in infant mortality"},{"label":"C","text":"a rise in life expectancy"},{"label":"D","text":"a rise in the level of adult literacy"}],"correct":""},{"id":26,"text":"What is not a reason for the decline in manufacturing industries in developed economies in recent years?","options":[{"label":"A","text":"growth of newly industrialised competitor countries"},{"label":"B","text":"invention of automated production methods"},{"label":"C","text":"rising costs of factor inputs in the steel industry"},{"label":"D","text":"considerable skill shortages as school-leavers prefer to work in the service sector"}],"correct":""},{"id":27,"text":"The table shows a country's exports and imports. What was the country's balance of trade in goods and services?","options":[{"label":"A","text":"a deficit of \\$7 million"},{"label":"B","text":"a deficit of \\$13 million"},{"label":"C","text":"a surplus of \\$7 million"},{"label":"D","text":"a surplus of \\$13 million"}],"correct":"","table":"<table><tr><td></td><td>\\$m</td></tr><tr><td>exports of goods</td><td>200</td></tr><tr><td>imports of goods</td><td>190</td></tr><tr><td>exports of services</td><td>35</td></tr><tr><td>imports of services</td><td>38</td></tr></table>"},{"id":28,"text":"Country X exports steel to country Y at a price below its cost of production. This has led to a fall in demand for steel produced in country Y. What is a method of trade protection that country Y could use to reduce the imports of steel from country X?","options":[{"label":"A","text":"apply anti-dumping tariffs"},{"label":"B","text":"increase interest rates"},{"label":"C","text":"revalue the currency"},{"label":"D","text":"subsidise the export of steel"}],"correct":""},{"id":29,"text":"What would increase the demand for a country's currency on the foreign exchange market?","options":[{"label":"A","text":"a decrease in its inward investment"},{"label":"B","text":"a decrease in its rate of interest"},{"label":"C","text":"an increase in its exports"},{"label":"D","text":"an increase in its imports"}],"correct":""},{"id":30,"text":"Country X has a persistent deficit on the current account of the balance payments. Which policy measure is most likely to improve this situation?","options":[{"label":"A","text":"lowering import quotas"},{"label":"B","text":"lowering income tax"},{"label":"C","text":"lowering import tariffs"},{"label":"D","text":"lowering export subsidies"}],"correct":""}];

const paper_12: MCQQuestion[] = [{"id":1,"text":"GDP per capita in Switzerland is high. What is the reason why Swiss citizens still face the basic economic problem?","options":[{"label":"A","text":"Income in Switzerland is unevenly distributed."},{"label":"B","text":"Inflation in Switzerland is high."},{"label":"C","text":"Swiss citizens expect high living standards."},{"label":"D","text":"Swiss citizens have to make choices in consumption."}],"correct":""},{"id":2,"text":"The production possibility curve of a country has shifted from \\( {\\mathrm{{PPC}}}_{1} \\) to \\( {\\mathrm{{PPC}}}_{2} \\) . What could have caused this shift?","options":[{"label":"A","text":"a decrease in the rate of unemployment"},{"label":"B","text":"a fall in the birth rate"},{"label":"C","text":"improved education"},{"label":"D","text":"outdated technology not being replaced"}],"correct":"","image":"/images/econ-mcq/109_594_707_610_524_0.jpg"},{"id":3,"text":"What is most likely to increase the geographical mobility of labour?","options":[{"label":"A","text":"an increase in the amount of credit available to firms"},{"label":"B","text":"an increase in the quantity of low-cost housing"},{"label":"C","text":"an increase in spending by firms on research and development"},{"label":"D","text":"an increase in spending by government on apprenticeships and training"}],"correct":""},{"id":4,"text":"What is not a microeconomic decision?","options":[{"label":"A","text":"A firm decides to increase the price of its product."},{"label":"B","text":"A government decides to increase interest rates."},{"label":"C","text":"A household decides to reduce its demand for fuel."},{"label":"D","text":"A trade union decides to go on strike."}],"correct":""},{"id":5,"text":"What is a feature of a market in equilibrium?","options":[{"label":"A","text":"demand exceeds supply"},{"label":"B","text":"no profits are earned"},{"label":"C","text":"the market will clear"},{"label":"D","text":"there will be a surplus of products"}],"correct":""},{"id":6,"text":"The diagram shows the supply curve for a good. What is the name and cause of the movement from X to Y?","options":[{"label":"A","text":"a contraction of supply caused by a decrease in demand"},{"label":"B","text":"a contraction of supply caused by an increase in demand"},{"label":"C","text":"an extension of supply caused by a decrease in demand"},{"label":"D","text":"an extension of supply caused by an increase in demand"}],"correct":"","image":"/images/econ-mcq/110_552_1011_695_466_0.jpg"},{"id":7,"text":"In a given year, the world output of coal was 3.94 billion metric tonnes at an average yearly price of \\$252 per metric tonne. Several years later, world output was 3.66 billion metric tonnes at an average yearly price of \\$120 per metric tonne. What might have caused such a fall in the price of coal?","options":[{"label":"A","text":"almost half the world's coal reserves were in just two countries"},{"label":"B","text":"the exhaustion of coal seams throughout the world"},{"label":"C","text":"the switch to renewable sources of energy"},{"label":"D","text":"the use of coal as a raw material as well as a fuel"}],"correct":""},{"id":8,"text":"A government believes that people eat too much sugar but not enough fruit. Which combination of policies would the government introduce?","options":[{"label":"A","text":"increase its tax | increase its tax"},{"label":"B","text":"increase its tax | subsidise its production"},{"label":"C","text":"subsidise its production | increase its tax"},{"label":"D","text":"subsidise its production | subsidise its production"}],"correct":""},{"id":9,"text":"Which row shows a characteristic of money and a function of money?","options":[{"label":"A","text":"acceptability | medium of exchange"},{"label":"B","text":"cash | measure of value"},{"label":"C","text":"divisibility | portability"},{"label":"D","text":"store of value | bank deposit"}],"correct":""},{"id":10,"text":"When will a central bank act as lender of last resort to a commercial bank?","options":[{"label":"A","text":"when a commercial bank faces a liquidity crisis"},{"label":"B","text":"when a commercial bank fails to make a profit"},{"label":"C","text":"when a commercial bank needs to raise share capital"},{"label":"D","text":"when a commercial bank reduces its lending rates"}],"correct":""},{"id":11,"text":"What is likely to increase the bargaining power of a trade union?","options":[{"label":"A","text":"when the economy is experiencing rising cyclical unemployment"},{"label":"B","text":"when the labour market moves from long-term to short-term contracts of employment"},{"label":"C","text":"when the price elasticity of demand for the product is price-elastic"},{"label":"D","text":"when the trade union supplies all the labour required by the employer"}],"correct":""},{"id":12,"text":"What is a likely reason why firms do not grow in size?","options":[{"label":"A","text":"External diseconomies of scale occur at high levels of output."},{"label":"B","text":"Internal economies of scale occur at high levels of output."},{"label":"C","text":"Internal economies of scale occur at low levels of output."},{"label":"D","text":"Internal diseconomies of scale occur at low levels of output."}],"correct":""},{"id":13,"text":"What is a reason why firms making similar products sometimes locate near each other?","options":[{"label":"A","text":"Competition is decreased."},{"label":"B","text":"There are external economies of scale."},{"label":"C","text":"There are internal economies of scale."},{"label":"D","text":"Transport costs may be eliminated."}],"correct":""},{"id":14,"text":"A government wishes to increase its spending on public goods. Which sector should have a spending increase to achieve this?","options":[{"label":"A","text":"education"},{"label":"B","text":"healthcare"},{"label":"C","text":"national defence"},{"label":"D","text":"railways"}],"correct":""},{"id":15,"text":"Which government measure would lead directly to more exports of goods?","options":[{"label":"A","text":"a devaluation of the currency"},{"label":"B","text":"a restriction of bank credit creation"},{"label":"C","text":"an increase in the rate of interest"},{"label":"D","text":"the issue of more bank notes and coins"}],"correct":""},{"id":16,"text":"A government wishes to stimulate economic recovery. Which action will assist this?","options":[{"label":"A","text":"decreasing government investment"},{"label":"B","text":"decreasing income tax"},{"label":"C","text":"increasing indirect taxation"},{"label":"D","text":"increasing interest rates"}],"correct":""},{"id":17,"text":"What is the most likely effect on an economy of a successful supply-side policy?","options":[{"label":"A","text":"an increase in the general price level"},{"label":"B","text":"an increase in the interest rate"},{"label":"C","text":"an increase in the money supply"},{"label":"D","text":"an increase in the potential GDP"}],"correct":""},{"id":18,"text":"A country is experiencing high economic growth caused by an increase in consumer spending. What are the most likely effects on inflation and unemployment?","options":[{"label":"A","text":"inflation falls and unemployment falls"},{"label":"B","text":"inflation falls and unemployment rises"},{"label":"C","text":"inflation rises and unemployment falls"},{"label":"D","text":"inflation rises and unemployment rises"}],"correct":""},{"id":19,"text":"Which pair is most likely to be provided by the private sector in a mixed economy?","options":[{"label":"A","text":"courts and prisons"},{"label":"B","text":"hospitals and tax collection"},{"label":"C","text":"insurance and banks"},{"label":"D","text":"weapon manufacture and defence"}],"correct":""},{"id":20,"text":"An economy is experiencing a sustained fall in the general price level. Which term is used to describe this?","options":[{"label":"A","text":"deflation"},{"label":"B","text":"depreciation"},{"label":"C","text":"market disequilibrium"},{"label":"D","text":"recession"}],"correct":""},{"id":21,"text":"What is most likely to cause an increase in relative poverty?","options":[{"label":"A","text":"an increase in state benefits"},{"label":"B","text":"an increase in the national minimum wage"},{"label":"C","text":"pension increases below the rate of inflation"},{"label":"D","text":"people working beyond retirement age"}],"correct":""},{"id":22,"text":"What might explain the high population growth in some developing countries?","options":[{"label":"A","text":"high birth rates and falling death rates"},{"label":"B","text":"low immigration and high emigration"},{"label":"C","text":"falling birth rates and rising death rates"},{"label":"D","text":"falling life expectancy"}],"correct":""},{"id":23,"text":"Which combination of factors might cause a country to be classified as developing rather than developed?","options":[{"label":"A","text":"a government budget deficit and a low death rate"},{"label":"B","text":"a high birth rate and a low death rate"},{"label":"C","text":"a large population and a current account deficit"},{"label":"D","text":"a poor education system and a low standard of living"}],"correct":""},{"id":24,"text":"What is certain to encourage a higher level of international trade?","options":[{"label":"A","text":"conservation of resources and unstable exchange rates"},{"label":"B","text":"exploitation of resources and wider use of quotas"},{"label":"C","text":"increased support for home industries and increased tariffs"},{"label":"D","text":"more specialisation and falling transport costs"}],"correct":""},{"id":25,"text":"The import of a product from another country has been banned. Which term describes this method of protection?","options":[{"label":"A","text":"embargo"},{"label":"B","text":"exchange control"},{"label":"C","text":"quota"},{"label":"D","text":"tariff"}],"correct":""},{"id":26,"text":"A developing country's two major sources of income from international trade are fishing and tourism. If the country's exchange rate depreciated, what is likely to happen?","options":[{"label":"A","text":"Imported goods would become cheaper for local people."},{"label":"B","text":"The country would definitely become poorer."},{"label":"C","text":"The price of fish sold as exports would become cheaper."},{"label":"D","text":"Tourists to the country would be discouraged by higher prices."}],"correct":""},{"id":27,"text":"What is the correct formula for calculating the current account of the balance of payments?","options":[{"label":"A","text":"balance of trade in goods + balance of trade in services + primary income balance + secondary income balance"},{"label":"B","text":"government revenue from abroad - domestic government spending"},{"label":"C","text":"percentage change in quantity demanded of exports"},{"label":"D","text":"percentage change in price of imports"}],"correct":""}];

const paper_13: MCQQuestion[] = [{"id":1,"text":"What is a free good?","options":[{"label":"A","text":"free samples of a new product"},{"label":"B","text":"health services provided by the state"},{"label":"C","text":"second-hand clothing"},{"label":"D","text":"sunlight"}],"correct":""},{"id":2,"text":"The diagram shows a production possibility curve (PPC) for an economy. What is the reason for the economy moving from point M to point N?","options":[{"label":"A","text":"decreased unemployment in industries producing good X"},{"label":"B","text":"improvement in technology used to produce good X"},{"label":"C","text":"increased productivity of workers producing good X"},{"label":"D","text":"increased resource allocation to the production of good X"}],"correct":"","image":"/images/econ-mcq/118_669_902_461_385_0.jpg"},{"id":3,"text":"What is not held constant when drawing a demand curve for a good or service?","options":[{"label":"A","text":"consumers' incomes"},{"label":"B","text":"tastes and preferences"},{"label":"C","text":"the price of substitutes"},{"label":"D","text":"the price of the good or service"}],"correct":""},{"id":4,"text":"The diagram shows a shift in the supply curve for New Zealand’s airlines from \\( {\\mathrm{S}}_{1} \\) to \\( {\\mathrm{S}}_{2} \\) . What is the most likely cause of this shift?","options":[{"label":"A","text":"a decrease in the costs of New Zealand's airlines"},{"label":"B","text":"a decrease in the number of people wanting to fly to New Zealand"},{"label":"C","text":"an increase in the price of train and bus travel in New Zealand"},{"label":"D","text":"an increase in the tax on air travel in New Zealand"}],"correct":"","image":"/images/econ-mcq/119_647_252_502_398_0.jpg"},{"id":5,"text":"What could cause the price of tea to increase?","options":[{"label":"A","text":"decrease in the demand for tea"},{"label":"B","text":"decrease in the price of a substitute good"},{"label":"C","text":"increase in the price of a substitute good"},{"label":"D","text":"increase in the supply of tea"}],"correct":""},{"id":6,"text":"A firm changes the price of its product and finds that its revenue increases. Which combination of price change and price elasticity of demand would have caused this?","options":[{"label":"A","text":"falls | between 0 and 1"},{"label":"B","text":"falls | equal to 1"},{"label":"C","text":"rises | between 0 and 1"},{"label":"D","text":"rises | greater than 1"}],"correct":""},{"id":7,"text":"What could not occur in a market economic system?","options":[{"label":"A","text":"a monopolist supplying specialist goods to the market"},{"label":"B","text":"excessive pollution created by power stations"},{"label":"C","text":"governments setting minimum wages to relieve poverty"},{"label":"D","text":"private ownership of firms making defence equipment"}],"correct":""},{"id":8,"text":"What is a correct definition of a demerit good?","options":[{"label":"A","text":"a good which generates external benefits"},{"label":"B","text":"a good with higher private costs than social costs"},{"label":"C","text":"a good which is more harmful to consumers than they realise"},{"label":"D","text":"a good which provides no costs to third parties"}],"correct":""},{"id":9,"text":"Within the same firm, one employee is paid a higher wage than another employee. Which reason for the difference in their wage could be considered discrimination?","options":[{"label":"A","text":"They are of different ages."},{"label":"B","text":"They have different levels of education."},{"label":"C","text":"They have different levels of productivity."},{"label":"D","text":"They have different levels of work experience."}],"correct":""},{"id":10,"text":"A farmer introduces machinery to help workers at harvest time. The farmer also reduces the number of workers by 50%. As a result, the total harvest increases by 25%. What has happened?","options":[{"label":"A","text":"Labour productivity has decreased and production has decreased."},{"label":"B","text":"Labour productivity has decreased and production has increased."},{"label":"C","text":"Labour productivity has increased and production has decreased."},{"label":"D","text":"Labour productivity has increased and production has increased."}],"correct":""},{"id":11,"text":"A firm has fixed costs of \\$20 and the following total variable costs. What happens to average total cost over this output range?","options":[{"label":"A","text":"It falls continuously."},{"label":"B","text":"It falls then rises."},{"label":"C","text":"It rises continuously."},{"label":"D","text":"It rises then falls."}],"correct":"","table":"<table><tr><td>output</td><td>10</td><td>20</td><td>30</td><td>40</td></tr><tr><td>total variable costs (\\$)</td><td>40</td><td>60</td><td>80</td><td>100</td></tr></table>"},{"id":12,"text":"A clothing manufacturer expands by taking over a clothing retailer. Which type of merger is this?","options":[{"label":"A","text":"backward vertical"},{"label":"B","text":"conglomerate"},{"label":"C","text":"forward vertical"},{"label":"D","text":"horizontal"}],"correct":""},{"id":13,"text":"What is likely to happen if a previously competitive market becomes a monopoly?","options":[{"label":"A","text":"decrease | decrease | increases"},{"label":"B","text":"decrease | increase | decreases"},{"label":"C","text":"increase | decrease | decreases"},{"label":"D","text":"increase | increase | increases"}],"correct":""},{"id":14,"text":"Which macroeconomic aim, if achieved, is most likely to increase a government budget surplus?","options":[{"label":"A","text":"full employment"},{"label":"B","text":"income redistribution"},{"label":"C","text":"low inflation"},{"label":"D","text":"balance of payments stability"}],"correct":""},{"id":15,"text":"The table shows the income tax rate paid by workers at different levels of income in selected years for a developed economy. What is most likely to have been the economic objective of the government in changing the tax rates between year 1 and year 2?","options":[{"label":"A","text":"to reduce a current account deficit"},{"label":"B","text":"to reduce income inequality"},{"label":"C","text":"to reduce inflation"},{"label":"D","text":"to reduce structural unemployment"}],"correct":"","table":"<table><tr><td>income band (\\$)</td><td>tax rate year 1 (%)</td><td>tax rate year 2 (%)</td></tr><tr><td>0 to 4999</td><td>0</td><td>0</td></tr><tr><td>5000 to 9999</td><td>10</td><td>0</td></tr><tr><td>10000 to 19999</td><td>20</td><td>10</td></tr><tr><td>20000 to 29999</td><td>30</td><td>30</td></tr><tr><td>30000 to 49999</td><td>40</td><td>50</td></tr><tr><td>50000+</td><td>40</td><td>60</td></tr></table>"},{"id":16,"text":"A government attempts to raise economic growth with a policy of reduced interest rates. Which other government objective is most likely to be helped in the short run?","options":[{"label":"A","text":"lower unemployment"},{"label":"B","text":"price stability"},{"label":"C","text":"reduced income inequality"},{"label":"D","text":"reduced trade deficit"}],"correct":""},{"id":17,"text":"What is the definition of a supply-side policy?","options":[{"label":"A","text":"any policy designed to decrease inflation"},{"label":"B","text":"any policy designed to decrease unemployment"},{"label":"C","text":"any policy designed to increase imports"},{"label":"D","text":"any policy designed to increase productivity"}],"correct":""},{"id":18,"text":"Subsistence farming is the practice of growing crops and raising livestock sufficient only for one's own use without any surplus for trade. Why is it difficult for a government to measure economic growth in an economy based on subsistence farming?","options":[{"label":"A","text":"Farmers' families consume most of their own produce."},{"label":"B","text":"Farmers have low rates of saving."},{"label":"C","text":"The size of harvest is dependent on the weather."},{"label":"D","text":"The surplus produce is sold to the government."}],"correct":""},{"id":19,"text":"What is necessary for a worker to be classified as unemployed?","options":[{"label":"A","text":"yes | no | no"},{"label":"B","text":"yes | no | yes"},{"label":"C","text":"yes | yes | no"},{"label":"D","text":"yes | yes | yes"}],"correct":""},{"id":20,"text":"What is most likely to increase when the rate of inflation gradually changes from 2% to 8% in one year?","options":[{"label":"A","text":"the cost of updating existing price lists"},{"label":"B","text":"the level of business confidence"},{"label":"C","text":"the real income of fixed-income earners"},{"label":"D","text":"the real value of consumer debt"}],"correct":""},{"id":21,"text":"The introduction of a minimum hourly wage in an industry aims to reduce poverty among low-paid workers. What is an advantage to workers of an effective national minimum wage?","options":[{"label":"A","text":"All workers get paid according to their level of productivity."},{"label":"B","text":"Firms may look to increase capital equipment rather than labour."},{"label":"C","text":"Levels of employment become more dependent on wage differences."},{"label":"D","text":"Redistribution of a firm's income rewards labour rather than owners."}],"correct":""},{"id":22,"text":"The chart shows the population pyramid for a country. What is most likely to cause the population pyramid to be shaped in this way?","options":[{"label":"A","text":"low | low"},{"label":"B","text":"low | high"},{"label":"C","text":"high | low"},{"label":"D","text":"high | high"}],"correct":"","image":"/images/econ-mcq/125_556_253_691_552_0.jpg"},{"id":23,"text":"The table shows information on four countries. Which country is likely to be the most developed?","options":[{"label":"A","text":"100 | 800 | 51"},{"label":"B","text":"200 | 6000 | 62"},{"label":"C","text":"300 | 600 | 48"},{"label":"D","text":"1000 | 1600 | 63"}],"correct":""},{"id":24,"text":"What is an advantage to a firm of specialisation at a national level?","options":[{"label":"A","text":"dependency on supplies from other countries"},{"label":"B","text":"greater competition from overseas firms"},{"label":"C","text":"greater depletion of the country's natural resources"},{"label":"D","text":"lower average costs due to economies of scale"}],"correct":""},{"id":25,"text":"What is an intended outcome of protecting infant industries from free trade?","options":[{"label":"A","text":"to decrease the competitiveness of domestic firms"},{"label":"B","text":"to decrease the demand for exported goods"},{"label":"C","text":"to increase employment in domestic firms"},{"label":"D","text":"to increase the supply of imported goods"}],"correct":""},{"id":26,"text":"In the diagram, curves \\( {D}_{1} \\) and \\( {S}_{1} \\) relate to the demand and supply of the US dollar (\\$) against the Chinese yuan. What is most likely to cause the demand curve for US dollars to shift from \\( {D}_{1} \\) to \\( {D}_{2} \\) ?","options":[{"label":"A","text":"a fall in Chinese interest rates"},{"label":"B","text":"a fall in US interest rates"},{"label":"C","text":"a faster growth rate in the US economy"},{"label":"D","text":"a reduction in the US government budget deficit"}],"correct":"","image":"/images/econ-mcq/126_563_1006_673_496_0.jpg"},{"id":27,"text":"Brazil had a balance of payments current account deficit of US\\$23.5 billion. Which policy is most likely to reduce the current account deficit in Brazil?","options":[{"label":"A","text":"depreciate Brazil's currency"},{"label":"B","text":"reduce rates of income tax in Brazil"},{"label":"C","text":"reduce subsidies to Brazil's exporting firms"},{"label":"D","text":"reduce tariffs on Brazil's imports"}],"correct":""}];

const paper_14: MCQQuestion[] = [{"id":1,"text":"Why will scarcity always exist?","options":[{"label":"A","text":"There are high costs of production."},{"label":"B","text":"There are low levels of education."},{"label":"C","text":"There are unlimited resources."},{"label":"D","text":"There are unlimited wants."}],"correct":""},{"id":2,"text":"What is not a macroeconomic topic?","options":[{"label":"A","text":"the growth in Chinese Gross Domestic Product"},{"label":"B","text":"the level of Consumer Prices Index inflation in the UK"},{"label":"C","text":"the level of unemployment in Spain"},{"label":"D","text":"the total output of the German car industry"}],"correct":""},{"id":3,"text":"What is likely to cause an extension in demand for a firm's fruit drink?","options":[{"label":"A","text":"a period of hot weather"},{"label":"B","text":"a reduction in the cost of producing the drink"},{"label":"C","text":"a rival firm leaving the market"},{"label":"D","text":"a successful advertising campaign by the firm"}],"correct":""},{"id":4,"text":"Supermarkets sell petrol (gas) outside their stores. They reduce the price of petrol below other suppliers to attract more customers to buy goods in the store when they buy more petrol. If this were successful, how might it be shown on demand and supply diagrams?","options":[{"label":"A","text":"shift of the demand curve to the left | shift of the supply curve to the left"},{"label":"B","text":"shift of the demand curve to the right | shift of the demand curve to the left"},{"label":"C","text":"shift of the supply curve to the left | shift of the supply curve to the right"},{"label":"D","text":"shift of the supply curve to the right | shift of the demand curve to the right"}],"correct":""},{"id":5,"text":"Which statement describes a market in disequilibrium?","options":[{"label":"A","text":"Excess demand results from a government maximum price below the equilibrium price."},{"label":"B","text":"The point where the demand and supply curves cross."},{"label":"C","text":"Price changes cause further changes in both demand and supply."},{"label":"D","text":"The quantity demanded by consumers equals the quantity supplied by producers."}],"correct":""},{"id":6,"text":"Which government measure is most likely to cause a fall both in price and in quantity traded?","options":[{"label":"A","text":"indirect tax"},{"label":"B","text":"maximum price"},{"label":"C","text":"minimum price"},{"label":"D","text":"subsidy"}],"correct":""},{"id":7,"text":"The diagrams show the wage rates of cleaners (OWc) and nurses (OWn). What is the result if a national minimum wage of OM is introduced?","options":[{"label":"A","text":"fall | rise"},{"label":"B","text":"no change | fall"},{"label":"C","text":"rise | fall"},{"label":"D","text":"rise | no change"}],"correct":"","image":"/images/econ-mcq/130_285_633_1224_378_0.jpg"},{"id":8,"text":"What would cause a decrease in spending by households in a country?","options":[{"label":"A","text":"a reduction in disposable income"},{"label":"B","text":"a reduction in the rate of sales tax"},{"label":"C","text":"lower interest rates"},{"label":"D","text":"lower savings"}],"correct":""},{"id":9,"text":"Which combination shows the advantages of a small firm over a larger firm?","options":[{"label":"A","text":"no | no | yes"},{"label":"B","text":"no | yes | no"},{"label":"C","text":"yes | yes | no"},{"label":"D","text":"yes | yes | yes"}],"correct":""},{"id":10,"text":"What is a variable cost for a firm?","options":[{"label":"A","text":"the cost of raw materials"},{"label":"B","text":"the interest payment on existing loans"},{"label":"C","text":"the rent on the factory"},{"label":"D","text":"the insurance on the factory buildings"}],"correct":""},{"id":11,"text":"The table shows the daily average revenue and units of output sold for a firm producing bicycles over a five day period. What can be concluded from the table?","options":[{"label":"A","text":"The firm's highest total revenue occurs at 2 units of output sold."},{"label":"B","text":"The firm's highest total revenue occurs at 14 units of output sold."},{"label":"C","text":"The firm's prices are always greater than total revenue."},{"label":"D","text":"The firm's total revenue always increases as output rises."}],"correct":"","table":"<table><tr><td>day</td><td>average revenue (\\$)</td><td>units of output sold</td></tr><tr><td>1</td><td>200</td><td>2</td></tr><tr><td>2</td><td>160</td><td>4</td></tr><tr><td>3</td><td>120</td><td>8</td></tr><tr><td>4</td><td>80</td><td>14</td></tr><tr><td>5</td><td>40</td><td>16</td></tr></table>"},{"id":12,"text":"Which function of money acts as a measure of value?","options":[{"label":"A","text":"a medium of exchange"},{"label":"B","text":"a standard of deferred payment"},{"label":"C","text":"a store of wealth"},{"label":"D","text":"a unit of account"}],"correct":""},{"id":13,"text":"What are the features of a highly competitive market when compared with a monopoly market?","options":[{"label":"A","text":"higher | higher"},{"label":"B","text":"higher | lower"},{"label":"C","text":"lower | higher"},{"label":"D","text":"lower | lower"}],"correct":""},{"id":14,"text":"What is not a role of central government in a mixed economy?","options":[{"label":"A","text":"providing demerit goods"},{"label":"B","text":"providing merit goods"},{"label":"C","text":"providing public goods"},{"label":"D","text":"stabilising the economy"}],"correct":""},{"id":15,"text":"A government wishes to prevent deflation. Which combination of policies would be the most effective in achieving this aim?","options":[{"label":"A","text":"increase | increase"},{"label":"B","text":"increase | reduce"},{"label":"C","text":"reduce | increase"},{"label":"D","text":"reduce | reduce"}],"correct":""},{"id":16,"text":"Which statement about supply-side policy is correct?","options":[{"label":"A","text":"It aims to increase the productive potential of the economy."},{"label":"B","text":"It aims to increase total demand in the economy."},{"label":"C","text":"It involves changes in the equilibrium foreign exchange rate."},{"label":"D","text":"It involves changes in the rate of interest."}],"correct":""},{"id":17,"text":"Which change is most likely to cause faster economic growth in the short run?","options":[{"label":"A","text":"an increase in net emigration"},{"label":"B","text":"an increase in the birth rate"},{"label":"C","text":"an increase in the death rate"},{"label":"D","text":"an increase in the retirement age"}],"correct":""},{"id":18,"text":"How is the pattern of employment likely to change when a country becomes more developed?","options":[{"label":"A","text":"from rural employment to urban employment"},{"label":"B","text":"from skilled employment to primary employment"},{"label":"C","text":"from technical employment to manual employment"},{"label":"D","text":"from tertiary employment to secondary employment"}],"correct":""},{"id":19,"text":"Which item is least likely to be included in the Consumer Prices Index (CPI)?","options":[{"label":"A","text":"domestic cooking oil"},{"label":"B","text":"homemade clothes"},{"label":"C","text":"milk"},{"label":"D","text":"personal mobile phones"}],"correct":""},{"id":20,"text":"The table shows statistics for four countries A, B, C and D. According to the data provided, which country has the lowest standard of living?","options":[{"label":"A","text":"6 | 45 | 200"},{"label":"B","text":"7 | 47 | 200"},{"label":"C","text":"9 | 60 | 220"},{"label":"D","text":"12 | 59 | 1500"}],"correct":""},{"id":21,"text":"Economic development in country X has progressed at a greater rate than in country Y. What is the most likely explanation of this difference in economic development between country X and country Y?","options":[{"label":"A","text":"Country X has a higher level of spending on education than country Y."},{"label":"B","text":"Country X has a higher level of unemployment than country Y."},{"label":"C","text":"Country Y has a higher level of investment spending than country X."},{"label":"D","text":"Country Y has a higher level of spending on healthcare than country X."}],"correct":""},{"id":22,"text":"A rise in which factor would cause an increase in the population growth rate of a country?","options":[{"label":"A","text":"birth rate"},{"label":"B","text":"death rate"},{"label":"C","text":"infant mortality rate"},{"label":"D","text":"net emigration"}],"correct":""},{"id":23,"text":"The diagram shows the market for the Chinese yuan (*) priced in US dollars (\\$). What could have caused the change in demand for the yuan from \\( {D}_{1} \\) to \\( {D}_{2} \\) ?","options":[{"label":"A","text":"a decrease in foreign direct investment in China"},{"label":"B","text":"a decrease in the level of tariffs levied by China on imports"},{"label":"C","text":"an increase in the buying of yuan by central banks"},{"label":"D","text":"an increase in the Chinese rate of interest"}],"correct":"","image":"/images/econ-mcq/135_566_1234_664_437_0.jpg"},{"id":24,"text":"The table shows the average exchange rate of the UK pound (£) to the US dollar (\\$), that is the amount of \\$ that can be bought with £1. What is a likely effect of this change on the UK economy?","options":[{"label":"A","text":"decreased cost-push inflation"},{"label":"B","text":"decreased current account deficit"},{"label":"C","text":"increased quantity of imports"},{"label":"D","text":"increased trade deficit"}],"correct":"","table":"<table><tr><td>year</td><td>exchange rate UK£/US\\$</td></tr><tr><td>1</td><td>1.64</td></tr><tr><td>2</td><td>1.52</td></tr><tr><td>3</td><td>1.35</td></tr><tr><td>4</td><td>1.25</td></tr></table>"},{"id":25,"text":"The table shows components of Japan's current account balance in trillion yen (*) for 2 years. Which balance improved between year 1 and year 2?","options":[{"label":"A","text":"balance of goods"},{"label":"B","text":"balance of primary income"},{"label":"C","text":"balance of secondary income"},{"label":"D","text":"balance of services"}],"correct":"","table":"<table><tr><td>year</td><td>balance of goods ￥ trillion</td><td>balance of services ￥ trillion</td><td>balance of primary income <br> ￥ trillion</td><td>balance of secondary income <br> ￥ trillion</td></tr><tr><td>1</td><td>-1.61</td><td>-1.76</td><td>14.04</td><td>-1.11</td></tr><tr><td>2</td><td>-5.23</td><td>-2.33</td><td>13.55</td><td>-1.02</td></tr></table>"}];

const paper_15: MCQQuestion[] = [{"id":1,"text":"How can the economic problem be described?","options":[{"label":"A","text":"as insufficient capital to satisfy our wants"},{"label":"B","text":"as insufficient income to satisfy all our needs"},{"label":"C","text":"as insufficient resources to satisfy our unlimited wants"},{"label":"D","text":"as insufficient wealth to satisfy all our needs"}],"correct":""},{"id":2,"text":"What would be included in the factor of production land?","options":[{"label":"A","text":"bread"},{"label":"B","text":"factory building"},{"label":"C","text":"sports arena"},{"label":"D","text":"wheat"}],"correct":""},{"id":3,"text":"What three key questions determine resource allocation?","options":[{"label":"A","text":"what, how, for whom"},{"label":"B","text":"what, when, for whom"},{"label":"C","text":"where, what, how"},{"label":"D","text":"where, how, for whom"}],"correct":""},{"id":4,"text":"An explosion in an important oil pipeline causes the world price of a barrel of oil to increase from \\$50 to \\$100. Before the explosion, the world demand for oil was 100 million barrels per day. The world price elasticity of demand for oil is -0.2 . What is the new global demand for oil (barrels per day) as a result of the explosion?","options":[{"label":"A","text":"20 million"},{"label":"B","text":"80 million"},{"label":"C","text":"90 million"},{"label":"D","text":"120 million"}],"correct":""},{"id":5,"text":"What is included in the study of microeconomics?","options":[{"label":"A","text":"demand-pull inflation"},{"label":"B","text":"diseconomies of scale"},{"label":"C","text":"increasing unemployment"},{"label":"D","text":"the size of the budget deficit"}],"correct":""},{"id":6,"text":"The price elasticity of supply (PES) of a product is 1.0. The price of this product is \\$10 and the quantity supplied is 200 units. If the price of the product increases to \\$11, by how many units will the quantity supplied increase?","options":[{"label":"A","text":"1 unit"},{"label":"B","text":"10 units"},{"label":"C","text":"20 units"},{"label":"D","text":"200 units"}],"correct":""},{"id":7,"text":"The government wishes to reduce the harmful emissions from road transport. Which measure would be effective in helping to achieve this aim?","options":[{"label":"A","text":"increased expenditure on oil exploration"},{"label":"B","text":"introducing a subsidy on public transport"},{"label":"C","text":"reduced taxation on the production of private vehicles"},{"label":"D","text":"reducing incentives to purchase electric vehicles"}],"correct":""},{"id":8,"text":"What function does a central bank provide for an economy?","options":[{"label":"A","text":"It issues bank notes to encourage spending."},{"label":"B","text":"It manages the debt of private sector firms."},{"label":"C","text":"It offers high interest rate accounts to encourage savings."},{"label":"D","text":"It provides mortgages to encourage home ownership."}],"correct":""},{"id":9,"text":"A firm changes from producing individual pieces of wooden furniture by hand to a mechanised production process using the division of labour. What is the most likely set of outcomes as a result?","options":[{"label":"A","text":"worker motivation will increase | average total cost will increase | total costs will increase"},{"label":"B","text":"worker motivation will decrease | average total cost will increase | total costs will increase"},{"label":"C","text":"worker motivation will decrease | average total cost will decrease | total costs will increase"},{"label":"D","text":"worker motivation will decrease | average total cost will decrease | total costs will decrease"}],"correct":""},{"id":10,"text":"What is the best definition of a trade union?","options":[{"label":"A","text":"a group of countries that negotiates trade agreements"},{"label":"B","text":"a group of firms that negotiates removing obstacles to trade"},{"label":"C","text":"a group of workers that negotiates collectively on pay"},{"label":"D","text":"a group of workers that negotiates fixing prices"}],"correct":""},{"id":11,"text":"What is most likely to be a disadvantage when operating a small firm?","options":[{"label":"A","text":"a lack of external economies of scale"},{"label":"B","text":"a lack of external diseconomies of scale"},{"label":"C","text":"a lack of internal economies of scale"},{"label":"D","text":"a lack of internal diseconomies of scale"}],"correct":""},{"id":12,"text":"A busy restaurant employs a large number of highly skilled chefs to individually prepare high quality meals. What is an advantage to the restaurant of this type of production?","options":[{"label":"A","text":"A highly skilled chef is paid more than an unskilled cook."},{"label":"B","text":"It is easier to prepare a wide variety of meals."},{"label":"C","text":"It takes time to train a highly skilled chef."},{"label":"D","text":"The quality of a meal varies according to which chef prepares it."}],"correct":""},{"id":13,"text":"How is the average cost of a product calculated?","options":[{"label":"A","text":"by adding total variable and total fixed costs"},{"label":"B","text":"by dividing total cost by output"},{"label":"C","text":"by multiplying total variable cost by output"},{"label":"D","text":"by subtracting fixed cost from total cost"}],"correct":""},{"id":14,"text":"Why might measures to reduce unemployment also make inflation rise?","options":[{"label":"A","text":"They encourage cheap imports."},{"label":"B","text":"They increase demand."},{"label":"C","text":"They reduce firms' costs."},{"label":"D","text":"They require wages to fall."}],"correct":""},{"id":15,"text":"The diagram shows selected areas of government spending for a country. What was the total government spending on merit goods?","options":[{"label":"A","text":"\\$32.2 billion"},{"label":"B","text":"\\$81.8 billion"},{"label":"C","text":"\\$118.2 billion"},{"label":"D","text":"\\$261.9 billion"}],"correct":"","image":"/images/econ-mcq/142_358_245_1068_383_0.jpg"},{"id":16,"text":"What correctly explains the effect of monetary policy measures on macroeconomic aims?","options":[{"label":"A","text":"A higher exchange rate will make imports more expensive and improve the balance of payments."},{"label":"B","text":"An increase in interest rates will encourage investment and lead to higher economic growth."},{"label":"C","text":"An increase in the money supply in an economy without spare capacity will result in demand-pull inflation."},{"label":"D","text":"Higher interest rates result in less income from savings and therefore higher unemployment."}],"correct":""},{"id":17,"text":"What is the most likely impact of lower direct taxes on demand and on supply?","options":[{"label":"A","text":"decrease | decrease"},{"label":"B","text":"decrease | increase"},{"label":"C","text":"increase | increase"},{"label":"D","text":"increase | decrease"}],"correct":""},{"id":18,"text":"The table shows the annual change in Gross Domestic Product (GDP) before adjustments for inflation have been made and the annual rate of inflation in four countries. Which country has the highest rate of growth in real GDP?","options":[{"label":"A","text":"5 | 6"},{"label":"B","text":"10 | 7"},{"label":"C","text":"15 | 14"},{"label":"D","text":"20 | 40"}],"correct":""},{"id":19,"text":"Which type of unemployment is generally regarded by economists as the least serious for the economy?","options":[{"label":"A","text":"cyclical"},{"label":"B","text":"frictional"},{"label":"C","text":"regional"},{"label":"D","text":"structural"}],"correct":""},{"id":20,"text":"What does the Human Development Index (HDI) indicate?","options":[{"label":"A","text":"economic development"},{"label":"B","text":"level of unemployment"},{"label":"C","text":"living standards"},{"label":"D","text":"Drate of inflation"}],"correct":""},{"id":21,"text":"What best describes relative poverty?","options":[{"label":"A","text":"A 12-year-old boy has never been able to access a doctor or school."},{"label":"B","text":"A person earns less than the minimum defined level of income."},{"label":"C","text":"A person has a lower living standard than the minimum level acceptable in a society."},{"label":"D","text":"A person is unable to afford the basic necessities of life."}],"correct":""},{"id":22,"text":"The table shows population statistics for three countries in a particular year. What can be concluded from the table?","options":[{"label":"A","text":"country \\( X \\) has fewer females than country \\( Y \\)"},{"label":"B","text":"country \\( Y \\) has the smallest population increase"},{"label":"C","text":"country \\( Y \\) has the highest living standards"},{"label":"D","text":") country Z has a decreasing population"}],"correct":"","table":"<table><tr><td>country</td><td>population size (millions)</td><td>birth rate (per thousand of population per year)</td><td>death rate (per thousand of population per year)</td><td>net migration</td></tr><tr><td>X</td><td>20</td><td>10</td><td>8</td><td>+20000</td></tr><tr><td>Y</td><td>30</td><td>20</td><td>18</td><td>+50000</td></tr><tr><td>Z</td><td>40</td><td>40</td><td>35</td><td>-1000000</td></tr></table>"},{"id":23,"text":"What is most likely to promote international specialisation?","options":[{"label":"A","text":"similarities in climate in different countries"},{"label":"B","text":"similarities in the availability of natural resources in different countries"},{"label":"C","text":"instability in foreign exchange rates"},{"label":"D","text":"the abolition of tariffs and customs duties"}],"correct":""},{"id":24,"text":"What are the effects on price and equilibrium quantity of the imposition of an import tariff on a good?","options":[{"label":"A","text":"decreases | decreases"},{"label":"B","text":"decreases | increases"},{"label":"C","text":"increases | decreases"},{"label":"D","text":"increases | increases"}],"correct":""},{"id":25,"text":"The diagram shows the market for the Indian rupee in US\\$. What will cause the demand curve for rupees to shift from \\( {\\mathrm{D}}_{1} \\) to \\( {\\mathrm{D}}_{2} \\) ?","options":[{"label":"A","text":"a fall in Indian exports to the US"},{"label":"B","text":"a fall in the US inflation rate"},{"label":"C","text":"a rise in foreign direct investment into India"},{"label":"D","text":"a rise in interest rates in the US"}],"correct":"","image":"/images/econ-mcq/145_601_251_595_497_0.jpg"},{"id":26,"text":"The diagram shows China's trade with Brazil for two years. What happened to China's trade balance with Brazil between year 1 and year 2?","options":[{"label":"A","text":"It experienced a falling surplus."},{"label":"B","text":"It experienced a rising deficit."},{"label":"C","text":"It moved from deficit to surplus."},{"label":"D","text":"It moved from surplus to deficit."}],"correct":"","image":"/images/econ-mcq/145_389_1238_1023_311_0.jpg"}];

const paper_16: MCQQuestion[] = [{"id":1,"text":"What is likely to increase the occupational mobility of labour?","options":[{"label":"A","text":"increasing entry requirements to professions"},{"label":"B","text":"increasing retraining of workers"},{"label":"C","text":"introducing job specialisation"},{"label":"D","text":"introducing subsidised transport"}],"correct":""},{"id":2,"text":"Sonia owns a takeaway food delivery service. She decides to expand the firm, buying more vans and hiring additional drivers. Which factors of production were changed?","options":[{"label":"A","text":"capital and labour"},{"label":"B","text":"capital and land"},{"label":"C","text":"enterprise and capital"},{"label":"D","text":"labour and land"}],"correct":""},{"id":3,"text":"In 2020, to prevent the spread of a pandemic, many governments temporarily closed restaurants and cafés. What would be a macroeconomic impact of such a policy?","options":[{"label":"A","text":"Demand for food to be consumed at home would rise."},{"label":"B","text":"Gross Domestic Product (GDP) would fall."},{"label":"C","text":"The profits from restaurants and cafés would fall."},{"label":"D","text":"Staff working in restaurants and cafés would lose income."}],"correct":""},{"id":4,"text":"Good weather results in an increase in the demand for and supply of peaches. How will this affect the price and quantity traded in the market for peaches?","options":[{"label":"A","text":"fall | fall"},{"label":"B","text":"rise | rise"},{"label":"C","text":"rise | uncertain"},{"label":"D","text":"uncertain | rise"}],"correct":""},{"id":5,"text":"The diagram shows demand and supply curves for a product at its equilibrium price P. How would the introduction of a subsidy be shown?","options":[{"label":"A","text":"Demand would shift to \\( {\\mathrm{D}}_{1} \\) ."},{"label":"B","text":"Demand would shift to \\( {\\mathrm{D}}_{2} \\) ."},{"label":"C","text":"Supply would shift to \\( {\\mathrm{S}}_{1} \\) ."},{"label":"D","text":"Supply would shift to \\( {\\mathrm{S}}_{2} \\) ."}],"correct":"","image":"/images/econ-mcq/148_595_252_611_497_0.jpg"},{"id":6,"text":"The table shows the quantity demanded at different prices. For which fall in price is the demand price-inelastic?","options":[{"label":"A","text":"from \\$6 to \\$5"},{"label":"B","text":"from \\$5 to \\$4"},{"label":"C","text":"from \\$4 to \\$3"},{"label":"D","text":"from \\$3 to \\$2"}],"correct":"","table":"<table><tr><td>price \\$</td><td>quantity demanded</td></tr><tr><td>6</td><td>3</td></tr><tr><td>5</td><td>4</td></tr><tr><td>4</td><td>5</td></tr><tr><td>3</td><td>7</td></tr><tr><td>2</td><td>9</td></tr></table>"},{"id":7,"text":"The price elasticity of supply (PES) of coffee is calculated as +0.2 for the current year and +2.0 in the long run. Why is the PES of coffee higher in the long run?","options":[{"label":"A","text":"Coffee plants take several years to grow."},{"label":"B","text":"Consumers will not buy coffee at higher prices."},{"label":"C","text":"There are many substitutes for coffee."},{"label":"D","text":"There are no stocks of coffee."}],"correct":""},{"id":8,"text":"What would a person believe who wished to encourage the use of the market system?","options":[{"label":"A","text":"people should have equal living standards"},{"label":"B","text":"people should have freedom of action"},{"label":"C","text":"profit maximisation is wrong"},{"label":"D","text":"the government should correct people's bad behaviour"}],"correct":""},{"id":9,"text":"What is not a form of money?","options":[{"label":"A","text":"a banknote"},{"label":"B","text":"a cheque"},{"label":"C","text":"a coin"},{"label":"D","text":"a credit card"}],"correct":""},{"id":10,"text":"If interest rates fall, what will be the most likely effect on saving and borrowing?","options":[{"label":"A","text":"decrease | decrease"},{"label":"B","text":"decrease | increase"},{"label":"C","text":"increase | decrease"},{"label":"D","text":"increase | increase"}],"correct":""},{"id":11,"text":"What is a function of a trade union?","options":[{"label":"A","text":"to negotiate workers' contracts"},{"label":"B","text":"to promote workers to more responsible jobs"},{"label":"C","text":"to recruit workers for the firm"},{"label":"D","text":"to supervise the workers in the firm"}],"correct":""},{"id":12,"text":"There has been an improvement in the transport infrastructure in India that reduces the costs of farming. What is this an example of?","options":[{"label":"A","text":"external diseconomies of scale"},{"label":"B","text":"external economies of scale"},{"label":"C","text":"internal diseconomies of scale"},{"label":"D","text":"internal economies of scale"}],"correct":""},{"id":13,"text":"A firm chooses to become more capital-intensive. What is least likely to have increased?","options":[{"label":"A","text":"interest rates"},{"label":"B","text":"minimum wages"},{"label":"C","text":"the power of trade unions"},{"label":"D","text":"the productivity of capital"}],"correct":""},{"id":14,"text":"The diagram shows the average total costs (ATC) and average fixed costs (AFC) for a firm. Which statement is correct?","options":[{"label":"A","text":"At output X, average variable costs are lower than average fixed costs."},{"label":"B","text":"At output Y, total variable costs are greater than total fixed costs."},{"label":"C","text":"Between outputs W and Z, total fixed costs are falling."},{"label":"D","text":"Between outputs W and Y, average variable costs have not changed."}],"correct":"","image":"/images/econ-mcq/151_627_251_543_465_0.jpg"},{"id":15,"text":"What is a macroeconomic aim of a government?","options":[{"label":"A","text":"high external costs"},{"label":"B","text":"high sales tax"},{"label":"C","text":"low unemployment"},{"label":"D","text":"low wages"}],"correct":""},{"id":16,"text":"What is a principle of taxation?","options":[{"label":"A","text":"equality between social cost and social benefit"},{"label":"B","text":"fairness between taxpayers"},{"label":"C","text":"profit maximisation by firms"},{"label":"D","text":"tax revenue maximisation"}],"correct":""},{"id":17,"text":"Monetary policy often involves a change in which variables?","options":[{"label":"A","text":"government expenditure or taxes"},{"label":"B","text":"interest rates or the money supply"},{"label":"C","text":"labour market or trade union laws"},{"label":"D","text":"tariffs or quotas"}],"correct":""},{"id":18,"text":"Which supply-side policy measure is most likely to enable a government to achieve its aim of full employment?","options":[{"label":"A","text":"decreasing government spending on school buildings"},{"label":"B","text":"decreasing the number of teachers in schools"},{"label":"C","text":"increasing taxation on private school fees"},{"label":"D","text":"increasing the provision of enterprise skills in schools"}],"correct":""},{"id":19,"text":"Which policy decision is most likely to cause economic growth?","options":[{"label":"A","text":"an increase in corporation tax rates"},{"label":"B","text":"an increase in interest rates"},{"label":"C","text":"an increase in the amount workers can earn before paying income tax"},{"label":"D","text":"an increase in the government's regulations for starting a new business"}],"correct":""},{"id":20,"text":"A government uses the labour force survey method to calculate unemployment. What is required under this method for a person to be classified as unemployed?","options":[{"label":"A","text":"no | no | yes"},{"label":"B","text":"no | yes | yes"},{"label":"C","text":"yes | yes | no"},{"label":"D","text":"yes | no | no"}],"correct":""},{"id":21,"text":"What is most likely to rise when the level of employment falls in a high-income economy?","options":[{"label":"A","text":"consumer confidence"},{"label":"B","text":"government expenditure on state benefits"},{"label":"C","text":"government revenue from income tax"},{"label":"D","text":"the rate of growth of real output"}],"correct":""},{"id":22,"text":"A Consumer Prices Index (CPI) consists of four items. The table shows the percentage price change for each item over a period of a year and the weight of each item. Which price change will affect the level of the CPI most?","options":[{"label":"A","text":"food | \\( + 5 \\) | 0.30"},{"label":"B","text":"housing | \\( + 6 \\) | 0.20"},{"label":"C","text":"recreation | \\( + 3 \\) | 0.40"},{"label":"D","text":"transport | +4 | 0.10"}],"correct":""},{"id":23,"text":"The table shows the Human Development Index (HDI) value for a country in two years. What would not explain the change in the HDI value?","options":[{"label":"A","text":"an increase in gender equality"},{"label":"B","text":"an increase in income per head"},{"label":"C","text":"- an increase in life expectancy"},{"label":"D","text":"an increase in years of schooling"}],"correct":"","table":"<table><tr><td>year</td><td>HDI value</td></tr><tr><td>1</td><td>0.467</td></tr><tr><td>2</td><td>0.609</td></tr></table>"},{"id":24,"text":"Which combination of statistics is used to calculate the natural population growth of a country?","options":[{"label":"A","text":"birth rate | net immigration"},{"label":"B","text":"death rate | birth rate"},{"label":"C","text":"emigration | death rate"},{"label":"D","text":"immigration | emigration"}],"correct":""},{"id":25,"text":"What will increase the level of specialisation in an economy?","options":[{"label":"A","text":"A computer manufacturer takes over an advertising company."},{"label":"B","text":"A retail store issues its own credit card."},{"label":"C","text":"A travel agent provides transport to the airport."},{"label":"D","text":"A vehicle assembler reduces its range of vehicles."}],"correct":""},{"id":26,"text":"What might an economist consider to be meant by the term dumping?","options":[{"label":"A","text":"foreign firms exporting waste products"},{"label":"B","text":"foreign firms producing goods at a lower cost than domestic firms"},{"label":"C","text":"foreign firms selling goods that are out of fashion"},{"label":"D","text":"foreign firms exporting products at a price below the cost of production"}],"correct":""},{"id":27,"text":"In the diagram, D is the demand curve for the Chinese yuan and S is the supply curve of the Chinese yuan. The Chinese central bank wishes to set the price of the yuan at \\( {P}_{1} \\) . Which action would it have to take?","options":[{"label":"A","text":"buy XY yuan"},{"label":"B","text":"buy XZ yuan"},{"label":"C","text":"sell XY yuan"},{"label":"D","text":"sell XZ yuan"}],"correct":"","image":"/images/econ-mcq/155_556_285_695_501_0.jpg"},{"id":28,"text":"The table shows the values of the items in a country's current account in two years. How did the value of net secondary income change between year 1 and year 2?","options":[{"label":"A","text":"decreased by \\$10m"},{"label":"B","text":"decreased by \\( \\$ {20}\\mathrm{\\;m} \\)"},{"label":"C","text":"increased by \\( \\$ {20}\\mathrm{\\;m} \\)"},{"label":"D","text":"increased by \\( \\$ {30}\\mathrm{\\;m} \\)"}],"correct":"","table":"<table><tr><td>item</td><td>year 1 (\\$m)</td><td>year 2 (\\$m)</td></tr><tr><td>balance of goods and services</td><td>-30</td><td>0</td></tr><tr><td>net primary income</td><td>-30</td><td>-20</td></tr><tr><td>net secondary income</td><td>?</td><td>?</td></tr><tr><td>balance of current account</td><td>-50</td><td>+10</td></tr></table>"}];

const paper_17: MCQQuestion[] = [{"id":1,"text":"A university rejects 2000 qualified applicants who wish to study there. Which factor of production could have caused the university to make this decision?","options":[{"label":"A","text":"infinite quantity of capital"},{"label":"B","text":"scarcity of labour"},{"label":"C","text":"surplus of land"},{"label":"D","text":"unlimited supply of enterprise"}],"correct":""},{"id":2,"text":"Sanjay, a coal miner, became unemployed when the only local mine closed. He lives in a village near family and friends and would like to stay in the same village. What is the cause of Sanjay's occupational immobility?","options":[{"label":"A","text":"a desire to live near family and friends"},{"label":"B","text":"no relevant skills"},{"label":"C","text":"the cost of travelling for work"},{"label":"D","text":"unaffordable housing"}],"correct":""},{"id":3,"text":"The diagram shows the production possibility curve (PPC) for an economy that is at point X. Which change in the economy's labour market will allow it to reach point Y?","options":[{"label":"A","text":"employed workers become more productive"},{"label":"B","text":"unemployed workers find new jobs"},{"label":"C","text":"workers emigrate for higher wages"},{"label":"D","text":"workers retire at younger ages"}],"correct":"","image":"/images/econ-mcq/156_580_1157_642_496_0.jpg"},{"id":4,"text":"What are both macroeconomic decisions?","options":[{"label":"A","text":"a school recruits more teachers | a firm sets the prices for its products"},{"label":"B","text":"a central bank reduces money supply | a government spends more on defence"},{"label":"C","text":"a government increases tax rates | a farmer decides which crops to grow"},{"label":"D","text":"a household cuts its energy use | a worker accepts an offer of overtime"}],"correct":""},{"id":5,"text":"The diagram shows the market for ice cream and the effects of very hot weather. If prices had remained at \\( {\\mathrm{P}}_{1} \\) even during the hot weather, what was likely to have happened in the market for ice cream?","options":[{"label":"A","text":"equilibrium"},{"label":"B","text":"excess supply"},{"label":"C","text":"rising profits"},{"label":"D","text":"shortage"}],"correct":"","image":"/images/econ-mcq/159_578_252_663_402_0.jpg"},{"id":6,"text":"The supply of which good is likely to be most price elastic?","options":[{"label":"A","text":"no | one day"},{"label":"B","text":"no | one year"},{"label":"C","text":"yes | one day"},{"label":"D","text":"yes | one year"}],"correct":""},{"id":7,"text":"What is a characteristic of a demerit good?","options":[{"label":"A","text":"it is more beneficial to the consumer than they realise"},{"label":"B","text":"it is overconsumed in the free market"},{"label":"C","text":"it is underproduced in the free market"},{"label":"D","text":"it provides external benefits"}],"correct":""},{"id":8,"text":"The table shows the average wage in four countries, A, B, C and D. In which country is there the greatest relative wage discrimination against female employees?","options":[{"label":"A","text":"100 | 80"},{"label":"B","text":"120 | 60"},{"label":"C","text":"140 | 100"},{"label":"D","text":"300 | 200"}],"correct":""},{"id":9,"text":"The diagram shows the average total cost curve (ATC) for a firm after a merger. Why is the movement from X to Y likely to result from this merger?","options":[{"label":"A","text":"Consumer demand is rising."},{"label":"B","text":"Marketing economies of scale occur at higher levels of output."},{"label":"C","text":"The firm faces problems of co-ordination between departments."},{"label":"D","text":"The firm is negotiating discounts through bulk buying."}],"correct":"","image":"/images/econ-mcq/160_659_826_481_407_0.jpg"},{"id":10,"text":"A restaurant employs two chefs who make all of the meals that are served to customers. What is most likely to increase the productivity of the chefs?","options":[{"label":"A","text":"a decrease in the number of customers in the restaurant"},{"label":"B","text":"a decrease in the chefs' pay"},{"label":"C","text":"an increase in the quality of the food"},{"label":"D","text":"an increase in training for the chefs"}],"correct":""},{"id":11,"text":"What are fixed costs?","options":[{"label":"A","text":"costs that are divided by the amount produced"},{"label":"B","text":"costs that are present when output is zero"},{"label":"C","text":"costs that change according to the level of output"},{"label":"D","text":"costs that decrease when output increases"}],"correct":""},{"id":12,"text":"The table shows the daily output and costs of four firms making chairs. Which firm has the highest average cost of production?","options":[{"label":"A","text":"6 | 100 | 140"},{"label":"B","text":"9 | 30 | 150"},{"label":"C","text":"12 | 200 | 160"},{"label":"D","text":"15 | 120 | 330"}],"correct":""},{"id":13,"text":"The only information known about a firm is the price it charges for its product and the quantity it sells. What else can be concluded from this?","options":[{"label":"A","text":"its average cost and profit"},{"label":"B","text":"its average cost and total revenue"},{"label":"C","text":"its average revenue and profit"},{"label":"D","text":"its average revenue and total revenue"}],"correct":""},{"id":14,"text":"If a very competitive market becomes a monopoly, what will be likely to increase and what will be likely to decrease?","options":[{"label":"A","text":"barriers to entry | economies of scale"},{"label":"B","text":"consumer choice | prices"},{"label":"C","text":"long-run profits | competition"},{"label":"D","text":"output | market share"}],"correct":""},{"id":15,"text":"Many central banks around the world decreased interest rates during a recession caused by a pandemic. What was the most likely macroeconomic aim of this policy?","options":[{"label":"A","text":"economic growth"},{"label":"B","text":"increase in the current account surplus"},{"label":"C","text":"low inflation"},{"label":"D","text":"redistribution of income"}],"correct":""},{"id":16,"text":"The diagram shows the percentage of income taken by a tax at different levels of income. Which term is used to describe the tax?","options":[{"label":"A","text":"indirect"},{"label":"B","text":"progressive"},{"label":"C","text":"proportional"},{"label":"D","text":"regressive"}],"correct":"","image":"/images/econ-mcq/162_640_723_533_333_0.jpg"},{"id":17,"text":"What is not a likely consequence of a rise in the budget deficit in a year?","options":[{"label":"A","text":"a rise in government borrowing"},{"label":"B","text":"a rise in the level of exports"},{"label":"C","text":"a rise in the national debt"},{"label":"D","text":"a rise in the rate of inflation"}],"correct":""},{"id":18,"text":"When a government aims to encourage economic growth, it may adopt supply-side policies. Which policy is a supply-side policy?","options":[{"label":"A","text":"increasing the money supply"},{"label":"B","text":"lowering interest rates"},{"label":"C","text":"reducing indirect taxation"},{"label":"D","text":"retraining unemployed workers"}],"correct":""},{"id":19,"text":"An economy that is fully employed is forecast to have an increase in total demand. What is most likely to increase?","options":[{"label":"A","text":"the rate of absolute poverty"},{"label":"B","text":"the government budget deficit"},{"label":"C","text":"the level of unemployment"},{"label":"D","text":"the rate of inflation"}],"correct":""},{"id":20,"text":"A school leaver is unable to find a job immediately after completing their education. Which type of unemployment is this?","options":[{"label":"A","text":"cyclical"},{"label":"B","text":"frictional"},{"label":"C","text":"regional"},{"label":"D","text":"structural"}],"correct":""},{"id":21,"text":"Which changes are likely to lead to the biggest increase in inflation in country X?","options":[{"label":"A","text":"5% decrease | 5% decrease"},{"label":"B","text":"5% decrease | 5% increase"},{"label":"C","text":"5% increase | 5% decrease"},{"label":"D","text":"5% increase | 5% increase"}],"correct":""},{"id":22,"text":"In rural areas in developing countries, farmers grow food for their own consumption. Why might this mean that the GDP is a weak measure of the standard of living in those countries?","options":[{"label":"A","text":"The food grown is not exported."},{"label":"B","text":"The GDP does not include agricultural production."},{"label":"C","text":"The GDP only refers to the public sector."},{"label":"D","text":"The value of the food is unknown."}],"correct":""},{"id":23,"text":"Japan's population has an increasing proportion of elderly people. What is the likely impact of this on the Japanese economy?","options":[{"label":"A","text":"increased government budget deficit"},{"label":"B","text":"increased rate of economic growth"},{"label":"C","text":"increased rate of emigration"},{"label":"D","text":"increased use of labour-intensive methods of production"}],"correct":""},{"id":24,"text":"Mining by multinational companies (MNCs) has both costs and benefits for the host nation. Which activity is least likely to offer a benefit to the host nation?","options":[{"label":"A","text":"developing courses for training in mining"},{"label":"B","text":"investing in infrastructure to export minerals"},{"label":"C","text":"repatriating profits and dividends"},{"label":"D","text":"using new technology"}],"correct":""},{"id":25,"text":"The table shows the retail price at which the same book can be bought in four countries. What additional information is required to make a meaningful comparison of the price of the book between the countries?","options":[{"label":"A","text":"direct tax rates"},{"label":"B","text":"exchange rates"},{"label":"C","text":"inflation rates"},{"label":"D","text":"level of import tariffs"}],"correct":"","table":"<table><tr><td>country</td><td>price in local currency</td><td>local currency</td></tr><tr><td>Australia</td><td>\\$14.99</td><td>Australian dollars</td></tr><tr><td>Canada</td><td>\\$11.99</td><td>Canadian dollars</td></tr><tr><td>New Zealand</td><td>\\$20.95</td><td>New Zealand dollars</td></tr><tr><td>United Kingdom</td><td>£6.99</td><td>GB pound</td></tr></table>"},{"id":26,"text":"What is a consequence of a surplus on the current account of the balance of payments?","options":[{"label":"A","text":"a decrease in GDP"},{"label":"B","text":"a decrease in unemployment"},{"label":"C","text":"a depreciation of the foreign exchange rate"},{"label":"D","text":"deflation"}],"correct":""}];

const paper_18: MCQQuestion[] = [{"id":1,"text":"What is not a factor of production?","options":[{"label":"A","text":"a 10 dollar note"},{"label":"B","text":"a farm labourer"},{"label":"C","text":"a farm shop"},{"label":"D","text":"a tractor"}],"correct":""},{"id":2,"text":"A person works at home making small cakes. She can make 30 cakes an hour and works for four hours a day. The total cost of the ingredients is \\$50 and she sells the cakes for \\$2 each. What is the opportunity cost if she takes a working day for a holiday?","options":[{"label":"A","text":"\\$50"},{"label":"B","text":"\\$240"},{"label":"C","text":"30 cakes"},{"label":"D","text":"120 cakes"}],"correct":""},{"id":3,"text":"An economy produces different types of goods using its limited resources. This can be illustrated by a production possibility curve (PPC). What does point X on the PPC show?","options":[{"label":"A","text":"All resources are used for the production of consumer goods."},{"label":"B","text":"More resources are allocated to producing capital goods than consumer goods."},{"label":"C","text":"Resources are allocated to produce a mixture of consumer goods and capital goods."},{"label":"D","text":"Total resources are not being fully utilised for production of these goods."}],"correct":"","image":"/images/econ-mcq/166_701_1118_606_440_0.jpg"},{"id":4,"text":"What is the function of the price mechanism in a market economy?","options":[{"label":"A","text":"allocating resources and guiding choices"},{"label":"B","text":"allowing governments to provide price stability"},{"label":"C","text":"enabling markets to operate fairly"},{"label":"D","text":"preventing competitors from entering a market"}],"correct":""},{"id":5,"text":"The table shows the demand and supply schedules for rice. The current price is \\$2.00 per kilo. What will happen if the price is reduced to \\$1.00 per kilo?","options":[{"label":"A","text":"The demand curve will shift to the left."},{"label":"B","text":"The market will move from shortage to surplus."},{"label":"C","text":"The market will move from surplus to shortage."},{"label":"D","text":"The supply curve will shift to the right."}],"correct":"","table":"<table><tr><td>price per kilo \\$</td><td>quantity demanded (million tonnes)</td><td>quantity supplied (million tonnes)</td></tr><tr><td>2.50</td><td>5</td><td>30</td></tr><tr><td>2.00</td><td>10</td><td>25</td></tr><tr><td>1.50</td><td>20</td><td>20</td></tr><tr><td>1.00</td><td>30</td><td>15</td></tr><tr><td>0.50</td><td>40</td><td>10</td></tr></table>"},{"id":6,"text":"The diagram shows the market for cherries in Chile. What would cause a change in the market equilibrium from \\( {\\mathrm{E}}_{1} \\) to \\( {\\mathrm{E}}_{2} \\) ?","options":[{"label":"A","text":"a newspaper article stating cherries are good for your health"},{"label":"B","text":"a poor harvest for cherries due to bad weather"},{"label":"C","text":"- an increase in the imports of cherries from Israel"},{"label":"D","text":"the government reducing the sales tax on cherries"}],"correct":"","image":"/images/econ-mcq/168_739_251_530_509_0.jpg"},{"id":7,"text":"A German car producer estimates the price elasticity of demand (PED) for its cars is -2.0. What can be concluded from this information?","options":[{"label":"A","text":"its cars are price elastic"},{"label":"B","text":"its cars are price inelastic"},{"label":"C","text":"its cars are unitary elastic"},{"label":"D","text":"its cars take time to produce"}],"correct":""},{"id":8,"text":"Which combination correctly describes features of a market economic system?","options":[{"label":"A","text":"by government | private sector"},{"label":"B","text":"by government | public sector"},{"label":"C","text":"by price mechanism | private sector"},{"label":"D","text":"by price mechanism | public sector"}],"correct":""},{"id":9,"text":"A country's central bank raised the rate of interest from 1% to 4% per year. How would this change have affected the amount saved and the cost of borrowing by individuals?","options":[{"label":"A","text":"decreased | decreased"},{"label":"B","text":"decreased | increased"},{"label":"C","text":"increased | decreased"},{"label":"D","text":"increased | increased"}],"correct":""},{"id":10,"text":"What is a non-wage factor influencing an individual's choice of occupation?","options":[{"label":"A","text":"the availability of overtime work"},{"label":"B","text":"the hourly rate of pay"},{"label":"C","text":"the opportunity to get a financial bonus"},{"label":"D","text":"the risk of unemployment"}],"correct":""},{"id":11,"text":"Workers in the secondary sector of an economy earn more on average than workers in the tertiary sector. Which combination will most likely increase differences in wages between workers in the secondary and tertiary sector of an economy?","options":[{"label":"A","text":"increased productivity | increased supply of workers"},{"label":"B","text":"decreased demand for products | decreased productivity of workers"},{"label":"C","text":"increased supply of workers | increased demand for products"},{"label":"D","text":"weaker bargaining strengths of trade unions | decreased minimum wage"}],"correct":""},{"id":12,"text":"What is most likely to increase the demand for labour in an industry?","options":[{"label":"A","text":"a decrease in the price of capital used by the industry"},{"label":"B","text":"a decrease in the productivity of labour in the industry"},{"label":"C","text":"an increase in the demand for the industry's product"},{"label":"D","text":"an increase in the wage paid to labour in the industry"}],"correct":""},{"id":13,"text":"A firm has fixed costs of \\$100 for its daily output. The table shows its daily total variable costs. What can be concluded about the firm's average total cost?","options":[{"label":"A","text":"It falls continuously."},{"label":"B","text":"It is highest at output 4 units."},{"label":"C","text":"It is lowest at output 3 units."},{"label":"D","text":"It rises continuously."}],"correct":"","table":"<table><tr><td>output (units)</td><td>1</td><td>2</td><td>3</td><td>4</td></tr><tr><td>total variable costs (\\$)</td><td>200</td><td>360</td><td>500</td><td>720</td></tr></table>"},{"id":14,"text":"A market changes from being very competitive to being a monopoly. What is likely to happen to output and price in this market?","options":[{"label":"A","text":"decrease | decrease"},{"label":"B","text":"decrease | increase"},{"label":"C","text":"increase | decrease"},{"label":"D","text":"increase | increase"}],"correct":""},{"id":15,"text":"What is the most likely reason for a government to aim for price stability?","options":[{"label":"A","text":"to improve international competitiveness"},{"label":"B","text":"to increase workers' wage demands"},{"label":"C","text":"to reduce consumer spending"},{"label":"D","text":"to reduce spending on employment-related benefits"}],"correct":""},{"id":16,"text":"A country's unemployment rate increased from 3.6% to 4.2% in one year. What might be the consequences for tax revenues and welfare payments?","options":[{"label":"A","text":"decrease | decrease"},{"label":"B","text":"decrease | increase"},{"label":"C","text":"increase | decrease"},{"label":"D","text":"increase | increase"}],"correct":""},{"id":17,"text":"In a country, some highly-paid workers reduce their working hours because of very high income tax rates at higher levels of income. What is a disadvantage of this income taxation?","options":[{"label":"A","text":"It creates uncertainty for workers."},{"label":"B","text":"It does not maximise tax revenue."},{"label":"C","text":"It is inequitable for lower-income earners."},{"label":"D","text":"It is regressive in the distribution of income."}],"correct":""},{"id":18,"text":"What is most likely to be a reason for taxing oil?","options":[{"label":"A","text":"to conserve oil resources"},{"label":"B","text":"to create employment"},{"label":"C","text":"to encourage economic growth"},{"label":"D","text":"to reduce oil prices"}],"correct":""},{"id":19,"text":"Brazil's real GDP fell by 3.8% in a year. What might have caused this?","options":[{"label":"A","text":"a decrease in imports"},{"label":"B","text":"a decrease in income tax"},{"label":"C","text":"an increase in interest rates"},{"label":"D","text":"an increase in output per worker"}],"correct":""},{"id":20,"text":"Factory owners invest in technologically-advanced industrial production by building new large-scale, energy-efficient factories. What is a negative consequence of this for local people?","options":[{"label":"A","text":"a large increase in the factory owners' incomes"},{"label":"B","text":"a reduction in the rate of inflation"},{"label":"C","text":"a rise in structural unemployment"},{"label":"D","text":"lower emissions of carbon gases"}],"correct":""},{"id":21,"text":"Country X measures unemployment by counting the number of people claiming unemployment benefit. Why might this method underestimate the level of unemployment?","options":[{"label":"A","text":"Some benefit claimants are working unofficially."},{"label":"B","text":"Some employees work overtime."},{"label":"C","text":"Some jobseekers do not claim benefits."},{"label":"D","text":"Some people are unable to work."}],"correct":""},{"id":22,"text":"What is likely to cause deflation?","options":[{"label":"A","text":"higher employment"},{"label":"B","text":"higher production costs"},{"label":"C","text":"increased money supply"},{"label":"D","text":"technological advances"}],"correct":""},{"id":23,"text":"What is the most likely reason that an improved standard of education will alleviate poverty?","options":[{"label":"A","text":"It will decrease the productivity of workers."},{"label":"B","text":"It will decrease the rate of unemployment."},{"label":"C","text":"It will increase the government budget deficit."},{"label":"D","text":"It will increase the rate of inflation of an economy."}],"correct":""},{"id":24,"text":"What will increase a country's population, all other things being equal?","options":[{"label":"A","text":"a rise in emigration"},{"label":"B","text":"a rise in immigration"},{"label":"C","text":"death rates higher than birth rates"},{"label":"D","text":"decreased life expectancy"}],"correct":""},{"id":25,"text":"Country Y decides to specialise in the domestic mining of rare metals required in the production of electric-car batteries. What is a likely benefit of this for country Y?","options":[{"label":"A","text":"increased emigration"},{"label":"B","text":"increased exports"},{"label":"C","text":"increased imports"},{"label":"D","text":"increased tariff revenue"}],"correct":""},{"id":26,"text":"The UK government increases the price of steel imported from Germany by increasing an existing tariff. Assuming steel has price-inelastic demand, what would be the effect on the revenues of German steel producers and the UK government?","options":[{"label":"A","text":"decrease | decrease"},{"label":"B","text":"decrease | increase"},{"label":"C","text":"increase | decrease"},{"label":"D","text":"increase | increase"}],"correct":""},{"id":27,"text":"The table shows the value of the UK pound (£) against the US dollar (\\$) in June and September. What will be the likely consequence for the UK economy in the short run of the change in the exchange rate?","options":[{"label":"A","text":"an increase in the budget deficit"},{"label":"B","text":"an increase in the price of exports"},{"label":"C","text":"an increase in the price of imports"},{"label":"D","text":"an increase in unemployment"}],"correct":"","table":"<table><tr><td>June</td><td>September</td></tr><tr><td>£1 = \\$1.48</td><td>£1 = \\$1.32</td></tr></table>"},{"id":28,"text":"The table shows a selection of economic data for a country. What is the current account balance of the balance of payments of this country?","options":[{"label":"A","text":"\\$100m B \\$600m C \\$4500m D \\$4725m"},{"label":"B","text":"Permission to reproduce items where third-party owned material protected by copyright is included has been sought and cleared where possible. Every reasonable effort has been made by the publisher (UCLES) to trace copyright holders, but if any items requiring clearance have unwittingly been included, the publisher will be pleased to make amends at the earliest possible opportunity."},{"label":"C","text":"To avoid the issue of disclosure of answer-related information to candidates, all copyright acknowledgements are reproduced online in the Cambridge Assessment International Education Copyright Acknowledgements Booklet. This is produced for each series of examinations and is freely available to download at www.cambridgeinternational.org after the live examination series."},{"label":"D","text":"Cambridge Assessment International Education is part of Cambridge Assessment. Cambridge Assessment is the brand name of University of Cambridge Local Examinations Syndicate (UCLES), which is a department of the University of Cambridge."}],"correct":"","table":"<table><tr><td></td><td>\\$m</td></tr><tr><td>primary income</td><td>1000</td></tr><tr><td>secondary income</td><td>-500</td></tr><tr><td>total value of exported goods</td><td>1000</td></tr><tr><td>total value of imported goods</td><td>2000</td></tr><tr><td>total value of exported services</td><td>800</td></tr><tr><td>total value of imported services</td><td>200</td></tr></table>"}];

const paper_19: MCQQuestion[] = [{"id":1,"text":"To help reduce the price of oil, new supplies are needed. However, objectors oppose exploration of new sites because of the environmental damage it may cause. Why is this statement an example of the basic economic problem?","options":[{"label":"A","text":"Oil is a limited resource."},{"label":"B","text":"Oil is expensive."},{"label":"C","text":"The exploration involves demand and supply."},{"label":"D","text":"There are external costs involved in production."}],"correct":""},{"id":2,"text":"The production possibility curve (PPC) shows the hours per day a student has for either entertainment or revision. The student revises for 3 hours a day. As exams approach, the student decides to revise for 9 hours a day. What is the opportunity cost of this decision?","options":[{"label":"A","text":"3 hours of revision"},{"label":"B","text":"6 hours of entertainment"},{"label":"C","text":"6 hours of revision"},{"label":"D","text":"9 hours of entertainment"}],"correct":"","image":"/images/econ-mcq/177_542_724_709_561_0.jpg"},{"id":3,"text":"Helium is a gas that is limited in supply because it takes thousands of years to form. The US government holds 35% of the world's supply of helium and has been selling its stocks. Helium is essential in medical scanners. It is also used for party balloons, which is a wasteful alternative use of a valuable good. Which two concepts apply to this statement?","options":[{"label":"A","text":"demand and supply, government subsidy"},{"label":"B","text":"excess demand, resource allocation"},{"label":"C","text":"opportunity cost, private monopoly"},{"label":"D","text":"public sector, factors of production"}],"correct":""},{"id":4,"text":"When is production certain to harm society?","options":[{"label":"A","text":"when the private costs are greater than the private benefits"},{"label":"B","text":"when the production results in externalities"},{"label":"C","text":"when the social costs are greater than the private costs"},{"label":"D","text":"when the social costs are greater than the social benefits"}],"correct":""},{"id":5,"text":"What is the role of the price mechanism in a market economy?","options":[{"label":"A","text":"to allocate scarce resources"},{"label":"B","text":"to increase the provision of merit goods"},{"label":"C","text":"to make the distribution of goods and services more equal"},{"label":"D","text":"to reduce the negative externalities of production and consumption"}],"correct":""},{"id":6,"text":"What is a macroeconomic concept?","options":[{"label":"A","text":"the effect of a price change of a good"},{"label":"B","text":"the equilibrium price in the market for a good"},{"label":"C","text":"the reason for a change in a firm's behaviour"},{"label":"D","text":"the total spending in an economy"}],"correct":""},{"id":7,"text":"The price elasticity of demand (PED) for bottled water is -0.9 . What will happen to the quantity demanded for bottled water if its price increases by 10%?","options":[{"label":"A","text":"decrease by 0.9%"},{"label":"B","text":"decrease by 9%"},{"label":"C","text":"increase by 0.9%"},{"label":"D","text":"increase by 9%"}],"correct":""},{"id":8,"text":"What will increase the demand for labour in an industry?","options":[{"label":"A","text":"a decrease in labour productivity in that industry"},{"label":"B","text":"a decrease in the demand for the good made in that industry"},{"label":"C","text":"an increase in labour productivity in that industry"},{"label":"D","text":"an increase in wages in that industry"}],"correct":""},{"id":9,"text":"Which government policies will both reduce the difference in income between low-paid and high-paid workers?","options":[{"label":"A","text":"a decrease in the maximum wage and a more regressive income tax system"},{"label":"B","text":"a decrease in the maximum wage and a reduction in trade union power"},{"label":"C","text":"an increase in the minimum wage and a more progressive income tax system"},{"label":"D","text":"an increase in the minimum wage and a more regressive income tax system"}],"correct":""},{"id":10,"text":"Wages for nurses decrease, while working hours for pilots decrease. Assuming other factors do not change, what is the likely effect on the number of individuals choosing to become nurses or pilots?","options":[{"label":"A","text":"decrease | decrease"},{"label":"B","text":"decrease | increase"},{"label":"C","text":"increase | decrease"},{"label":"D","text":"increase | increase"}],"correct":""},{"id":11,"text":"The table shows the average revenue of a firm at various levels of output. What happens to total revenue as output rises?","options":[{"label":"A","text":"It falls and then rises."},{"label":"B","text":"It falls continuously."},{"label":"C","text":"It rises and then falls."},{"label":"D","text":"It rises continuously."}],"correct":"","table":"<table><tr><td>output</td><td>average revenue (\\$)</td></tr><tr><td>1</td><td>10</td></tr><tr><td>2</td><td>8</td></tr><tr><td>3</td><td>6</td></tr><tr><td>4</td><td>4</td></tr></table>"},{"id":12,"text":"For some months the price of petrol (gas) decreased significantly. How would this affect a delivery firm that delivers goods for other firms using petrol (gas) powered vehicles?","options":[{"label":"A","text":"Average fixed costs would decrease."},{"label":"B","text":"Profits would decrease."},{"label":"C","text":"Total fixed costs would decrease."},{"label":"D","text":"Variable costs would decrease."}],"correct":""},{"id":13,"text":"The size of the domestic car industry in Japan has enabled Japanese car producers to be more price competitive than rival car producers. What is an explanation for this?","options":[{"label":"A","text":"Economies of scale are present in the Japanese car industry."},{"label":"B","text":"Managerial problems exist in the Japanese car industry."},{"label":"C","text":"Productivity is low in Japan."},{"label":"D","text":"The Japanese car industry is very labour-intensive."}],"correct":""},{"id":14,"text":"What is a major advantage of a horizontal merger compared with a conglomerate merger?","options":[{"label":"A","text":"It causes more motivation of the workforce."},{"label":"B","text":"It gains financial economies of scale with cheaper borrowing from banks."},{"label":"C","text":"It leads to a diversification making the firm less vulnerable."},{"label":"D","text":"It reduces competition and increases the merged firm's market share."}],"correct":""},{"id":15,"text":"Recession is when there are two consecutive quarters (six months) of","options":[{"label":"A","text":"deflation."},{"label":"B","text":"falling GDP."},{"label":"C","text":"rising prices."},{"label":"D","text":"rising unemployment."}],"correct":""},{"id":16,"text":"An economy is operating with all resources fully employed. Which would be an outcome of a significant increase in government expenditure?","options":[{"label":"A","text":"deflation"},{"label":"B","text":"demand-pull inflation"},{"label":"C","text":"falling output"},{"label":"D","text":"increased employment"}],"correct":""},{"id":17,"text":"What causes economic growth?","options":[{"label":"A","text":"availability of more resources"},{"label":"B","text":"higher imports of consumer goods"},{"label":"C","text":"higher unemployment"},{"label":"D","text":"lower investment"}],"correct":""},{"id":18,"text":"Which statement about supply-side policy is correct?","options":[{"label":"A","text":"It aims to increase the productive potential of the economy."},{"label":"B","text":"It aims to increase total demand in the economy."},{"label":"C","text":"It involves changes in the equilibrium foreign exchange rate."},{"label":"D","text":"It involves changes in the rate of interest."}],"correct":""},{"id":19,"text":"Why is weighting used in the Consumer Prices Index (CPI)?","options":[{"label":"A","text":"to ensure that all items in the index are treated equally"},{"label":"B","text":"to ensure that all price changes are included in the index"},{"label":"C","text":"to ensure that the index includes changes in the quantity consumed"},{"label":"D","text":"to ensure that the index reflects the spending patterns of consumers"}],"correct":""},{"id":20,"text":"Which combination of policy measures is most likely to increase the level of employment?","options":[{"label":"A","text":"decrease general taxation and decrease the rate of interest"},{"label":"B","text":"decrease general taxation and increase the rate of interest"},{"label":"C","text":"increase general taxation and decrease the rate of interest"},{"label":"D","text":"increase general taxation and increase the rate of interest"}],"correct":""},{"id":21,"text":"What is a certain cause of absolute poverty?","options":[{"label":"A","text":"growing old"},{"label":"B","text":"insufficient income for basic needs"},{"label":"C","text":"lack of good healthcare"},{"label":"D","text":"many dependants in the family"}],"correct":""},{"id":22,"text":"The birth rate in a country is higher than the death rate. What might prevent the country's population from rising?","options":[{"label":"A","text":"Emigration is greater than immigration."},{"label":"B","text":"The birth rate is falling."},{"label":"C","text":"The country's medical care improves."},{"label":"D","text":"The death rate is rising."}],"correct":""},{"id":23,"text":"The table shows statistics for four countries, A-D. Which country has the lowest standard of living?","options":[{"label":"A","text":"1.9 | 19 | 46 | 190"},{"label":"B","text":"2.7 | 2 | 58 | 1700"},{"label":"C","text":"3.7 | 45 | 59 | 210"},{"label":"D","text":"4.2 | 89 | 44 | 190"}],"correct":""},{"id":24,"text":"Why can specialisation cause economic growth?","options":[{"label":"A","text":"Specialisation can allow a country to produce many different goods and services."},{"label":"B","text":"Specialisation can lead to a reduction in average costs of production."},{"label":"C","text":"Specialisation can mean that firms in a country will face diseconomies of scale."},{"label":"D","text":"Specialisation can reduce a country's need to depend on other economies."}],"correct":""},{"id":25,"text":"The diagram shows China's trade with Brazil for two years. What happened to China's trade balance with Brazil between year 1 and year 2?","options":[{"label":"A","text":"It experienced a falling surplus."},{"label":"B","text":"It experienced a rising deficit."},{"label":"C","text":"It moved from deficit to surplus."},{"label":"D","text":"It moved from surplus to deficit."}],"correct":"","image":"/images/econ-mcq/184_391_1198_1020_308_0.jpg"},{"id":26,"text":"Why do some governments limit the operations of multinational companies (MNCs) within their domestic economy?","options":[{"label":"A","text":"MNCs contribute to technological advances."},{"label":"B","text":"MNCs decrease a country's unemployment rate."},{"label":"C","text":"MNCs gain profits which are transferred out of the country."},{"label":"D","text":"MNCs increase a country's current account surplus."}],"correct":""},{"id":27,"text":"What is an immediate effect for a country of a fall in its foreign exchange rate?","options":[{"label":"A","text":"a fall in the money supply"},{"label":"B","text":"an increase in purchasing power"},{"label":"C","text":"cheaper imports"},{"label":"D","text":"more competitive exports"}],"correct":""}];

const paper_20: MCQQuestion[] = [{"id":1,"text":"To help reduce the price of oil, new supplies are needed. However, objectors oppose exploration of new sites because of the environmental damage it may cause. Why is this statement an example of the basic economic problem?","options":[{"label":"A","text":"Oil is a limited resource."},{"label":"B","text":"Oil is expensive."},{"label":"C","text":"The exploration involves demand and supply."},{"label":"D","text":"There are external costs involved in production."}],"correct":""},{"id":2,"text":"What is an opportunity cost for a consumer spending money on a holiday?","options":[{"label":"A","text":"the potential interest earned if the holiday money had been saved"},{"label":"B","text":"the price paid for an air ticket to the holiday destination"},{"label":"C","text":"the rubbish created during the holiday which affects the local community"},{"label":"D","text":"the satisfaction that the consumer gains from the holiday"}],"correct":""},{"id":3,"text":"Helium is a gas that is limited in supply because it takes thousands of years to form. The US government holds 35% of the world's supply of helium and has been selling its stocks. Helium is essential in medical scanners. It is also used for party balloons, which is a wasteful alternative use of a valuable good. Which two concepts apply to this statement?","options":[{"label":"A","text":"demand and supply, government subsidy"},{"label":"B","text":"excess demand, resource allocation"},{"label":"C","text":"opportunity cost, private monopoly"},{"label":"D","text":"public sector, factors of production"}],"correct":""},{"id":4,"text":"Which combination of characteristics describes a public good?","options":[{"label":"A","text":"excludable and non-rival in consumption"},{"label":"B","text":"excludable and rival in consumption"},{"label":"C","text":"non-excludable and non-rival in consumption"},{"label":"D","text":"non-excludable and rival in consumption"}],"correct":""},{"id":5,"text":"What is an advantage of a market economy?","options":[{"label":"A","text":"Equilibrium market price clears the market."},{"label":"B","text":"Producers and consumers have the same aims."},{"label":"C","text":"The government has no need to intervene in markets."},{"label":"D","text":"The lowest price possible is always charged."}],"correct":""},{"id":6,"text":"What is a macroeconomic aim of a government?","options":[{"label":"A","text":"balance of payments stability"},{"label":"B","text":"deflation"},{"label":"C","text":"income inequality"},{"label":"D","text":"unemployment"}],"correct":""},{"id":7,"text":"The table shows the quantity demanded at different prices. For which fall in price is the demand price-inelastic?","options":[{"label":"A","text":"from \\$6 to \\$5"},{"label":"B","text":"from \\$5 to \\$4"},{"label":"C","text":"from \\$4 to \\$3"},{"label":"D","text":"from \\$3 to \\$2"}],"correct":"","table":"<table><tr><td>price \\$</td><td>quantity demanded</td></tr><tr><td>6</td><td>3</td></tr><tr><td>5</td><td>4</td></tr><tr><td>4</td><td>5</td></tr><tr><td>3</td><td>7</td></tr><tr><td>2</td><td>9</td></tr></table>"},{"id":8,"text":"Which government policy will increase productivity?","options":[{"label":"A","text":"decreasing the number of training programmes"},{"label":"B","text":"encouraging labour-intensive production"},{"label":"C","text":"promoting good industrial relations"},{"label":"D","text":"reducing private sector investment"}],"correct":""},{"id":9,"text":"The diagrams show the wage rates of cleaners (OWc) and nurses (OWn). What is the result if a national minimum wage of OM is introduced?","options":[{"label":"A","text":"fall | rise"},{"label":"B","text":"no change | fall"},{"label":"C","text":"rise | fall"},{"label":"D","text":"rise | no change"}],"correct":"","image":"/images/econ-mcq/189_285_235_1222_377_0.jpg"},{"id":10,"text":"Which result of increased specialisation in a firm is an advantage for the firm, but a disadvantage for some of the workers in the firm?","options":[{"label":"A","text":"greater mechanisation"},{"label":"B","text":"higher labour productivity"},{"label":"C","text":"higher skill levels"},{"label":"D","text":"longer training times"}],"correct":""},{"id":11,"text":"The diagram shows the total cost curve for a firm. What can be concluded about the firm?","options":[{"label":"A","text":"It has no fixed costs."},{"label":"B","text":"It has no variable costs."},{"label":"C","text":"Its average fixed cost increases."},{"label":"D","text":"Its average variable cost is constant."}],"correct":"","image":"/images/econ-mcq/190_662_1044_471_403_0.jpg"},{"id":12,"text":"Two car manufacturers agree to merge. Which outcome would be a disadvantage for customers?","options":[{"label":"A","text":"increased capital for research and development"},{"label":"B","text":"lower average costs through economies of scale"},{"label":"C","text":"reduced range of vehicles produced"},{"label":"D","text":"use of a wider range of marketing information"}],"correct":""},{"id":13,"text":"An economy recorded a second month of deflation. What does this mean?","options":[{"label":"A","text":"It was facing a recession."},{"label":"B","text":"Price levels were falling."},{"label":"C","text":"Total demand was rising."},{"label":"D","text":"Unemployment was falling."}],"correct":""},{"id":14,"text":"What is a cause of demand-pull inflation?","options":[{"label":"A","text":"a surplus of skilled labour"},{"label":"B","text":"higher government expenditure"},{"label":"C","text":"higher tax rates"},{"label":"D","text":"lower net exports"}],"correct":""},{"id":15,"text":"What is the consequence of economic growth for individuals and for the economy?","options":[{"label":"A","text":"increase in absolute poverty | increase in inflation"},{"label":"B","text":"increase in average incomes | increase in government tax revenue"},{"label":"C","text":"increase in the variety of goods and services | reduction in exports"},{"label":"D","text":"increase in unemployment | reduction in the standard of living"}],"correct":""},{"id":16,"text":"Which supply-side policy measure would help to match the skills of workers to job vacancies?","options":[{"label":"A","text":"encouraging the modernisation of factories"},{"label":"B","text":"offering retraining to unemployed workers"},{"label":"C","text":"reducing taxes to provide incentives to work"},{"label":"D","text":"replacing government enterprises with private enterprises"}],"correct":""},{"id":17,"text":"How is the rate of inflation measured?","options":[{"label":"A","text":"by calculating the change in the price of goods and services from one year to the next"},{"label":"B","text":"by calculating the real value of all output of goods and services in an economy"},{"label":"C","text":"by calculating the total number of people willing and able to work but cannot find work"},{"label":"D","text":"by calculating the total value of exports minus the total value of imports"}],"correct":""},{"id":18,"text":"Which combination of policy measures is most likely to increase the level of employment?","options":[{"label":"A","text":"decrease general taxation and decrease the rate of interest"},{"label":"B","text":"decrease general taxation and increase the rate of interest"},{"label":"C","text":"increase general taxation and decrease the rate of interest"},{"label":"D","text":"increase general taxation and increase the rate of interest"}],"correct":""},{"id":19,"text":"Poverty in households may be defined in relative terms. What indicates relative poverty?","options":[{"label":"A","text":"falling below society's expected standard of living"},{"label":"B","text":"income level required to meet basic needs"},{"label":"C","text":"lack of access to clean water"},{"label":"D","text":"living on less than \\$2 a day"}],"correct":""},{"id":20,"text":"What is the effect on an economy of net emigration of people aged 20-40?","options":[{"label":"A","text":"a more mobile labour force"},{"label":"B","text":"an ageing population"},{"label":"C","text":"higher government tax revenue"},{"label":"D","text":"rising house prices"}],"correct":""},{"id":21,"text":"The table shows statistics for four countries, A-D. Which country has the lowest standard of living?","options":[{"label":"A","text":"1.9 | 19 | 46 | 190"},{"label":"B","text":"2.7 | 2 | 58 | 1700"},{"label":"C","text":"3.7 | 45 | 59 | 210"},{"label":"D","text":"4.2 | 89 | 44 | 190"}],"correct":""},{"id":22,"text":"A country specialises in the production of steel, toys and textiles. What is a disadvantage of specialisation for the country's workers?","options":[{"label":"A","text":"They cannot afford to buy products from other countries."},{"label":"B","text":"They could become structurally unemployed if global demand changes."},{"label":"C","text":"They have to learn a variety of skills."},{"label":"D","text":"They have too much choice which wastes their time."}],"correct":""},{"id":23,"text":"The diagram shows China's trade with Brazil for two years. What happened to China's trade balance with Brazil between year 1 and year 2?","options":[{"label":"A","text":"It experienced a falling surplus."},{"label":"B","text":"It experienced a rising deficit."},{"label":"C","text":"It moved from deficit to surplus."},{"label":"D","text":"It moved from surplus to deficit."}],"correct":"","image":"/images/econ-mcq/194_390_1269_1019_295_0.jpg"},{"id":24,"text":"The US imposed tariffs on cars and motorcycles from Germany. What is the effect of these tariffs?","options":[{"label":"A","text":"decrease in inflation in the US"},{"label":"B","text":"decrease in trade between the US and Germany"},{"label":"C","text":"increase in profits of car and motorcycle producers from Germany"},{"label":"D","text":"increase in standards of living in the US and in Germany"}],"correct":""},{"id":25,"text":"What is an immediate effect for a country of a fall in its foreign exchange rate?","options":[{"label":"A","text":"a fall in the money supply"},{"label":"B","text":"an increase in purchasing power"},{"label":"C","text":"cheaper imports"},{"label":"D","text":"more competitive exports"}],"correct":""}];

const paper_21: MCQQuestion[] = [{"id":1,"text":"To help reduce the price of oil, new supplies are needed. However, objectors oppose exploration of new sites because of the environmental damage it may cause. Why is this statement an example of the basic economic problem?","options":[{"label":"A","text":"Oil is a limited resource."},{"label":"B","text":"Oil is expensive."},{"label":"C","text":"The exploration involves demand and supply."},{"label":"D","text":"There are external costs involved in production."}],"correct":""},{"id":2,"text":"Helium is a gas that is limited in supply because it takes thousands of years to form. The US government holds 35% of the world's supply of helium and has been selling its stocks. Helium is essential in medical scanners. It is also used for party balloons, which is a wasteful alternative use of a valuable good. Which two concepts apply to this statement?","options":[{"label":"A","text":"demand and supply, government subsidy"},{"label":"B","text":"excess demand, resource allocation"},{"label":"C","text":"Copportunity cost, private monopoly"},{"label":"D","text":"public sector, factors of production"}],"correct":""},{"id":3,"text":"What is an example of a public good?","options":[{"label":"A","text":"healthcare"},{"label":"B","text":"street lights"},{"label":"C","text":"cunemployment benefits"},{"label":"D","text":"vaccinations"}],"correct":""},{"id":4,"text":"Why does a government provide certain goods and services in a mixed economic system?","options":[{"label":"A","text":"The government always provides goods more cheaply than private firms."},{"label":"B","text":"The government considers only private costs and benefits."},{"label":"C","text":"The government provides goods to prevent the development of monopolies."},{"label":"D","text":"The government provides public goods because private firms cannot charge for them."}],"correct":""},{"id":5,"text":"What is a microeconomic decision?","options":[{"label":"A","text":"a central bank reducing interest rates"},{"label":"B","text":"a gas firm reducing its prices"},{"label":"C","text":"a government increasing income tax"},{"label":"D","text":"a government increasing the national minimum wage"}],"correct":""},{"id":6,"text":"The diagram shows a shift in the supply curve for New Zealand’s airlines from \\( {S}_{1} \\) to \\( {S}_{2} \\) . What is the cause of this shift?","options":[{"label":"A","text":"a decrease in the costs of New Zealand's airlines"},{"label":"B","text":"a decrease in the number of people wanting to fly to New Zealand"},{"label":"C","text":"an increase in the price of train and bus travel in New Zealand"},{"label":"D","text":"an increase in the tax on air travel in New Zealand"}],"correct":"","image":"/images/econ-mcq/197_647_1286_500_395_0.jpg"},{"id":7,"text":"The diagram shows the demand curve for rice. What is the price elasticity of demand (PED) for rice as price increases from \\$1.0 to \\$1.5 per kilo?","options":[{"label":"A","text":"0"},{"label":"B","text":"1"},{"label":"C","text":"less than 1"},{"label":"D","text":"greater than 1"}],"correct":"","image":"/images/econ-mcq/198_532_234_733_484_0.jpg"},{"id":8,"text":"The table shows the output of cakes from four bakeries, A-D. Which bakery has the highest labour productivity?","options":[{"label":"A","text":"10 | 40"},{"label":"B","text":"40 | 640"},{"label":"C","text":"50 | 750"},{"label":"D","text":"100 | 500"}],"correct":""},{"id":9,"text":"What is an advantage of labour-intensive production and what is an advantage of capital-intensive production?","options":[{"label":"A","text":"each item can be individually made | average costs of production are low"},{"label":"B","text":"keeps unemployment down | fixed costs are high"},{"label":"C","text":"workers have pride in the product | machinery may break down"},{"label":"D","text":"workers have to work hard | there is a ready market for the product"}],"correct":""},{"id":10,"text":"The market equilibrium wage rate is \\( \\$ {10} \\) per hour. What explains why the wage rate actually paid is \\( \\$ {12} \\) per hour?","options":[{"label":"A","text":"Employers are competing for labour."},{"label":"B","text":"The government sets a minimum wage of \\$12 per hour."},{"label":"C","text":"There is a surplus of skilled labour."},{"label":"D","text":"Workers have received unpaid training."}],"correct":""},{"id":11,"text":"The diagram shows total cost (TC), total fixed cost (TFC) and total variable cost (TVC). Which costs are shown by W, X and Y?","options":[{"label":"A","text":"TC | TFC | TVC"},{"label":"B","text":"TC | TVC | TFC"},{"label":"C","text":"TFC | TC | TVC"},{"label":"D","text":"TVC | TC | TFC"}],"correct":"","image":"/images/econ-mcq/199_669_931_461_438_0.jpg"},{"id":12,"text":"The table shows output and total cost of a firm with four production methods, A-D. Which method causes diseconomies of scale as the firm expands production from 1000 to 3000 units?","options":[{"label":"A","text":"8000 | 10000 | 12000"},{"label":"B","text":"8000 | 14000 | 27000"},{"label":"C","text":"10000 | 16000 | 21000"},{"label":"D","text":"10000 | 20000 | 30000"}],"correct":""},{"id":13,"text":"A clothing manufacturer expands by taking over a clothing retailer. Which type of merger is this?","options":[{"label":"A","text":"backward vertical"},{"label":"B","text":"conglomerate"},{"label":"C","text":"forward vertical"},{"label":"D","text":"horizontal"}],"correct":""},{"id":14,"text":"Which economic situation exists when there are two consecutive quarters (six months) of negative economic growth?","options":[{"label":"A","text":"budget surplus"},{"label":"B","text":"current account deficit"},{"label":"C","text":"inflation"},{"label":"D","text":"recession"}],"correct":""},{"id":15,"text":"Why might measures to reduce unemployment also make inflation rise?","options":[{"label":"A","text":"They encourage cheap imports."},{"label":"B","text":"They increase demand."},{"label":"C","text":"They reduce firms' costs."},{"label":"D","text":"They require wages to fall."}],"correct":""},{"id":16,"text":"Which change affecting an economy's labour market promotes economic growth?","options":[{"label":"A","text":"increasing trade union strike action"},{"label":"B","text":"lowering the age of retirement"},{"label":"C","text":"reducing training of workers"},{"label":"D","text":"removing immigration controls"}],"correct":""},{"id":17,"text":"Which statement relating to supply-side policies is correct?","options":[{"label":"A","text":"They aim to increase aggregate demand."},{"label":"B","text":"They aim to increase the long-run capacity of the economy."},{"label":"C","text":"They aim to reduce cyclical unemployment."},{"label":"D","text":"They aim to work in the short term."}],"correct":""},{"id":18,"text":"What is always indicated by an increase in the Consumer Prices Index (CPI)?","options":[{"label":"A","text":"an increase in consumer spending in an economy"},{"label":"B","text":"an increase in living standards"},{"label":"C","text":"an increase in the average cost of living"},{"label":"D","text":"an increase in the purchasing power of money"}],"correct":""},{"id":19,"text":"Which combination of policy measures is most likely to increase the level of employment?","options":[{"label":"A","text":"decrease general taxation and decrease the rate of interest"},{"label":"B","text":"decrease general taxation and increase the rate of interest"},{"label":"C","text":"increase general taxation and decrease the rate of interest"},{"label":"D","text":"increase general taxation and increase the rate of interest"}],"correct":""},{"id":20,"text":"What could reduce poverty?","options":[{"label":"A","text":"greater economic growth"},{"label":"B","text":"less spending on education"},{"label":"C","text":"more regressive taxation"},{"label":"D","text":"privatisation of hospitals"}],"correct":""},{"id":21,"text":"The table shows information about four countries, A-D. Which country is most likely to have a falling population?","options":[{"label":"A","text":"falling | falling"},{"label":"B","text":"falling | rising"},{"label":"C","text":"rising | falling"},{"label":"D","text":"rising | rising"}],"correct":""},{"id":22,"text":"The table shows statistics for four countries, A-D. Which country has the lowest standard of living?","options":[{"label":"A","text":"1.9 | 19 | 46 | 190"},{"label":"B","text":"2.7 | 2 | 58 | 1700"},{"label":"C","text":"3.7 | 45 | 59 | 210"},{"label":"D","text":"4.2 | 89 | 44 | 190"}],"correct":""},{"id":23,"text":"Malaysia and Indonesia specialise in the production of palm oil. What is a disadvantage of specialisation?","options":[{"label":"A","text":"concentration of labour in the activity in which it is most productive"},{"label":"B","text":"creation of jobs to meet world demand"},{"label":"C","text":"reliance on trade with other countries for other goods"},{"label":"D","text":"rising palm oil prices"}],"correct":""},{"id":24,"text":"The diagram shows China's trade with Brazil for two years. What happened to China's trade balance with Brazil between year 1 and year 2?","options":[{"label":"A","text":"It experienced a falling surplus."},{"label":"B","text":"It experienced a rising deficit."},{"label":"C","text":"It moved from deficit to surplus."},{"label":"D","text":"It moved from surplus to deficit."}],"correct":"","image":"/images/econ-mcq/203_389_1269_1020_299_0.jpg"},{"id":25,"text":"What is a reason for trade protection?","options":[{"label":"A","text":"to reduce a deficit on the current account of the balance of payments"},{"label":"B","text":"to reduce a surplus on the current account of the balance of payments"},{"label":"C","text":"to reduce economic growth"},{"label":"D","text":"to reduce inflation"}],"correct":""},{"id":26,"text":"What is an immediate effect for a country of a fall in its foreign exchange rate?","options":[{"label":"A","text":"a fall in the money supply"},{"label":"B","text":"an increase in purchasing power"},{"label":"C","text":"cheaper imports"},{"label":"D","text":"more competitive exports"}],"correct":""}];

const paper_22: MCQQuestion[] = [{"id":1,"text":"The Chinese government is concerned about the level of poverty and the need for more resources in low-income regions of the country. As a result, it is increasing its expenditure in those regions and reducing it in high-income regions. Which economic concept does this government policy illustrate?","options":[{"label":"A","text":"diseconomies of scale"},{"label":"B","text":"market forces"},{"label":"C","text":"opportunity cost"},{"label":"D","text":"specialisation"}],"correct":""},{"id":2,"text":"An airline needs people and equipment. These can be divided into factors of production. What is allocated to its correct factor of production?","options":[{"label":"A","text":"aircraft | capital"},{"label":"B","text":"airline owners | labour"},{"label":"C","text":"computer network | land"},{"label":"D","text":"pilots | enterprise"}],"correct":""},{"id":3,"text":"The diagram shows a production possibility curve (PPC) for country Z. Government policy is to move the economy from point X to point Y on the PPC. What is the most likely effect of this policy?","options":[{"label":"A","text":"Living standards rise in the short run."},{"label":"B","text":"More capital goods are produced."},{"label":"C","text":"Prices of consumer goods increase."},{"label":"D","text":"Total output increases."}],"correct":"","image":"/images/econ-mcq/205_685_1261_427_409_0.jpg"},{"id":4,"text":"The table shows examples of changes in an economy. Which combination has two microeconomic changes?","options":[{"label":"A","text":"an increase in the rate of inflation | a rise in the average earnings of healthcare professionals"},{"label":"B","text":"an increase in the rate of inflation | a rise in the rate of unemployment"},{"label":"C","text":"a reduction in output in the car industry | a rise in the average earnings of healthcare professionals"},{"label":"D","text":"a reduction in output in the car industry | a rise in the rate of unemployment"}],"correct":""},{"id":5,"text":"The diagram shows the supply of motor vehicles. What will cause a shift in the supply curve from \\( {S}_{1} \\) to \\( {S}_{2} \\) ?","options":[{"label":"A","text":"a decrease in the profits of suppliers"},{"label":"B","text":"a fall in the real incomes of customers"},{"label":"C","text":"a more efficient assembly line using robots"},{"label":"D","text":"a rise in the cost of motor vehicle components"}],"correct":"","image":"/images/econ-mcq/206_646_880_501_403_0.jpg"},{"id":6,"text":"The diagram shows the demand for and supply of plastic bags. The original equilibrium price is P. How would the introduction of a unit tax on plastic bags be shown?","options":[{"label":"A","text":"Demand would shift to \\( {\\mathrm{D}}_{2} \\) ."},{"label":"B","text":"Demand would shift to \\( {\\mathrm{D}}_{3} \\) ."},{"label":"C","text":"Supply would shift to \\( {\\mathrm{S}}_{2} \\) ."},{"label":"D","text":"Supply would shift to \\( {\\mathrm{S}}_{3} \\) ."}],"correct":"","image":"/images/econ-mcq/207_584_303_625_536_0.jpg"},{"id":7,"text":"What is the significance to firms of price elasticity of demand?","options":[{"label":"A","text":"It allows firms to measure the effect of a change in the price of their competitors."},{"label":"B","text":"It allows firms to measure their ability to change production due to a change in price."},{"label":"C","text":"It allows firms to predict the change in costs of production."},{"label":"D","text":"It allows firms to predict the effect of a change in price on their total revenue."}],"correct":""},{"id":8,"text":"In a free market, market failure causes a misallocation of resources. What is not an example of market failure?","options":[{"label":"A","text":"external costs of production"},{"label":"B","text":"internal diseconomies of scale"},{"label":"C","text":"over-consumption of demerit goods"},{"label":"D","text":"under-consumption of merit goods"}],"correct":""},{"id":9,"text":"Which organisations can directly fund the growth of firms?","options":[{"label":"A","text":"no | yes | no"},{"label":"B","text":"no | yes | yes"},{"label":"C","text":"yes | no | no"},{"label":"D","text":"yes | no | yes"}],"correct":""},{"id":10,"text":"Which advantage do coins have that makes them more suitable than paper banknotes to act as money?","options":[{"label":"A","text":"They are more divisible."},{"label":"B","text":"They are more durable."},{"label":"C","text":"They are more portable."},{"label":"D","text":"They are more recognisable."}],"correct":""},{"id":11,"text":"Which statement about different income groups is correct?","options":[{"label":"A","text":"High-income groups do not need to borrow money."},{"label":"B","text":"High-income groups save less money than low-income groups."},{"label":"C","text":"Low-income groups find it easier to borrow than high-income groups."},{"label":"D","text":"Low-income groups save a smaller percentage of their income than high-income groups."}],"correct":""},{"id":12,"text":"A musician has a choice of playing for an orchestra in either Germany or England. Which combination of incomes and cost of living is most likely to cause her to choose the German orchestra?","options":[{"label":"A","text":"higher | higher | higher"},{"label":"B","text":"higher | lower | lower"},{"label":"C","text":"lower | higher | higher"},{"label":"D","text":"lower | higher | lower"}],"correct":""},{"id":13,"text":"A firm sells 50 units at a price of \\$3 per product. What is the firm's total revenue and average revenue?","options":[{"label":"A","text":"50 | 3"},{"label":"B","text":"50 | 50"},{"label":"C","text":"150 | 3"},{"label":"D","text":"150 | 50"}],"correct":""},{"id":14,"text":"A firm produces bicycles. It uses a combination of workers and machines. The table shows the output from different combinations of workers and machines. Which combination shows the greatest labour productivity?","options":[{"label":"A","text":"4 | 5 | 17"},{"label":"B","text":"8 | 5 | 32"},{"label":"C","text":"10 | 5 | 45"},{"label":"D","text":"20 | 5 | 76"}],"correct":""},{"id":15,"text":"Two large-scale firms involved in chemical manufacturing wish to merge. Why might the government decide to prevent the merger?","options":[{"label":"A","text":"It enables greater economies of scale to operate."},{"label":"B","text":"It increases productivity per worker employed."},{"label":"C","text":"It reduces competition in the industry."},{"label":"D","text":"It results in higher wages paid to labour."}],"correct":""},{"id":16,"text":"What is included in a government budget calculation?","options":[{"label":"A","text":"export revenue"},{"label":"B","text":"external costs"},{"label":"C","text":"indirect tax revenue"},{"label":"D","text":"opportunity cost"}],"correct":""},{"id":17,"text":"Which change is an example of monetary policy?","options":[{"label":"A","text":"a depreciation of the foreign exchange rate"},{"label":"B","text":"a reduction of unemployment benefits"},{"label":"C","text":"an increased import tax"},{"label":"D","text":"the introduction of import quotas"}],"correct":""},{"id":18,"text":"What is the most likely effect of increasing the rate of interest?","options":[{"label":"A","text":"Investment increases."},{"label":"B","text":"The cost of government borrowing falls."},{"label":"C","text":"The exchange rate falls."},{"label":"D","text":"The rate of inflation falls."}],"correct":""},{"id":19,"text":"What is the most effective way for a government to raise national output?","options":[{"label":"A","text":"encourage a period of deflation"},{"label":"B","text":"improve the productivity of resources"},{"label":"C","text":"limit the size of its population"},{"label":"D","text":"restrict its trade with other countries"}],"correct":""},{"id":20,"text":"The table shows real GDP and population for four countries. Which country has the highest real GDP per head?","options":[{"label":"A","text":"200 | 80"},{"label":"B","text":"100 | 25"},{"label":"C","text":"80 | 50"},{"label":"D","text":"60 | 12"}],"correct":""},{"id":21,"text":"A shop worker was made redundant due to the introduction of self-service checkouts. Which type of unemployment is this?","options":[{"label":"A","text":"cyclical"},{"label":"B","text":"frictional"},{"label":"C","text":"seasonal"},{"label":"D","text":"structural"}],"correct":""},{"id":22,"text":"A decrease in which variable is most likely to cause the rate of inflation to increase?","options":[{"label":"A","text":"the average wage rate"},{"label":"B","text":"the budget deficit"},{"label":"C","text":"the interest rate"},{"label":"D","text":"the money supply"}],"correct":""},{"id":23,"text":"Which type of goods have to be financed by a government?","options":[{"label":"A","text":"capital goods"},{"label":"B","text":"demerit goods"},{"label":"C","text":"free goods"},{"label":"D","text":"public goods"}],"correct":""},{"id":24,"text":"The table shows the percentage changes in earnings and consumer prices for four countries for one year. Which country is likely to have experienced the greatest increase in real income during the year?","options":[{"label":"A","text":"France | +6.5 | +3.5"},{"label":"B","text":"Germany | +4.0 | +4.0"},{"label":"C","text":"Japan | +4.0 | -1.0"},{"label":"D","text":"UK | +6.5 | - 2.0"}],"correct":""},{"id":25,"text":"The table shows the Human Development Index (HDI) for a country in two years. What would not explain the changes in the HDI?","options":[{"label":"A","text":"an increase in gender equality"},{"label":"B","text":"an increase in income per head"},{"label":"C","text":"an increase in life expectancy"},{"label":"D","text":"an increase in years of schooling"}],"correct":"","table":"<table><tr><td>year</td><td>HDI value</td></tr><tr><td>1</td><td>0.467</td></tr><tr><td>2</td><td>0.609</td></tr></table>"},{"id":26,"text":"The table shows the percentage (%) contribution of agriculture to the GDP of three countries in a year. What can be concluded from the table?","options":[{"label":"A","text":"Agricultural production in country Z was not as productive as it was in country Y."},{"label":"B","text":"Country X was likely to be less developed as a country than country Z."},{"label":"C","text":"Country Y was likely to import more agricultural produce than country Z."},{"label":"D","text":"Total agricultural production was higher in country X than in country Z."}],"correct":"","table":"<table><tr><td>country</td><td>%</td></tr><tr><td>X</td><td>18.5</td></tr><tr><td>Y</td><td>3.9</td></tr><tr><td>Z</td><td>2.2</td></tr></table>"},{"id":27,"text":"The table shows some details from a country's balance of payments that has no secondary income (current transfers). What is the country's balance on its current account?","options":[{"label":"A","text":"a deficit of \\$60 million"},{"label":"B","text":"a deficit of \\$160 million"},{"label":"C","text":"a surplus of \\$20 million"},{"label":"D","text":"a surplus of \\$760 million"}],"correct":"","table":"<table><tr><td>item</td><td>\\$ million</td></tr><tr><td>exports of goods</td><td>280</td></tr><tr><td>imports of goods</td><td>350</td></tr><tr><td>exports of services</td><td>110</td></tr><tr><td>imports of services</td><td>60</td></tr><tr><td>net primary income</td><td>-40</td></tr></table>"},{"id":28,"text":"Vietnamese companies buy insurance from companies in the US. How will this transaction be recorded in the Vietnamese balance of payments?","options":[{"label":"A","text":"trade in goods | credit"},{"label":"B","text":"trade in services | credit"},{"label":"C","text":"trade in services | debit"},{"label":"D","text":"current transfers | debit"}],"correct":""},{"id":29,"text":"Which row shows the potential benefits of free trade to consumers, producers and the economy?","options":[{"label":"A","text":"higher income | lower costs | deflation"},{"label":"B","text":"lower quality | higher prices | greater equality"},{"label":"C","text":"lower prices | increased competition | higher current account deficit"},{"label":"D","text":"more choices | larger market | lower unemployment"}],"correct":""},{"id":30,"text":"A manufacturing firm in a low-income country has decided to close. What is most likely to have caused this decision?","options":[{"label":"A","text":"increase in foreign multinational companies operating in its country"},{"label":"B","text":"increase in global demand for its products"},{"label":"C","text":"increase in its productivity"},{"label":"D","text":"increase in subsidies received from its government"}],"correct":""}];

const paper_23: MCQQuestion[] = [{"id":1,"text":"Economists describe resources as being 'scarce'. What must be a consequence of scarce resources?","options":[{"label":"A","text":"production will cause external costs"},{"label":"B","text":"relative poverty will gradually increase"},{"label":"C","text":"sustainable development will take place"},{"label":"D","text":"wants will exceed productive capacity"}],"correct":""},{"id":2,"text":"A hospital has spent all of its budget allocated for employing doctors. What is the opportunity cost to the hospital of employing an extra doctor?","options":[{"label":"A","text":"a reduction in the number of nurses employed"},{"label":"B","text":"an improvement in the recovery rate of patients"},{"label":"C","text":"an increase in the number of patients treated"},{"label":"D","text":"the salary paid to the extra doctor"}],"correct":""},{"id":3,"text":"There has been an increase in the demand for wheat. This has led to an increase in the demand for labour to harvest the wheat. Which branch of economics covers these two concepts?","options":[{"label":"A","text":"macroeconomics | macroeconomics"},{"label":"B","text":"macroeconomics | microeconomics"},{"label":"C","text":"microeconomics | macroeconomics"},{"label":"D","text":"microeconomics | microeconomics"}],"correct":""},{"id":4,"text":"In the United Kingdom (UK), the price of timber used in house building increased. This was because of a boom in the UK house building industry and a shortage of drivers to deliver the timber. What happened in the UK market for timber to cause this price increase?","options":[{"label":"A","text":"shifted left | shifted left"},{"label":"B","text":"shifted left | shifted right"},{"label":"C","text":"shifted right | shifted left"},{"label":"D","text":"shifted right | shifted right"}],"correct":""},{"id":5,"text":"What does a supply curve show?","options":[{"label":"A","text":"A firm will supply more when consumers' purchasing power increases."},{"label":"B","text":"The higher the price, the fewer goods are supplied as costs of production increase."},{"label":"C","text":"The lower the price, the more profit is made by the firm."},{"label":"D","text":"There is a positive relationship between quantity supplied and price."}],"correct":""},{"id":6,"text":"What is a disadvantage of a market economy?","options":[{"label":"A","text":"not enough competition"},{"label":"B","text":"not enough merit goods"},{"label":"C","text":"no consumer choice"},{"label":"D","text":"state intervention"}],"correct":""},{"id":7,"text":"Droughts in some countries caused the supply of wheat to fall. Wheat prices then rose providing an opportunity for wheat producers in other countries to increase supply. Why might the price of wheat continue to be high in the year following the drought?","options":[{"label":"A","text":"Different weather conditions allowed a bumper harvest."},{"label":"B","text":"Suppliers unaffected by drought failed to increase output."},{"label":"C","text":"The government introduced a subsidy to wheat producers."},{"label":"D","text":"The wheat market returned to its original equilibrium."}],"correct":""},{"id":8,"text":"Newly built houses tend to be inelastic in supply. A government aim is to make the supply more elastic by relaxing building regulations. Why is the government not likely to achieve this aim immediately?","options":[{"label":"A","text":"Banks will only lend to high-income earners."},{"label":"B","text":"Costs of building materials fluctuate according to season."},{"label":"C","text":"Houses take a long period of time to be built."},{"label":"D","text":"Population increases lead to greater housing demand."}],"correct":""},{"id":9,"text":"A person planning for old age saves in the form of money rather than goods. Which function does money perform when this is done?","options":[{"label":"A","text":"medium of exchange"},{"label":"B","text":"standard of deferred payment"},{"label":"C","text":"store of value"},{"label":"D","text":"unit of account"}],"correct":""},{"id":10,"text":"What is not normally a function of the central bank of a country?","options":[{"label":"A","text":"acting as lender of last resort"},{"label":"B","text":"issuing notes and coins"},{"label":"C","text":"operating the government monetary policy"},{"label":"D","text":"setting the government budget"}],"correct":""},{"id":11,"text":"What is a trade union most likely to protect?","options":[{"label":"A","text":"the profit of a firm"},{"label":"B","text":"the rights of a group of workers"},{"label":"C","text":"the satisfaction of consumers"},{"label":"D","text":"the social welfare of everybody"}],"correct":""},{"id":12,"text":"A person sets up a street food stall. What is necessary for the food stall to survive in the long run?","options":[{"label":"A","text":"no | no"},{"label":"B","text":"no | yes"},{"label":"C","text":"yes | no"},{"label":"D","text":"yes | yes"}],"correct":""},{"id":13,"text":"A large privately owned firm is the sole supplier of electricity to a city. Which combination of characteristics is likely to exist for this firm?","options":[{"label":"A","text":"high | high | price maker"},{"label":"B","text":"high | low | price taker"},{"label":"C","text":"low | high | price maker"},{"label":"D","text":"low | low | price taker"}],"correct":""},{"id":14,"text":"The government of country Z announces a forecast budget deficit of \\$234 billion, as part of its fiscal policy. What is the effect of this forecast budget deficit likely to be?","options":[{"label":"A","text":"a decrease in economic growth"},{"label":"B","text":"a decrease in inflation"},{"label":"C","text":"an increase in employment"},{"label":"D","text":"an increase in unemployment"}],"correct":""},{"id":15,"text":"Low-income groups do not pay income tax but are able to use state-provided healthcare services. What does this illustrate?","options":[{"label":"A","text":"monetary policy"},{"label":"B","text":"privatisation"},{"label":"C","text":"redistribution of income"},{"label":"D","text":"regressive taxation"}],"correct":""},{"id":16,"text":"The government uses monetary policy and reduces the interest rate. What might be a consequence of this?","options":[{"label":"A","text":"a decrease in the rate of inflation"},{"label":"B","text":"an increase in the level of investment"},{"label":"C","text":"an increase in the level of savings"},{"label":"D","text":"an increase in unemployment"}],"correct":""},{"id":17,"text":"What is a likely objective of supply-side policy?","options":[{"label":"A","text":"improving productive potential"},{"label":"B","text":"increasing direct taxation"},{"label":"C","text":"increasing the power of trade unions"},{"label":"D","text":"promoting the public sector"}],"correct":""},{"id":18,"text":"An increase in which economic indicator best describes economic growth?","options":[{"label":"A","text":"general price level"},{"label":"B","text":"level of consumption"},{"label":"C","text":"level of output"},{"label":"D","text":"living standards"}],"correct":""},{"id":19,"text":"What is full employment considered to be?","options":[{"label":"A","text":"no cyclical unemployment"},{"label":"B","text":"no frictional unemployment"},{"label":"C","text":"no private sector unemployment"},{"label":"D","text":"no seasonal unemployment"}],"correct":""},{"id":20,"text":"Which group is most likely to benefit during a period of rapid inflation?","options":[{"label":"A","text":"exporters"},{"label":"B","text":"pensioners"},{"label":"C","text":"people with debts"},{"label":"D","text":"savers"}],"correct":""},{"id":21,"text":"What are the components of the Human Development Index (HDI)?","options":[{"label":"A","text":"life expectancy at birth, expected years of schooling, gross national income (GNI)"},{"label":"B","text":"life expectancy at birth, expected years of schooling, gross national income (GNI) per head"},{"label":"C","text":"population growth, adult literacy rate, gross national income (GNI) per head"},{"label":"D","text":") population size, expected years of schooling, number of doctors per head"}],"correct":""},{"id":22,"text":"Which situation must produce an ageing population?","options":[{"label":"A","text":"a falling birth rate and a falling death rate"},{"label":"B","text":"a rising birth rate and a rising death rate"},{"label":"C","text":"a rising marriage rate and a falling death rate"},{"label":"D","text":"a falling marriage rate and a rising death rate"}],"correct":""},{"id":23,"text":"The table shows the unemployment rate in three developed economies in one year. What is the main cause of high rates of unemployment in developed economies in periods of recession?","options":[{"label":"A","text":"decreases in total demand"},{"label":"B","text":"movement of labour between countries"},{"label":"C","text":"reduced levels of technological change"},{"label":"D","text":"regional inequalities of wealth"}],"correct":"","table":"<table><tr><td></td><td>unemployment rate %</td></tr><tr><td>United States</td><td>7.6</td></tr><tr><td>Sweden</td><td>8.2</td></tr><tr><td>France</td><td>10.9</td></tr></table>"},{"id":24,"text":"What is most likely to result from an extension of specialisation in manufacturing?","options":[{"label":"A","text":"for the consumer some prices will be reduced"},{"label":"B","text":"for the country there will be less dependency on international trade"},{"label":"C","text":"for the employee the work will become more varied"},{"label":"D","text":"for the producer there will be less efficiency"}],"correct":""},{"id":25,"text":"A country imposes a tariff on an imported product. What is the effect of this change?","options":[{"label":"A","text":"no | no"},{"label":"B","text":"no | yes"},{"label":"C","text":"yes | no"},{"label":"D","text":"yes | yes"}],"correct":""},{"id":26,"text":"The world demand for oil is price-inelastic and oil is paid for in US dollars. If the price of oil falls rapidly, how might it affect the US dollar?","options":[{"label":"A","text":"greater demand for US\\$ | increases"},{"label":"B","text":"greater supply of US\\$ | decreases"},{"label":"C","text":"less demand for US\\$ | decreases"},{"label":"D","text":"less supply of US\\$ | increases"}],"correct":""},{"id":27,"text":"Which benefit do multinational companies (MNCs) bring to their home country?","options":[{"label":"A","text":"flow of profits"},{"label":"B","text":"higher wages"},{"label":"C","text":"increased employment"},{"label":"D","text":"more investment"}],"correct":""}];

const paper_24: MCQQuestion[] = [{"id":1,"text":"Which statement is correct?","options":[{"label":"A","text":"Economic goods are not scarce."},{"label":"B","text":"Economic goods have no opportunity cost."},{"label":"C","text":"Free goods are scarce."},{"label":"D","text":"Free goods have no opportunity cost."}],"correct":""},{"id":2,"text":"The economy of country X is always on its production possibility curve (PPC). When will the goods and services produced by country X become more scarce?","options":[{"label":"A","text":"shifts left | increases"},{"label":"B","text":"shifts right | unchanged"},{"label":"C","text":"unchanged | decreases"},{"label":"D","text":"unchanged | unchanged"}],"correct":""},{"id":3,"text":"What is capital?","options":[{"label":"A","text":"the ability to organise the factors of production"},{"label":"B","text":"the energy used in production"},{"label":"C","text":"the factory used in production"},{"label":"D","text":"the money invested in a firm"}],"correct":""},{"id":4,"text":"What are features of a market economy?","options":[{"label":"A","text":"no | no | yes"},{"label":"B","text":"no | yes | yes"},{"label":"C","text":"yes | no | no"},{"label":"D","text":"yes | yes | yes"}],"correct":""},{"id":5,"text":"Public transport and cars are substitute goods. The price of public transport rises. What will happen to the demand for cars?","options":[{"label":"A","text":"It will contract."},{"label":"B","text":"It will extend."},{"label":"C","text":"It will decrease."},{"label":"D","text":"It will increase."}],"correct":""},{"id":6,"text":"The markets of four products are all in equilibrium. The table gives the value of the price elasticity of supply (PES) for each product. The demand for each product shifts to the right by 5000 units at all prices. Which product will have the largest price increase?","options":[{"label":"A","text":"0"},{"label":"B","text":"0.6"},{"label":"C","text":"1.0"},{"label":"D","text":"2.5"}],"correct":""},{"id":7,"text":"What is the value of the price elasticity of demand (PED) for a product if total revenue remains the same when the price is reduced?","options":[{"label":"A","text":"zero"},{"label":"B","text":"between 0 and 1"},{"label":"C","text":"greater than 1"},{"label":"D","text":"1"}],"correct":""},{"id":8,"text":"The owner of a hotel in Malaysia finds that the price elasticity of demand (PED) for accommodation in the area is -1.7. If the hotel owner decreases the price of a room by 5%, how would the demand for a room change?","options":[{"label":"A","text":"It would decrease by 2.9%."},{"label":"B","text":"It would decrease by 8.5%."},{"label":"C","text":"It would increase by 2.9%."},{"label":"D","text":"It would increase by 8.5%."}],"correct":""},{"id":9,"text":"Good weather results in an increase in the demand for tomatoes. It also increases the supply of tomatoes. What must be a result of this?","options":[{"label":"A","text":"The price of tomatoes will fall."},{"label":"B","text":"The price of tomatoes will rise."},{"label":"C","text":"The quantity of tomatoes traded will fall."},{"label":"D","text":"The quantity of tomatoes traded will rise."}],"correct":""},{"id":10,"text":"What causes a change in the price of a product in a free market economy?","options":[{"label":"A","text":"changes in demand and supply conditions"},{"label":"B","text":"changes in external costs and external benefits"},{"label":"C","text":"changes in government decisions"},{"label":"D","text":"changes in the quantity of public goods"}],"correct":""},{"id":11,"text":"The ways of making and receiving payments continue to develop. Payments can now be made using smartphones, as well as cash, debit cards and credit cards. Which method of paying for products provides no information to sellers about their customers?","options":[{"label":"A","text":"cash"},{"label":"B","text":"debit cards"},{"label":"C","text":"credit cards"},{"label":"D","text":"smartphones"}],"correct":""},{"id":12,"text":"In most countries, which organisation controls the banking system?","options":[{"label":"A","text":"central bank"},{"label":"B","text":"commercial bank"},{"label":"C","text":"investment bank"},{"label":"D","text":"World Bank"}],"correct":""},{"id":13,"text":"What is not a reason for differences in the earnings of airline pilots in a particular country?","options":[{"label":"A","text":"bargaining power of employees"},{"label":"B","text":"discrimination"},{"label":"C","text":"government policies"},{"label":"D","text":"inflation"}],"correct":""},{"id":14,"text":"An airline takes over an online clothing company. What is an advantage of such a move by the airline?","options":[{"label":"A","text":"to diversify their operations"},{"label":"B","text":"to generate economies of scale"},{"label":"C","text":"to improve lines of communication"},{"label":"D","text":"to increase market share"}],"correct":""},{"id":15,"text":"In which type of industry is a firm most likely to make a large profit in the short run and in the long run?","options":[{"label":"A","text":"many | high"},{"label":"B","text":"many | low"},{"label":"C","text":"one | high"},{"label":"D","text":"one | low"}],"correct":""},{"id":16,"text":"What is an example of government macroeconomic policy?","options":[{"label":"A","text":"increasing the money supply"},{"label":"B","text":"preventing price rises in the food industry"},{"label":"C","text":"removing a monopoly's barriers to entry"},{"label":"D","text":"setting a maximum price for wheat"}],"correct":""},{"id":17,"text":"Why would devaluing the international value of an economy's currency help reduce unemployment?","options":[{"label":"A","text":"Devaluing the currency would increase the cost of production."},{"label":"B","text":"Devaluing the currency would increase the confidence of investors."},{"label":"C","text":"Devaluing the currency would increase the foreign demand for domestic products."},{"label":"D","text":"Devaluing the currency would increase the demand for imports."}],"correct":""},{"id":18,"text":"What is likely to happen when the rate of interest increases?","options":[{"label":"A","text":"consumer spending increases"},{"label":"B","text":"firms buy fewer machines"},{"label":"C","text":"people hold more cash"},{"label":"D","text":"savers earn lower rewards"}],"correct":""},{"id":19,"text":"What is not a supply-side policy measure?","options":[{"label":"A","text":"control of trade union power"},{"label":"B","text":"higher indirect taxation"},{"label":"C","text":"privatisation"},{"label":"D","text":"skills training for workers"}],"correct":""},{"id":20,"text":"The table shows the real GDP per head for a country in 2021 and 2022. What is most likely to have changed between 2021 and 2022?","options":[{"label":"A","text":"Incomes were distributed more evenly."},{"label":"B","text":"There was more activity in the informal economy."},{"label":"C","text":"The living standards of some people improved."},{"label":"D","text":"The rate of inflation increased."}],"correct":"","table":"<table><tr><td>2021</td><td>2022</td></tr><tr><td>\\$20000</td><td>\\$21000</td></tr></table>"},{"id":21,"text":"Which change to fiscal policy is most likely to reduce cyclical unemployment in an economy?","options":[{"label":"A","text":"increasing direct taxation"},{"label":"B","text":"increasing the budget deficit"},{"label":"C","text":"increasing the budget surplus"},{"label":"D","text":"increasing the money supply"}],"correct":""},{"id":22,"text":"What must have happened in a country when it experienced an annual rate of inflation of 100%?","options":[{"label":"A","text":"The money supply doubled."},{"label":"B","text":"The price level halved."},{"label":"C","text":"The purchasing power of money halved."},{"label":"D","text":"The real value of money doubled."}],"correct":""},{"id":23,"text":"The Human Development Index (HDI) can be used to measure human development in countries. Which measure would not be part of its calculation?","options":[{"label":"A","text":"inequality of incomes"},{"label":"B","text":"life expectancy"},{"label":"C","text":"gross national income per head"},{"label":"D","text":"years of schooling"}],"correct":""},{"id":24,"text":"What is the most likely consequence of an ageing population for a high-income economy?","options":[{"label":"A","text":"There will be a fall in the dependency ratio."},{"label":"B","text":"There will be a fall in the level of immigration."},{"label":"C","text":"There will be an increase in geographic mobility."},{"label":"D","text":"There will be an increase in spending on healthcare."}],"correct":""},{"id":25,"text":"In some developing countries a large percentage of the population is involved in subsistence farming. What can be concluded from this?","options":[{"label":"A","text":"Each family will be able to produce enough to live on."},{"label":"B","text":"Production is unlikely to be capital intensive."},{"label":"C","text":"Production will be efficient."},{"label":"D","text":"There will be a high level of trade."}],"correct":""},{"id":26,"text":"A small country whose only export is oil decides to reduce substantially the rate at which it extracts its limited oil reserves. What is the most likely reason for this decision?","options":[{"label":"A","text":"to improve the balance of payments in the following year"},{"label":"B","text":"to increase current government income"},{"label":"C","text":"to maintain future living standards"},{"label":"D","text":"to raise the level of employment in the oil industry"}],"correct":""},{"id":27,"text":"Country X believes that country Y is selling steel at prices below the average cost of production. So, country X imposes a higher tariff on steel imports from country Y. What does country X hope to achieve by imposing this higher tariff?","options":[{"label":"A","text":"avoid country X dumping steel in country Y"},{"label":"B","text":"avoid country Y dumping steel in country X"},{"label":"C","text":"reduce inflation in country \\( X \\)"},{"label":"D","text":"reduce inflation in country \\( Y \\)"}],"correct":""},{"id":28,"text":"Which factor would cause a country's exchange rate to fall?","options":[{"label":"A","text":"Demand for imports increases."},{"label":"B","text":"Domestic interest rates rise."},{"label":"C","text":"Domestic savings increase."},{"label":"D","text":"More tourists visit the country."}],"correct":""},{"id":29,"text":"Many European firms employ workers from the Philippines. These workers send part of their income to relatives in the Philippines. In which part of the balance of payments current account for the Philippines would these transactions be recorded?","options":[{"label":"A","text":"primary income"},{"label":"B","text":"secondary income"},{"label":"C","text":"trade in goods"},{"label":"D","text":"trade in services"}],"correct":""}];

const paper_25: MCQQuestion[] = [{"id":1,"text":"A consumer has \\$10 to spend. A meal costs \\$9 and a drink costs \\$5. What would describe the situation if the consumer did not have enough money to purchase both the meal and the drink?","options":[{"label":"A","text":"excess demand"},{"label":"B","text":"free goods"},{"label":"C","text":"market failure"},{"label":"D","text":"the economic problem"}],"correct":""},{"id":2,"text":"The diagram shows a production possibility curve (PPC) for a country. The country moved from position \\( X \\) to position \\( Y \\) on the PPC. What is the most likely reason for this change?","options":[{"label":"A","text":"Firms have decided to increase investment in technology."},{"label":"B","text":"New economic resources have been discovered in the country."},{"label":"C","text":"The government has brought about an increase in living standards."},{"label":"D","text":"The government has encouraged long-term economic growth."}],"correct":"","image":"/images/econ-mcq/230_608_779_582_415_0.jpg"},{"id":3,"text":"Which type of factor of production is a railway track?","options":[{"label":"A","text":"capital"},{"label":"B","text":"enterprise"},{"label":"C","text":"labour"},{"label":"D","text":"land"}],"correct":""},{"id":4,"text":"Which statement must be correct if a market is in disequilibrium?","options":[{"label":"A","text":"Quantity demanded and quantity supplied are equal."},{"label":"B","text":"The government must intervene if anything is to be sold."},{"label":"C","text":"There can be no changes to demand or supply."},{"label":"D","text":"There is excess supply or excess demand."}],"correct":""},{"id":5,"text":"What is a determinant of price elasticity of demand (PED)?","options":[{"label":"A","text":"availability of stocks of the product"},{"label":"B","text":"change in the income of consumers"},{"label":"C","text":"degree of necessity of the product"},{"label":"D","text":"existence of monopoly"}],"correct":""},{"id":6,"text":"What would cause the supply curve for an agricultural product to shift to the right?","options":[{"label":"A","text":"an increase in the costs of production"},{"label":"B","text":"an increase in the price of substitutes"},{"label":"C","text":"an increase in the price of the good"},{"label":"D","text":"an increase in the productivity of farms"}],"correct":""},{"id":7,"text":"What would increase the price elasticity of supply (PES) of a product?","options":[{"label":"A","text":"an increase in the cost of inputs"},{"label":"B","text":"an increase in the firm's profits"},{"label":"C","text":"an increase in the number of close substitutes"},{"label":"D","text":"an increase in the time a product can be stored"}],"correct":""},{"id":8,"text":"The diagram shows a demand curve. What does the movement from \\( \\mathrm{X} \\) to \\( \\mathrm{Y} \\) show?","options":[{"label":"A","text":"a decrease in quantity demanded due to an increase in price"},{"label":"B","text":"a decrease in quantity demanded due to changes in the conditions of demand"},{"label":"C","text":"an increase in quantity demanded due to changes in the conditions of demand"},{"label":"D","text":"an increase in quantity demanded due to an increase in price"}],"correct":"","image":"/images/econ-mcq/232_631_249_536_453_0.jpg"},{"id":9,"text":"In a market there is a surplus of a good. Which change would cause the market to come to an equilibrium?","options":[{"label":"A","text":"a decrease in demand"},{"label":"B","text":"a fall in price"},{"label":"C","text":"a rise in price"},{"label":"D","text":"an increase in supply"}],"correct":""},{"id":10,"text":"When the price of a good is \\$10, the quantity demanded is 100 units per day. Which combination of price change and price elasticity of demand will cause the largest increase in the quantity demanded for the good?","options":[{"label":"A","text":"price falls to \\$9 | 0.8"},{"label":"B","text":"price falls to \\$9 | 1.2"},{"label":"C","text":"price rises to \\$11 | 0.8"},{"label":"D","text":"price rises to \\$11 | 1.2"}],"correct":""},{"id":11,"text":"A function of money is to act as a measure of value. What does this mean?","options":[{"label":"A","text":"It is used for future savings."},{"label":"B","text":"It is used to compare the worth of different goods."},{"label":"C","text":"It is used to enable monthly payments for expensive goods."},{"label":"D","text":"It is used to pay the price of a good."}],"correct":""},{"id":12,"text":"In 2008-2009 the central bank of a developed country reduced interest rates from 5% to 0.5% per year to stimulate the economy. How would this policy have affected the amount saved and the cost of borrowing by individuals?","options":[{"label":"A","text":"decreased | decreased"},{"label":"B","text":"decreased | increased"},{"label":"C","text":"increased | decreased"},{"label":"D","text":"increased | increased"}],"correct":""},{"id":13,"text":"Many small energy providers have closed down due to rising costs. What is the likely effect of this on the price of energy and choice of energy providers for consumers, assuming there is no government intervention?","options":[{"label":"A","text":"decreases | decreases"},{"label":"B","text":"decreases | increases"},{"label":"C","text":"increases | decreases"},{"label":"D","text":"increases | increases"}],"correct":""},{"id":14,"text":"What is the most likely goal of a state-owned enterprise providing health services?","options":[{"label":"A","text":"profits"},{"label":"B","text":"public satisfaction"},{"label":"C","text":"sales revenue"},{"label":"D","text":"survival"}],"correct":""},{"id":15,"text":"Some governments allow monopoly markets to exist. What is a reason for this?","options":[{"label":"A","text":"to attract entry into the market"},{"label":"B","text":"to fund research and development"},{"label":"C","text":"to increase prices for consumers"},{"label":"D","text":"to maximise monopoly profits"}],"correct":""},{"id":16,"text":"A government increases its revenue by higher direct taxation of both personal incomes and company profits. What is most likely to be the reason for this increase?","options":[{"label":"A","text":"to control spending on specific consumer goods"},{"label":"B","text":"to encourage business investment"},{"label":"C","text":"to provide public and merit goods"},{"label":"D","text":"to reduce pollution from industrial production"}],"correct":""},{"id":17,"text":"Income tax in a country gives all individuals an initial tax-free income allowance. Any income above this allowance is taxed at increasing rates as the incomes of individuals rise. Which change to this income tax will be regressive?","options":[{"label":"A","text":"decreasing the lowest rate of tax"},{"label":"B","text":"decreasing the tax-free income allowance"},{"label":"C","text":"increasing the tax-free income allowance"},{"label":"D","text":"increasing the top rate of tax"}],"correct":""},{"id":18,"text":"A government lowers the rate of interest. Who is most likely to be disadvantaged by this policy?","options":[{"label":"A","text":"house buyers"},{"label":"B","text":"manufacturers"},{"label":"C","text":"retailers"},{"label":"D","text":"savers"}],"correct":""},{"id":19,"text":"What is a supply-side policy measure?","options":[{"label":"A","text":"a tariff on imported goods"},{"label":"B","text":"an increase in indirect taxes"},{"label":"C","text":"a contractionary monetary policy"},{"label":"D","text":"the removal of barriers to entry to a market"}],"correct":""},{"id":20,"text":"What is the most likely consequence of economic growth?","options":[{"label":"A","text":"more equal income distribution"},{"label":"B","text":"more use of resources"},{"label":"C","text":"reduced imports"},{"label":"D","text":"reduced tax revenue"}],"correct":""},{"id":21,"text":"In high-income economies, cereal farming is highly productive but few workers are employed. What could have caused this employment situation?","options":[{"label":"A","text":"a fall in world demand for cereals"},{"label":"B","text":"a lack of capital equipment"},{"label":"C","text":"increased mechanisation of agriculture"},{"label":"D","text":"large-scale migration from rural areas"}],"correct":""},{"id":22,"text":"Who is most likely to benefit during a period of inflation?","options":[{"label":"A","text":"creditors (lenders)"},{"label":"B","text":"debtors (borrowers)"},{"label":"C","text":"fixed income earners"},{"label":"D","text":"holders of cash"}],"correct":""},{"id":23,"text":"The table shows some economic indicators. Which increase in the first indicator is most likely to lead to an increase in the second indicator?","options":[{"label":"A","text":"budget surplus | consumer saving"},{"label":"B","text":"consumer spending | unemployment"},{"label":"C","text":"inflation | trade surplus"},{"label":"D","text":"productivity | living standards"}],"correct":""},{"id":24,"text":"Which combination would be most likely to increase the population of a country?","options":[{"label":"A","text":"high | high | positive"},{"label":"B","text":"high | low | positive"},{"label":"C","text":"low | high | negative"},{"label":"D","text":"low | low | negative"}],"correct":""},{"id":25,"text":"Which economic consequence is most likely to result from an increasing proportion of the population being over the age of 65?","options":[{"label":"A","text":"Government transfer payments will increase."},{"label":"B","text":"More facilities will be needed to retrain workers."},{"label":"C","text":"The total savings in the economy will increase."},{"label":"D","text":"There will be a rise in the economic growth rate."}],"correct":""},{"id":26,"text":"What is most likely to encourage international specialisation?","options":[{"label":"A","text":"similarities in climate in different countries"},{"label":"B","text":"the ability to produce products more cheaply than other countries"},{"label":"C","text":"the discovery of oil in a country that had no oil before"},{"label":"D","text":"very high international transport costs"}],"correct":""},{"id":27,"text":"Country X established free trade agreements with other nations. What would be the intended benefit of such agreements to country X?","options":[{"label":"A","text":"increased labour shortages"},{"label":"B","text":"increased tariff revenue"},{"label":"C","text":"more efficient allocation of resources"},{"label":"D","text":"protection from low wage competition"}],"correct":""},{"id":28,"text":"A country's foreign exchange rate appreciates significantly. Which group in the country will directly benefit from this change?","options":[{"label":"A","text":"a government department which only buys locally made goods"},{"label":"B","text":"retailers who get all their supplies from foreign producers"},{"label":"C","text":"workers in local companies that compete with foreign firms in the local market"},{"label":"D","text":"workers in local companies that sell only in foreign countries"}],"correct":""},{"id":29,"text":"What is measured in the secondary income balance in a country's current account of the balance of payments?","options":[{"label":"A","text":"net contributions to international and regional organisations"},{"label":"B","text":"net exports of goods and services"},{"label":"C","text":"net foreign investment flows"},{"label":"D","text":"net inflow of income from factors of production abroad"}],"correct":""}];

const paper_26: MCQQuestion[] = [{"id":1,"text":"What has an opportunity cost in consumption?","options":[{"label":"A","text":"air"},{"label":"B","text":"food"},{"label":"C","text":"sea water"},{"label":"D","text":"sunlight"}],"correct":""},{"id":2,"text":"In which case is it possible to set the level of reward before production takes place for the first factor of production but not for the second factor?","options":[{"label":"A","text":"capital | land"},{"label":"B","text":"enterprise | labour"},{"label":"C","text":"labour | capital"},{"label":"D","text":"land | enterprise"}],"correct":""},{"id":3,"text":"The diagram shows the production possibility curve (PPC) for an economy. Which cost can be determined as the economy moves along its PPC from point X to point Y?","options":[{"label":"A","text":"the opportunity cost of producing more capital goods"},{"label":"B","text":"the opportunity cost of producing more consumer goods"},{"label":"C","text":"the social cost of producing more capital goods"},{"label":"D","text":"the social cost of producing more consumer goods"}],"correct":"","image":"/images/econ-mcq/239_577_1118_642_457_0.jpg"},{"id":4,"text":"Which person is most likely to make a microeconomic decision as part of their job?","options":[{"label":"A","text":"a government finance minister"},{"label":"B","text":"the global administrator of the Human Development Index"},{"label":"C","text":"the governor of the central bank"},{"label":"D","text":"the manager of a private sector firm"}],"correct":""},{"id":5,"text":"What necessarily describes the market system?","options":[{"label":"A","text":"all resources used to produce consumer goods"},{"label":"B","text":"an economy with both a private and a public sector"},{"label":"C","text":"limited resources but unlimited wants"},{"label":"D","text":"resources allocated through demand and supply"}],"correct":""},{"id":6,"text":"Why does a government provide certain goods and services in a mixed economic system?","options":[{"label":"A","text":"The government always provides goods more cheaply than private firms."},{"label":"B","text":"The government considers only private costs and private benefits."},{"label":"C","text":"The government provides goods to prevent the development of monopolies."},{"label":"D","text":"The government provides public goods because private firms cannot charge for them."}],"correct":""},{"id":7,"text":"A government intends to subsidise bus fares and increase taxes on private motoring. How would this affect the private cost of transport?","options":[{"label":"A","text":"decrease | decrease"},{"label":"B","text":"decrease | increase"},{"label":"C","text":"increase | decrease"},{"label":"D","text":"increase | increase"}],"correct":""},{"id":8,"text":"What is not a function of money?","options":[{"label":"A","text":"medium of exchange"},{"label":"B","text":"portability"},{"label":"C","text":"store of value"},{"label":"D","text":"unit of account"}],"correct":""},{"id":9,"text":"Bus drivers receive a wage of \\$15000 a year. The government introduces a national minimum wage. Under which circumstances will the largest number of bus drivers become unemployed as a result of the minimum wage?","options":[{"label":"A","text":"15000 | increasing"},{"label":"B","text":"15000 | unchanged"},{"label":"C","text":"18000 | increasing"},{"label":"D","text":"18000 | unchanged"}],"correct":""},{"id":10,"text":"A clothes retailer borrows money to finance the opening of another clothes shop. Which type of growth is this?","options":[{"label":"A","text":"internal and horizontal"},{"label":"B","text":"internal and vertical"},{"label":"C","text":"external and horizontal"},{"label":"D","text":"external and vertical"}],"correct":""},{"id":11,"text":"What is meant by internal diseconomies of scale?","options":[{"label":"A","text":"average cost for the firm decreases when the output of the firm increases"},{"label":"B","text":"average cost for the firm decreases when the output of the industry increases"},{"label":"C","text":"average cost for the firm increases when the output of the firm increases"},{"label":"D","text":"average cost for the firm increases when the output of the industry increases"}],"correct":""},{"id":12,"text":"A food-processing firm decides to change from a labour-intensive production method to a capital-intensive production method. What is likely to decrease as a result of the change?","options":[{"label":"A","text":"fixed costs as a percentage of total cost"},{"label":"B","text":"output per worker per hour"},{"label":"C","text":"the level of total output"},{"label":"D","text":"variable costs as a percentage of total cost"}],"correct":""},{"id":13,"text":"What is an example of a fixed cost?","options":[{"label":"A","text":"electricity"},{"label":"B","text":"insurance"},{"label":"C","text":"Craw materials"},{"label":"D","text":"wages"}],"correct":""},{"id":14,"text":"What is the definition of profit maximisation?","options":[{"label":"A","text":"The firm is allocating a proportion of profit to other business objectives."},{"label":"B","text":"The firm is making as much profit as possible."},{"label":"C","text":"The firm is making higher levels of profit this year than last year."},{"label":"D","text":"The firm is making the same amount of profit this year as last year."}],"correct":""},{"id":15,"text":"The central bank of Mexico set its rate of interest to try to keep the rise in the price level to only 3%. Which government aim was it directly trying to achieve?","options":[{"label":"A","text":"balance of payments equilibrium"},{"label":"B","text":"economic growth"},{"label":"C","text":"full employment"},{"label":"D","text":"low inflation"}],"correct":""},{"id":16,"text":"The table shows a forecast for a government budget for year 1 and for year 2. What does the forecast government budget for year 2 show?","options":[{"label":"A","text":"The budget deficit decreased when compared with year 1."},{"label":"B","text":"The budget deficit increased when compared with year 1."},{"label":"C","text":"The budget surplus decreased when compared with year 1."},{"label":"D","text":"The budget surplus increased when compared with year 1."}],"correct":"","table":"<table><tr><td></td><td>year 1 \\$bn</td><td>year 2 \\$bn</td></tr><tr><td>revenue</td><td>50</td><td>55</td></tr><tr><td>spending</td><td>60</td><td>60</td></tr></table>"},{"id":17,"text":"The graph shows the impact of a tax on the supply of petrol (gas). What can be concluded from this graph?","options":[{"label":"A","text":"The government will receive no tax revenue."},{"label":"B","text":"The impact of the tax will be shared between the consumer and the producer."},{"label":"C","text":"The impact of the tax will fall entirely upon the consumer."},{"label":"D","text":"The impact of the tax will fall entirely on the producer."}],"correct":"","image":"/images/econ-mcq/243_636_1390_527_392_0.jpg"},{"id":18,"text":"What is most likely to result from a successful supply-side policy?","options":[{"label":"A","text":"a deterioration in the current account of the balance of payments"},{"label":"B","text":"economic growth"},{"label":"C","text":"increased inflation"},{"label":"D","text":") increased structural unemployment"}],"correct":""},{"id":19,"text":"The table shows the rates of unemployment and real GDP growth for an economy in year 1 and year 2. Which combination of policy measures would be most effective in returning the economy to the year 1 level of activity?","options":[{"label":"A","text":"a decrease in direct taxes and an increase in the rate of interest"},{"label":"B","text":"a decrease in government expenditure and an increase in the rate of interest"},{"label":"C","text":"an increase in direct taxes and a decrease in the rate of interest"},{"label":"D","text":"an increase in government expenditure and a decrease in the rate of interest"}],"correct":"","table":"<table><tr><td></td><td>year 1</td><td>year 2</td></tr><tr><td>rate of unemployment (%)</td><td>3</td><td>7</td></tr><tr><td>rate of real GDP growth (%)</td><td>3</td><td>-1</td></tr></table>"},{"id":20,"text":"The table shows selected indicators for the labour market of an economy in year 1 and year 2. According to the table, what is the most likely type of unemployment in year 2?","options":[{"label":"A","text":"cyclical"},{"label":"B","text":"frictional"},{"label":"C","text":"seasonal"},{"label":"D","text":"structural"}],"correct":"","table":"<table><tr><td></td><td>year 1 (millions)</td><td>year 2 (millions)</td></tr><tr><td>total labour force</td><td>30</td><td>30</td></tr><tr><td>employed workers</td><td>25</td><td>28</td></tr><tr><td>long-term unemployed</td><td>1</td><td>2</td></tr><tr><td>employment in manufacturing</td><td>4</td><td>2</td></tr><tr><td>employment in services</td><td>13</td><td>16</td></tr></table>"},{"id":21,"text":"The table shows the percentage changes in earnings and consumer prices for four countries in one year. Which country has experienced the greatest increase in real income during the year?","options":[{"label":"A","text":"+12.5 | +9.5"},{"label":"B","text":"+4.0 | +2.0"},{"label":"C","text":"+8.5 | +5.0"},{"label":"D","text":"+4.0 | +4.0"}],"correct":""},{"id":22,"text":"The table shows the distribution of income as measured by GDP for three countries in a year. What can be concluded from the table?","options":[{"label":"A","text":"The lowest 20% of households in the US have lower incomes than the lowest 20% of households in Mexico."},{"label":"B","text":"The lowest 40% of households in Belgium receive a larger share of the country's income than the highest 20% of households."},{"label":"C","text":"The distribution of income is most equal in Belgium."},{"label":"D","text":"The highest 20% of households in the US receive half of the country's income."}],"correct":"","table":"<table><tr><td rowspan=\"2\"></td><td colspan=\"5\">percentage of GDP received by each 20% of households</td></tr><tr><td>highest 20%</td><td>second highest 20%</td><td>middle 20%</td><td>second lowest 20%</td><td>lowest 20%</td></tr><tr><td>Belgium</td><td>36.4</td><td>22.4</td><td>18.0</td><td>14.3</td><td>8.9</td></tr><tr><td>Mexico</td><td>51.7</td><td>20.0</td><td>13.5</td><td>9.4</td><td>5.4</td></tr><tr><td>US</td><td>46.9</td><td>22.4</td><td>15.3</td><td>10.3</td><td>5.1</td></tr></table>"},{"id":23,"text":"The number of people in relative poverty in a country is decreasing. What is the most likely cause of this?","options":[{"label":"A","text":"a contractionary fiscal policy"},{"label":"B","text":"a decrease in the national minimum wage"},{"label":"C","text":"an expansion of investment in education"},{"label":"D","text":"an increase in barriers to entry for multinational companies"}],"correct":""},{"id":24,"text":"African economies may have rapid economic growth because of a large increase in their working age population. Based on this idea, which factor of production is most likely to grow significantly?","options":[{"label":"A","text":"labour"},{"label":"B","text":"enterprise"},{"label":"C","text":"capital"},{"label":"D","text":"land"}],"correct":""},{"id":25,"text":"Which statement shows two benefits for consumers from specialisation at a national level?","options":[{"label":"A","text":"decreased prices and better quality"},{"label":"B","text":"decreased profits and high-quality raw materials"},{"label":"C","text":"increased choice and high transport costs"},{"label":"D","text":"increased productivity and increased economies of scale"}],"correct":""},{"id":26,"text":"A multinational company (MNC) opens up a new factory in a host country. What is a possible cost of this new factory to the host country?","options":[{"label":"A","text":"increased access to modern technology"},{"label":"B","text":"increased competition for host-country industries"},{"label":"C","text":"increased employment for workers"},{"label":"D","text":"increased tax revenue for the government"}],"correct":""},{"id":27,"text":"The diagram shows the change in the exchange rate market for country X's \\$. Which change in country X would have caused this?","options":[{"label":"A","text":"a fall in its international competitiveness"},{"label":"B","text":"a fall in its level of interest rates"},{"label":"C","text":"a rise in its exports of services"},{"label":"D","text":"a rise in its imports of goods"}],"correct":"","image":"/images/econ-mcq/247_628_1046_545_446_0.jpg"},{"id":28,"text":"What is the most likely cause of an increased current account surplus in a country?","options":[{"label":"A","text":"lower prices for the country's exports"},{"label":"B","text":"higher exchange rate for the country"},{"label":"C","text":"economic growth in the country"},{"label":"D","text":"recession in trade-partner countries"}],"correct":""}];

const paper_27: MCQQuestion[] = [{"id":1,"text":"Which economic question is least likely to arise as a result of scarcity?","options":[{"label":"A","text":"For whom will we produce?"},{"label":"B","text":"How will we produce?"},{"label":"C","text":"What will we produce?"},{"label":"D","text":"When will we produce?"}],"correct":""},{"id":2,"text":"What is opportunity cost?","options":[{"label":"A","text":"the allocation of resources in an economy"},{"label":"B","text":"the cost to the individual when they consume a good"},{"label":"C","text":"the lack of goods and services available to satisfy unlimited wants"},{"label":"D","text":"the next best alternative forgone when making an economic decision"}],"correct":""},{"id":3,"text":"A period of bad weather leads to a failure of the rice crop. What is the effect on the market for rice?","options":[{"label":"A","text":"a shortage of rice and a fall in its price"},{"label":"B","text":"a shortage of rice and a rise in its price"},{"label":"C","text":"a surplus of rice and a fall in its price"},{"label":"D","text":"a surplus of rice and a rise in its price"}],"correct":""},{"id":4,"text":"The diagram shows a change in demand for coffee. What would cause the demand for coffee to change from \\( {D}_{1} \\) to \\( {D}_{2} \\) ?","options":[{"label":"A","text":"a good coffee harvest"},{"label":"B","text":"a rise in the price of substitute drinks"},{"label":"C","text":"a rise in the wages of coffee workers"},{"label":"D","text":") a successful advertising campaign for tea"}],"correct":"","image":"/images/econ-mcq/250_529_248_740_442_0.jpg"},{"id":5,"text":"The table shows the supply for a product at different prices. If the price changes from \\$12 to \\$14, what will be the change in supply?","options":[{"label":"A","text":"Supply will contract by 40 units and there will be a movement down along the supply curve."},{"label":"B","text":"Supply will contract by 200 units and there will be an inward shift of the supply curve."},{"label":"C","text":"Supply will extend by 40 units and there will be a movement up along the supply curve."},{"label":"D","text":"Supply will extend by 200 units and there will be an outward shift of the supply curve."}],"correct":"","table":"<table><tr><td>price (\\$)</td><td>supply (units)</td></tr><tr><td>10</td><td>120</td></tr><tr><td>12</td><td>160</td></tr><tr><td>14</td><td>200</td></tr><tr><td>16</td><td>240</td></tr><tr><td>18</td><td>280</td></tr></table>"},{"id":6,"text":"Which changes would move the equilibrium in the diagram from point X to point Z?","options":[{"label":"A","text":"a decrease in demand with a decrease in supply"},{"label":"B","text":"a decrease in demand with an increase in supply"},{"label":"C","text":"an increase in demand with a decrease in supply"},{"label":"D","text":"an increase in demand with an increase in supply"}],"correct":"","image":"/images/econ-mcq/251_577_250_642_501_0.jpg"},{"id":7,"text":"When the price of shirts rises from \\$8 to \\$10, the demand for shirts falls from 1000 to 500. What is the value of the price elasticity of demand for shirts?","options":[{"label":"A","text":"greater than 1"},{"label":"B","text":"unitary"},{"label":"C","text":"less than 1"},{"label":"D","text":"zero"}],"correct":""},{"id":8,"text":"A government intends to build a new international airport in an area of outstanding natural beauty. What would be an external cost of this decision?","options":[{"label":"A","text":"the cost of importing construction materials"},{"label":"B","text":"the enjoyment lost by those unable to use the countryside"},{"label":"C","text":"the increase in profits for local businesses"},{"label":"D","text":"the wages paid to the construction workers"}],"correct":""},{"id":9,"text":"What is an important role of a central bank?","options":[{"label":"A","text":"attempts to achieve price stability"},{"label":"B","text":"issues credit cards"},{"label":"C","text":"provides loans to producers"},{"label":"D","text":"provides savings accounts for consumers"}],"correct":""},{"id":10,"text":"How would a change in the demand for labour affect the labour market in an occupation?","options":[{"label":"A","text":"decrease | decrease | extend"},{"label":"B","text":"decrease | increase | contract"},{"label":"C","text":"increase | decrease | contract"},{"label":"D","text":"increase | increase | extend"}],"correct":""},{"id":11,"text":"A fast-food multinational bought a food-ordering website, in order to allow the multinational's customers to download menus and make advance payments. Which term best describes this merger?","options":[{"label":"A","text":"backward vertical"},{"label":"B","text":"conglomerate"},{"label":"C","text":"forward vertical"},{"label":"D","text":"horizontal"}],"correct":""},{"id":12,"text":"The diagram shows the average total cost (ATC) for a firm, in the long run. What would cause the shift from \\( {\\mathrm{{ATC}}}_{1} \\) to \\( {\\mathrm{{ATC}}}_{2} \\) ?","options":[{"label":"A","text":"difficulties in controlling the firm"},{"label":"B","text":"external economies of scale"},{"label":"C","text":"managerial economies of scale"},{"label":"D","text":"technical economies of scale"}],"correct":"","image":"/images/econ-mcq/253_632_250_538_440_0.jpg"},{"id":13,"text":"What is most likely to encourage capital-intensive production methods in a low-income economy?","options":[{"label":"A","text":"expensive capital equipment costs"},{"label":"B","text":"grants from foreign aid programmes"},{"label":"C","text":"supplies of local low-cost labour"},{"label":"D","text":"- a shortage of highly trained supervisors"}],"correct":""},{"id":14,"text":"A firm's average revenue is \\$20. It sells 1000 units. What are the firm's total revenue and the price of the product?","options":[{"label":"A","text":"20 | 20"},{"label":"B","text":"1000 | 50"},{"label":"C","text":"20000 | 20"},{"label":"D","text":"20000 | 50"}],"correct":""},{"id":15,"text":"A competitive industry becomes a monopoly. What is the most likely advantage for consumers?","options":[{"label":"A","text":"consumer choice may increase"},{"label":"B","text":"economies of scale may reduce prices"},{"label":"C","text":"more goods may be produced"},{"label":"D","text":"prices may be set by market forces"}],"correct":""},{"id":16,"text":"What will cause real GDP to rise in a country?","options":[{"label":"A","text":"nominal GDP rising at a faster rate than employment"},{"label":"B","text":"nominal GDP rising faster than inflation"},{"label":"C","text":"nominal GDP rising faster than the population"},{"label":"D","text":"nominal GDP rising"}],"correct":""},{"id":17,"text":"What is the money supply?","options":[{"label":"A","text":"the total quantity of foreign currency available within the economy"},{"label":"B","text":"the total quantity of money available within the economy"},{"label":"C","text":"the total quantity of money issued by the central bank"},{"label":"D","text":"the total quantity of money within commercial banks"}],"correct":""},{"id":18,"text":"Which macroeconomic policy is most likely to achieve economic growth and price stability at the same time?","options":[{"label":"A","text":"fiscal policy"},{"label":"B","text":"import barriers"},{"label":"C","text":"monetary policy"},{"label":"D","text":"supply-side policy"}],"correct":""},{"id":19,"text":"What is the definition of economic growth?","options":[{"label":"A","text":"It is an increase in the general level of prices over time."},{"label":"B","text":"It is an increase in the level of a nation's output over time."},{"label":"C","text":"It is an increase in the level of total demand over time."},{"label":"D","text":"It is an increase in wages, interest, profits and rent over time."}],"correct":""},{"id":20,"text":"What causes cyclical unemployment in a recession?","options":[{"label":"A","text":"a permanent decrease in the demand for labour"},{"label":"B","text":"a permanent decrease in the supply of labour"},{"label":"C","text":"a temporary decrease in the demand for labour"},{"label":"D","text":"a temporary decrease in the supply of labour"}],"correct":""},{"id":21,"text":"The table shows government expenditure and revenue in selected years. What might explain the changes in the government's budget over the period?","options":[{"label":"A","text":"a fall in the dependency ratio"},{"label":"B","text":"a fall in the exchange rate"},{"label":"C","text":"an increase in cyclical unemployment"},{"label":"D","text":"an increase in real GDP"}],"correct":"","table":"<table><tr><td>year</td><td>government expenditure \\$bn</td><td>tax revenue \\$bn</td></tr><tr><td>1</td><td>500</td><td>500</td></tr><tr><td>2</td><td>600</td><td>400</td></tr><tr><td>3</td><td>700</td><td>300</td></tr></table>"},{"id":22,"text":"The table shows changes in economic policies for four countries, A, B, C and D. Which country is most likely to be following a policy of preventing deflation?","options":[{"label":"A","text":"decreasing | decreasing | decreasing"},{"label":"B","text":"decreasing | decreasing | increasing"},{"label":"C","text":"increasing | increasing | decreasing"},{"label":"D","text":"increasing | increasing | increasing"}],"correct":""},{"id":23,"text":"Workers in Switzerland earn more on average than workers in Mexico. What is a likely cause of this?","options":[{"label":"A","text":"A greater percentage of workers in Switzerland work part-time than in Mexico."},{"label":"B","text":"The average worker in Switzerland is more productive than the average worker in Mexico."},{"label":"C","text":"The average worker in Switzerland pays more income tax than the average worker in Mexico."},{"label":"D","text":"The unemployment rate is higher in Switzerland than in Mexico."}],"correct":""},{"id":24,"text":"The table contains details on birth rate, death rate and net migration for several countries in a year. What can be concluded from the table?","options":[{"label":"A","text":"Only one country, Nigeria, had a decreasing population."},{"label":"B","text":"The country with the lowest birth rate had the lowest death rate."},{"label":"C","text":"The country with the lowest death rate had the highest birth rate."},{"label":"D","text":"The country with the lowest natural rate of increase in population was the US."}],"correct":"","table":"<table><tr><td></td><td>birth rate</td><td>death rate</td><td>net migration</td></tr><tr><td>Australia</td><td>13</td><td>7</td><td>850000</td></tr><tr><td>Brazil</td><td>14</td><td>6</td><td>30000</td></tr><tr><td>Nigeria</td><td>39</td><td>12</td><td>-300000</td></tr><tr><td>US</td><td>12</td><td>8</td><td>4 500000</td></tr></table>"},{"id":25,"text":"Which combination best describes the characteristics of a high-income economy?","options":[{"label":"A","text":"high | high | high"},{"label":"B","text":"high | high | low"},{"label":"C","text":"low | low | high"},{"label":"D","text":"low | low | low"}],"correct":""},{"id":26,"text":"What might encourage international specialisation between countries?","options":[{"label":"A","text":"free trade"},{"label":"B","text":"inefficiencies in production"},{"label":"C","text":"labour immobility"},{"label":"D","text":"tariffs"}],"correct":""},{"id":27,"text":"A government wishes to stop the dumping of a specific imported good at a very low price. Which method of protection would be most effective?","options":[{"label":"A","text":"apply an embargo to this good"},{"label":"B","text":"devalue the currency"},{"label":"C","text":"increase interest rates"},{"label":"D","text":"provide subsidies to home producers of this good"}],"correct":""},{"id":28,"text":"The price of the US dollar in terms of other currencies is set by the forces of demand and supply. To what does this statement refer?","options":[{"label":"A","text":"an alternative method of trade protection"},{"label":"B","text":"the determination of the exchange rate in a fixed exchange rate system"},{"label":"C","text":"the determination of the exchange rate in a floating exchange rate system"},{"label":"D","text":"the increasing globalisation of international trade"}],"correct":""}];

const paper_28: MCQQuestion[] = [{"id":1,"text":"Consumers and producers face the same problem of satisfying wants. What is the most likely reason wants cannot be satisfied?","options":[{"label":"A","text":"consumers and producers cannot establish an equilibrium price"},{"label":"B","text":"consumers have excess choice when producers oversupply"},{"label":"C","text":"consumers have limited income and producers have finite resources"},{"label":"D","text":"consumers lack information to buy and producers lack motivation to supply"}],"correct":""},{"id":2,"text":"A worker decides to leave their job as a bus driver and take a job as a lorry driver. What will increase the opportunity cost of this decision?","options":[{"label":"A","text":"an increase in the holidays for lorry drivers"},{"label":"B","text":"an increase in the income tax paid by bus drivers"},{"label":"C","text":"an increase in the wages of bus drivers"},{"label":"D","text":"an increase in the wages of lorry drivers"}],"correct":""},{"id":3,"text":"The diagram shows a country's production possibility curve (PPC). What would cause a movement from point X to point Y?","options":[{"label":"A","text":"decrease in productivity"},{"label":"B","text":"decrease in unemployment"},{"label":"C","text":"increase in capital investment"},{"label":"D","text":"increase in economic growth"}],"correct":"","image":"/images/econ-mcq/259_709_1121_591_438_0.jpg"},{"id":4,"text":"The price of petrol increases in a country with a market economic system. What is a consequence of this?","options":[{"label":"A","text":"More cars are bought."},{"label":"B","text":"The costs of road transport increase."},{"label":"C","text":"The quantity of petrol supplied falls."},{"label":"D","text":"There is a shortage of petrol."}],"correct":""},{"id":5,"text":"What determines a consumer's demand for a product?","options":[{"label":"A","text":"✓ | ✓ | ✓"},{"label":"B","text":"✓ | ✓ | ✘"},{"label":"C","text":"✘ | ✓ | ✓"},{"label":"D","text":"✓ | ✘ | ✓"}],"correct":""},{"id":6,"text":"The price elasticity of demand (PED) of a good is -1 . What will happen to both demand and total revenue as price increases?","options":[{"label":"A","text":"demand will fall and total revenue will not change"},{"label":"B","text":"demand will fall and total revenue will rise"},{"label":"C","text":"demand will rise and total revenue will not change"},{"label":"D","text":"demand will rise and total revenue will rise"}],"correct":""},{"id":7,"text":"Which pair of economic institutions can be found in a market economy?","options":[{"label":"A","text":"charities and public sector firms"},{"label":"B","text":"multinational companies and commercial banks"},{"label":"C","text":"public sector firms and private sector firms"},{"label":"D","text":"stock exchanges and government-funded hospitals"}],"correct":""},{"id":8,"text":"The table shows the weekly demand for, and supply of, good X at three prices. What will be the effect if the government imposes a minimum price of \\$40 per tonne?","options":[{"label":"A","text":"a fall in the price of \\( X \\)"},{"label":"B","text":"a shortage of \\( X \\)"},{"label":"C","text":"a surplus of \\( X \\)"},{"label":"D","text":"no change in the market equilibrium"}],"correct":"","table":"<table><tr><td>price (\\$)</td><td>demand (tonnes)</td><td>supply (tonnes)</td></tr><tr><td>20</td><td>16</td><td>10</td></tr><tr><td>30</td><td>12</td><td>12</td></tr><tr><td>40</td><td>10</td><td>14</td></tr></table>"},{"id":9,"text":"What is the function of money when it is used to value goods and record transactions?","options":[{"label":"A","text":"a medium of exchange"},{"label":"B","text":"a standard of deferred payment"},{"label":"C","text":"a store of wealth"},{"label":"D","text":"a unit of account"}],"correct":""},{"id":10,"text":"The wages of school teachers are rising. What is least likely to be the cause of this?","options":[{"label":"A","text":"decreased membership of teaching trade unions"},{"label":"B","text":"increased awareness among parents about the importance of education"},{"label":"C","text":"more restrictions on the immigration of teachers from other countries"},{"label":"D","text":"the opening of new schools by the government"}],"correct":""},{"id":11,"text":"What is a feature of every trade union?","options":[{"label":"A","text":"members are unskilled workers"},{"label":"B","text":"members use collective bargaining"},{"label":"C","text":"members work for the same employer"},{"label":"D","text":"members work in the same industry"}],"correct":""},{"id":12,"text":"What must occur if a firm experiences economies of scale?","options":[{"label":"A","text":"average costs decrease"},{"label":"B","text":"profits decrease"},{"label":"C","text":"the number of workers increases"},{"label":"D","text":"total advertising costs decrease"}],"correct":""},{"id":13,"text":"If the average revenue of a firm increases from \\$4 to \\$5 and quantity demanded decreases from 20 units to 10 units, what will be the effect on the firm's total revenue?","options":[{"label":"A","text":"decreases by \\$20"},{"label":"B","text":"decreases by \\$30"},{"label":"C","text":"increases by \\$20"},{"label":"D","text":"increases by \\$30"}],"correct":""},{"id":14,"text":"What are two macroeconomic aims of government?","options":[{"label":"A","text":"to allocate resources and reduce trade union membership"},{"label":"B","text":"to create economic growth and prevent high inflation"},{"label":"C","text":"to raise interest rates and reduce pollution"},{"label":"D","text":") to reduce exports and increase imports"}],"correct":""},{"id":15,"text":"A government's spending currently equals its revenue. The government decides to decrease its spending. What is the most likely effect of this in the short run?","options":[{"label":"A","text":"a budget deficit"},{"label":"B","text":"a budget surplus"},{"label":"C","text":"an increase in output"},{"label":"D","text":"an increase in tax revenue"}],"correct":""},{"id":16,"text":"What is not a monetary policy measure?","options":[{"label":"A","text":"changes in income tax rates"},{"label":"B","text":"changes in interest rates"},{"label":"C","text":"changes in the exchange rate"},{"label":"D","text":"changes in the money supply"}],"correct":""},{"id":17,"text":"Which government action would not be included as part of a supply-side policy?","options":[{"label":"A","text":"increasing the privatisation of industries"},{"label":"B","text":"lowering national minimum wage rates"},{"label":"C","text":"raising tariffs on international trade"},{"label":"D","text":"reducing state benefits"}],"correct":""},{"id":18,"text":"An economy operating on its production possibility curve (PPC) enters a recession that causes unemployment. As the recession gets worse some unemployed workers emigrate in search of jobs overseas. How are these effects of the recession shown on a diagram of the economy's PPC in the short-term and the long-term?","options":[{"label":"A","text":"movement to a point inside the PPC | movement to a point inside the PPC"},{"label":"B","text":"movement to a point inside the PPC | shift of PPC to the left"},{"label":"C","text":"shift of PPC to the left | movement to a point inside the PPC"},{"label":"D","text":"shift of PPC to the left | shift of PPC to the left"}],"correct":""},{"id":19,"text":"Chile specialises in the production of copper for export. In what way is the Chilean economy likely to be affected by a large rise in the supply of copper from other countries?","options":[{"label":"A","text":"fall | fall"},{"label":"B","text":"fall | rise"},{"label":"C","text":"rise | fall"},{"label":"D","text":"rise | rise"}],"correct":""},{"id":20,"text":"The table shows the patterns of employment in selected industries in two years. How did the patterns of employment change between year 1 and year 2?","options":[{"label":"A","text":"fell | rose"},{"label":"B","text":"fell | unchanged"},{"label":"C","text":"rose | fell"},{"label":"D","text":"unchanged | rose"}],"correct":"","table":"<table><tr><td rowspan=\"2\">industry</td><td colspan=\"2\">employment in millions</td></tr><tr><td>year 1</td><td>year 2</td></tr><tr><td>agriculture</td><td>8</td><td>6</td></tr><tr><td>fishing</td><td>4</td><td>4</td></tr><tr><td>hospitality</td><td>8</td><td>10</td></tr><tr><td>manufacturing</td><td>12</td><td>10</td></tr><tr><td>retailing</td><td>8</td><td>10</td></tr><tr><td>total</td><td>40</td><td>40</td></tr></table>"},{"id":21,"text":"What is deflation?","options":[{"label":"A","text":"a sustained fall in total demand"},{"label":"B","text":"a sustained fall in the general price level"},{"label":"C","text":"a sustained fall in the rate of inflation"},{"label":"D","text":"a sustained fall in the value of money"}],"correct":""},{"id":22,"text":"What is most likely to cause more poverty in a country?","options":[{"label":"A","text":"a decrease in the general price level"},{"label":"B","text":"a decrease in the rate of income tax"},{"label":"C","text":"a decrease in the level of unemployment"},{"label":"D","text":"- a decrease in the level of wages"}],"correct":""},{"id":23,"text":"The charts show the population structure of a country in year X and year X + 50. During this period, how did birth and death rates change?","options":[{"label":"A","text":"fell | fell"},{"label":"B","text":"fell | no change"},{"label":"C","text":"rose | fell"},{"label":"D","text":"rose | no change"}],"correct":"","image":"/images/econ-mcq/266_405_613_1205_869_0.jpg"},{"id":24,"text":"What is an advantage for consumers from international specialisation?","options":[{"label":"A","text":"competition between firms results in lower prices"},{"label":"B","text":"labour can move more freely between countries"},{"label":"C","text":"less wealth is created throughout the world"},{"label":"D","text":"multinational companies can increase their profits"}],"correct":""},{"id":25,"text":"Which government policy would encourage greater international trade?","options":[{"label":"A","text":"an increase in the level of domestic regulation"},{"label":"B","text":"an increase in the level of tariffs on imports"},{"label":"C","text":"the abolition of domestic subsidies for declining industries"},{"label":"D","text":"the abolition of free trade agreements"}],"correct":""},{"id":26,"text":"What is most likely to directly result from a persistent and large current account surplus on the balance of payments of a country?","options":[{"label":"A","text":"a lower exchange rate"},{"label":"B","text":"a lower standard of living"},{"label":"C","text":"an increase in gross domestic product"},{"label":"D","text":"an increase in the unemployment rate"}],"correct":""}];

const paper_29: MCQQuestion[] = [{"id":1,"text":"A government wants to build a new hospital. What is most likely to prevent the government from doing this?","options":[{"label":"A","text":"People in the country cannot afford healthcare."},{"label":"B","text":"People in the country would go abroad for healthcare."},{"label":"C","text":"The government cannot agree how big the hospital should be."},{"label":"D","text":"The government does not have enough money."}],"correct":""},{"id":2,"text":"Which term describes the loss of potential benefit to a consumer when making a choice between alternatives?","options":[{"label":"A","text":"opportunity cost"},{"label":"B","text":"scarcity"},{"label":"C","text":"shortage"},{"label":"D","text":"the economic problem"}],"correct":""},{"id":3,"text":"Which combination gives correct examples of macroeconomics and microeconomics?","options":[{"label":"A","text":"study of demand for a product | study of price of a product"},{"label":"B","text":"study of behaviour of firms | study of individual behaviour"},{"label":"C","text":"study of the economy as a whole | study of specific markets"},{"label":"D","text":"study of the international economy | study of the national economy"}],"correct":""},{"id":4,"text":"The diagram shows the supply and demand curves for a good. The initial market equilibrium is given at point \\( {E}_{1} \\) . There is a change in the market that leads to a new equilibrium at \\( {E}_{2} \\) . What is the cause of the change in the market equilibrium?","options":[{"label":"A","text":"a decrease in the price of a substitute good"},{"label":"B","text":"a decrease in raw material prices"},{"label":"C","text":"an increase in the price of a substitute good"},{"label":"D","text":") an increase in raw material prices"}],"correct":"","image":"/images/econ-mcq/270_569_752_663_513_0.jpg"},{"id":5,"text":"The diagram shows the demand curve for a good. What can be concluded about a single downward-sloping demand curve?","options":[{"label":"A","text":"consumers increase demand when their incomes rise"},{"label":"B","text":"consumers plan to buy less when prices rise"},{"label":"C","text":"firms produce less as prices rise"},{"label":"D","text":"firms sell more when prices rise"}],"correct":"","image":"/images/econ-mcq/271_644_250_510_431_0.jpg"},{"id":6,"text":"How are economic decisions determined in a market economic system?","options":[{"label":"A","text":"by a mixture of market forces and government intervention"},{"label":"B","text":"by central planners of production and consumption"},{"label":"C","text":"by government regulation of the price mechanism"},{"label":"D","text":"by the forces of demand and supply"}],"correct":""},{"id":7,"text":"A bridge is built over a river which enables journey times to be reduced. The table shows costs and benefits of building the bridge. Which calculation represents social benefit?","options":[{"label":"A","text":"\\$12000 - \\$10000 = \\$2000"},{"label":"B","text":"\\$8000 - \\$5000 = \\$3000"},{"label":"C","text":"\\$12000 + \\$5000 = \\$17000"},{"label":"D","text":"\\$8000 + \\$12000 = \\$20000"}],"correct":"","table":"<table><tr><td></td><td>\\$000</td></tr><tr><td>private benefit</td><td>12</td></tr><tr><td>private cost</td><td>10</td></tr><tr><td>external benefit</td><td>8</td></tr><tr><td>external cost</td><td>5</td></tr></table>"},{"id":8,"text":"What is not a role of the central bank?","options":[{"label":"A","text":"to act as the lender of last resort"},{"label":"B","text":"to hold deposits from the general public"},{"label":"C","text":"to issue notes and coins"},{"label":"D","text":"to manage the gold reserves of the country"}],"correct":""},{"id":9,"text":"The table shows the proportion of disposable income spent on three different goods by four different households. Which household is likely to have the lowest income?","options":[{"label":"A","text":"50 | 15 | 5"},{"label":"B","text":"35 | 18 | 10"},{"label":"C","text":"30 | 20 | 15"},{"label":"D","text":"20 | 25 | 20"}],"correct":""},{"id":10,"text":"In which occupations do wages tend to be lowest?","options":[{"label":"A","text":"in those where the work is dangerous"},{"label":"B","text":"in those where there is an excess supply of labour"},{"label":"C","text":"in those where workers belong to trade unions"},{"label":"D","text":"in those where workers need long training"}],"correct":""},{"id":11,"text":"How might a trade union increase its bargaining power?","options":[{"label":"A","text":"by expanding the market for the product"},{"label":"B","text":"by increasing the cost of union membership for workers"},{"label":"C","text":"by restricting the entry of workers to the industry"},{"label":"D","text":"by supporting wage claims in other industries"}],"correct":""},{"id":12,"text":"To be able to produce a car tyre, rubber is required. If a car tyre manufacturer merges with a supplier of rubber, which type of merger is this?","options":[{"label":"A","text":"conglomerate"},{"label":"B","text":"horizontal"},{"label":"C","text":"internal"},{"label":"D","text":"vertical"}],"correct":""},{"id":13,"text":"What is likely to be found when there are many small firms in an industry?","options":[{"label":"A","text":"There are few barriers to entry."},{"label":"B","text":"There is high expenditure on research and development."},{"label":"C","text":"There is little competition."},{"label":"D","text":"Very large capital costs are needed to establish a firm."}],"correct":""},{"id":14,"text":"A government imposes tariffs on imported goods. What is not a likely reason for this?","options":[{"label":"A","text":"to boost domestic output"},{"label":"B","text":"to influence the country's balance of payments"},{"label":"C","text":"to protect domestic employment"},{"label":"D","text":"to reduce the exports from the country"}],"correct":""},{"id":15,"text":"Which policy measures would be classified as fiscal policy?","options":[{"label":"A","text":"changes in interest rates and money supply"},{"label":"B","text":"changes in labour market policies to encourage more training"},{"label":"C","text":"changes in tax rates and government spending"},{"label":"D","text":"changes in the exchange rate"}],"correct":""},{"id":16,"text":"What is the most likely result of a fall in interest rates?","options":[{"label":"A","text":"a fall in inflation"},{"label":"B","text":"a fall in investment"},{"label":"C","text":"a rise in consumer spending"},{"label":"D","text":"a rise in saving"}],"correct":""},{"id":17,"text":"What does a successful supply-side policy increase in an economy?","options":[{"label":"A","text":"the level of unemployment"},{"label":"B","text":"the production possibilities"},{"label":"C","text":"the rate of inflation"},{"label":"D","text":"the rate of interest"}],"correct":""},{"id":18,"text":"In one particular year, South Sudan's population growth was 1.3% while its GDP growth was 2%. What is the most likely consequence of this?","options":[{"label":"A","text":"GDP per capita will decrease"},{"label":"B","text":"the rate of inflation will decrease"},{"label":"C","text":"the standard of living will increase"},{"label":"D","text":"unemployment will increase"}],"correct":""},{"id":19,"text":"What are the correct definitions of unemployment and employment relative to the number of people of working age?","options":[{"label":"A","text":"those who want a job but cannot get one at the current wage rate | those who are not in full-time education"},{"label":"B","text":"those who want a job but cannot get one at the current wage rate | those who have a job at the current wage rate"},{"label":"C","text":"those without a job | those who are not in full-time education"},{"label":"D","text":"those without a job | those who have a job at the current wage rate"}],"correct":""},{"id":20,"text":"The graph shows changes in the average price level. When did the country experience deflation?","options":[{"label":"A","text":"year 2 to year 5"},{"label":"B","text":"year 2 to year 3"},{"label":"C","text":"year 2 to year 4"},{"label":"D","text":"year 4 to year 5"}],"correct":"","image":"/images/econ-mcq/276_428_252_943_670_0.jpg"},{"id":21,"text":"In many high-income economies, increasing income inequality has led to greater levels of poverty. Which combination of policies would aim to reduce income inequality?","options":[{"label":"A","text":"decrease corporation tax | create more competition"},{"label":"B","text":"increase income tax | reduce the power of trade unions"},{"label":"C","text":"increase inheritance tax | increase the national minimum wage"},{"label":"D","text":"increase sales tax | privatise more public sector firms"}],"correct":""},{"id":22,"text":"A country has a falling birth rate and a rising death rate, while an increasing number of its working age adults (16-60 years) are seeking employment abroad. How is this likely to affect the numbers in the different age groups in the country?","options":[{"label":"A","text":"fall | fall | fall"},{"label":"B","text":"fall | rise | rise"},{"label":"C","text":"rise | fall | rise"},{"label":"D","text":"rise | rise | fall"}],"correct":""},{"id":23,"text":"What is an advantage of international specialisation?","options":[{"label":"A","text":"Choice is limited."},{"label":"B","text":"Countries become over-dependent on each other."},{"label":"C","text":"Resources are used more efficiently."},{"label":"D","text":"Transport costs are decreased."}],"correct":""},{"id":24,"text":"An economy raises its tariffs on imported goods. What is the most likely result?","options":[{"label":"A","text":"a fall in the rate of inflation"},{"label":"B","text":"an increase in consumer choice"},{"label":"C","text":"an increase in domestic production"},{"label":"D","text":"the current account of the balance of payments moves into a deficit"}],"correct":""},{"id":25,"text":"Which combination of changes in export revenue and import expenditure is most likely to cause a country's exchange rate to depreciate?","options":[{"label":"A","text":"decreases | decreases"},{"label":"B","text":"decreases | increases"},{"label":"C","text":"increases | decreases"},{"label":"D","text":"increases | increases"}],"correct":""},{"id":26,"text":"A government wishes to reduce the deficit on the current account of its balance of payments. Which policy should it adopt?","options":[{"label":"A","text":"increase subsidies on exports"},{"label":"B","text":"increase taxes on its exports"},{"label":"C","text":"remove an embargo on imports"},{"label":"D","text":"remove tariffs on its imports"}],"correct":""}];

const paper_30: MCQQuestion[] = [{"id":1,"text":"What is least likely to increase the geographical mobility of labour?","options":[{"label":"A","text":"greater provision of information about available jobs"},{"label":"B","text":"improved roads and communication network"},{"label":"C","text":"increased opportunities for education and training"},{"label":"D","text":"strengthened family ties and relationships"}],"correct":""},{"id":2,"text":"Which value does opportunity cost measure?","options":[{"label":"A","text":"environmental damage"},{"label":"B","text":"next best alternative forgone"},{"label":"C","text":"output of labour"},{"label":"D","text":"price paid"}],"correct":""},{"id":3,"text":"What is not a function of prices in a market economy?","options":[{"label":"A","text":"prices allow income to be distributed equally"},{"label":"B","text":"prices ration scarce resources among economic agents"},{"label":"C","text":"prices rise and fall to reflect shortages and surpluses"},{"label":"D","text":"prices send information to consumers and producers"}],"correct":""},{"id":4,"text":"The table shows the market schedule for good X. If the quantity supplied increases by 50% at each price, what will the equilibrium price and quantity be?","options":[{"label":"A","text":"10 | 100"},{"label":"B","text":"9 | 200"},{"label":"C","text":"8 | 300"},{"label":"D","text":"7 | 400"}],"correct":"","table":"<table><tr><td>price</td><td>quantity supplied</td><td>quantity demanded</td></tr><tr><td>10</td><td>400</td><td>100</td></tr><tr><td>9</td><td>300</td><td>200</td></tr><tr><td>8</td><td>200</td><td>300</td></tr><tr><td>7</td><td>100</td><td>400</td></tr></table>"},{"id":5,"text":"Which combination shows features of the mixed economic system?","options":[{"label":"A","text":"no | no | yes"},{"label":"B","text":"no | yes | no"},{"label":"C","text":"yes | yes | no"},{"label":"D","text":"yes | yes | yes"}],"correct":""},{"id":6,"text":"The diagram shows the equilibrium price for bread. What will be the short-term effect if the government sets a maximum price below \\$5?","options":[{"label":"A","text":"a shift in the demand curve"},{"label":"B","text":"a shift in the supply curve"},{"label":"C","text":"an excess of demand over supply"},{"label":"D","text":"an excess of supply over demand"}],"correct":"","image":"/images/econ-mcq/281_686_1024_437_370_0.jpg"},{"id":7,"text":"Why do banknotes function as money?","options":[{"label":"A","text":"They are backed by gold."},{"label":"B","text":"They are durable."},{"label":"C","text":"They are generally acceptable."},{"label":"D","text":"They have intrinsic value."}],"correct":""},{"id":8,"text":"Worker X earns less than worker Y. What is most likely to be true of worker X?","options":[{"label":"A","text":"They have a longer period of training than worker Y."},{"label":"B","text":"They have a longer working day than worker Y."},{"label":"C","text":"They have skills that are more in demand than worker Y."},{"label":"D","text":"They have weaker bargaining power than worker Y."}],"correct":""},{"id":9,"text":"What would increase the strength of a trade union?","options":[{"label":"A","text":"a growth in part-time employment"},{"label":"B","text":"a growth in the membership"},{"label":"C","text":"a rise in the national minimum wage"},{"label":"D","text":"a rise in the standard of living"}],"correct":""},{"id":10,"text":"The size of the domestic car industry in Japan has enabled Japanese car producers to be more price competitive than rival car producers. What is an explanation for this?","options":[{"label":"A","text":"Economies of scale are present in the Japanese car industry."},{"label":"B","text":"Managerial problems exist in the Japanese car industry."},{"label":"C","text":"Productivity is low in Japan."},{"label":"D","text":"The Japanese car industry is very labour-intensive."}],"correct":""},{"id":11,"text":"The table shows the output of cakes from four bakeries, A, B, C and D. Which bakery has the highest labour productivity?","options":[{"label":"A","text":"10 | 40"},{"label":"B","text":"40 | 640"},{"label":"C","text":"50 | 750"},{"label":"D","text":"100 | 500"}],"correct":""},{"id":12,"text":"The table shows a firm's average revenue and average cost at different levels of output. When all output is sold, which level of output generates the most profit?","options":[{"label":"A","text":"5 | 10 | 30"},{"label":"B","text":"10 | 20 | 20"},{"label":"C","text":"15 | 25 | 15"},{"label":"D","text":"20 | 30 | 18"}],"correct":""},{"id":13,"text":"What would make the existence of a monopoly market more likely?","options":[{"label":"A","text":"consumers prefer a variety of choice in products"},{"label":"B","text":"significant economies of scale can be achieved"},{"label":"C","text":"there are low barriers to entry and exit for firms"},{"label":"D","text":"there are no restrictions on international trade"}],"correct":""},{"id":14,"text":"Which role is not performed by a government?","options":[{"label":"A","text":"paying dividends to shareholders"},{"label":"B","text":"promoting international trade agreements"},{"label":"C","text":"providing state benefits"},{"label":"D","text":"subsidising merit goods"}],"correct":""},{"id":15,"text":"What is not likely to be included in a government budget?","options":[{"label":"A","text":"anticipated tax revenue"},{"label":"B","text":"changes in exchange rates"},{"label":"C","text":"forecast government borrowing"},{"label":"D","text":"proposed government spending"}],"correct":""},{"id":16,"text":"Which combination of policy measures is most likely to increase total demand in an economy?","options":[{"label":"A","text":"decrease | decrease | revaluation"},{"label":"B","text":"decrease | increase | devaluation"},{"label":"C","text":"increase | decrease | devaluation"},{"label":"D","text":"increase | increase | revaluation"}],"correct":""},{"id":17,"text":"Which supply-side policy measure would most likely cause the greatest increase in labour productivity in a country?","options":[{"label":"A","text":"a decrease in the rate of corporation tax"},{"label":"B","text":"a reduced top rate of income tax"},{"label":"C","text":"improved education and training provision"},{"label":"D","text":"privatisation of a state-owned industry"}],"correct":""},{"id":18,"text":"How is economic growth of a country measured?","options":[{"label":"A","text":"by an increase in the monetary value of goods produced"},{"label":"B","text":"by an increase in the number of people in employment"},{"label":"C","text":"by an increase in the real Gross Domestic Product (GDP)"},{"label":"D","text":"by an increase in the value of the Human Development Index (HDI)"}],"correct":""},{"id":19,"text":"A country experiences a significant fall in unemployment. What is a possible advantage and a possible disadvantage of such a fall?","options":[{"label":"A","text":"fall in government spending on unemployment benefits | fall in labour disputes"},{"label":"B","text":"fall in tax revenue | fall in poverty"},{"label":"C","text":"rise in living standards | rise in inflation rate"},{"label":"D","text":"rise in output | rise in labour mobility"}],"correct":""},{"id":20,"text":"A country's Consumer Prices Index (CPI) falls from 120 to 110 in a year. What will be a likely effect of this fall?","options":[{"label":"A","text":"incomes will fall in real terms"},{"label":"B","text":"savings will fall in real terms"},{"label":"C","text":"the rate of interest will rise"},{"label":"D","text":"the real value of debt will rise"}],"correct":""},{"id":21,"text":"The population sizes of four countries, A, B, C and D, are all equal. Which country is most likely to have the highest population growth, given the changes in the table?","options":[{"label":"A","text":"decreasing | increasing | unchanged"},{"label":"B","text":"increasing | decreasing | increasing"},{"label":"C","text":"increasing | increasing | decreasing"},{"label":"D","text":"unchanged | increasing | decreasing"}],"correct":""},{"id":22,"text":"Which combination of characteristics would be found in a less developed economy?","options":[{"label":"A","text":"high | high | small"},{"label":"B","text":"low | high | small"},{"label":"C","text":"high | low | large"},{"label":"D","text":"low | low | large"}],"correct":""},{"id":23,"text":"What is a likely benefit of increased national specialisation?","options":[{"label":"A","text":"It guarantees a balance of trade in goods and services surplus."},{"label":"B","text":"It increases dependency on other economies."},{"label":"C","text":"It lengthens international supply chains."},{"label":"D","text":"It reduces the cost of living."}],"correct":""},{"id":24,"text":"What is not a likely benefit of free trade?","options":[{"label":"A","text":"consumers should experience lower prices"},{"label":"B","text":"consumers should have a greater choice of goods"},{"label":"C","text":"firms could be protected from foreign competition"},{"label":"D","text":"firms could take advantage of economies of scale"}],"correct":""},{"id":25,"text":"Which combination of changes would definitely raise the price of the Pakistani rupee on the foreign exchange market?","options":[{"label":"A","text":"decrease | decrease"},{"label":"B","text":"decrease | increase"},{"label":"C","text":"increase | decrease"},{"label":"D","text":"increase | increase"}],"correct":""},{"id":26,"text":"What is a likely government policy to reduce a deficit on the current account of the balance of payments?","options":[{"label":"A","text":"increasing the value of the foreign exchange rate"},{"label":"B","text":"increasing training for workers in export industries"},{"label":"C","text":"reducing subsidies to domestic export industries"},{"label":"D","text":"reducing tariffs on imported goods and services"}],"correct":""}];

